{
  "name": "KindredParent - Social-Emotional Support",
  "description": "A personalized parenting platform helping parents navigate social-emotional challenges with scripts, activities, and AI-driven expert advice.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Child {
  id: string;
  name: string;
  age: number;
  challenges: string[];
  interests: string[];
}

export interface UserProfile {
  name: string;
  children: Child[];
  onboarded: boolean;
}

export interface ChatMessage {
  role: 'user' | 'assistant';
  content: string;
}

export enum View {
  DASHBOARD = 'DASHBOARD',
  AI_CHAT = 'AI_CHAT',
  EXPERT = 'EXPERT',
  WELLNESS = 'WELLNESS',
  SETTINGS = 'SETTINGS'
}

export interface DailyTip {
  title: string;
  content: string;
  activity: string;
  script?: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Child, DailyTip } from "../types";

const apiKey = process.env.API_KEY || "";
const ai = new GoogleGenAI({ apiKey });

export const getDailyTip = async (children: Child[]): Promise<DailyTip> => {
  const childContext = children.map(c => 
    `${c.name} (age ${c.age}), challenges: ${c.challenges.join(", ")}, interests: ${c.interests.join(", ")}`
  ).join("; ");

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Generate a personalized daily parenting tip, a fun activity, and a helpful script for a parent with these children: ${childContext}. Focus on social-emotional growth.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          content: { type: Type.STRING },
          activity: { type: Type.STRING },
          script: { type: Type.STRING },
        },
        required: ["title", "content", "activity"],
      },
    },
  });

  return JSON.parse(response.text) as DailyTip;
};

export const getAiChatResponse = async (history: {role: string, content: string}[], message: string, children: Child[]) => {
  const childContext = children.map(c => `${c.name} (${c.age})`).join(", ");
  const chat = ai.chats.create({
    model: "gemini-3-flash-preview",
    config: {
      systemInstruction: `You are an expert parenting coach specializing in social-emotional development for kids aged 0-18. You are empathetic, practical, and science-based. The parent has these children: ${childContext}. Keep responses concise and actionable.`,
    }
  });

  const result = await chat.sendMessage({ message });
  return result.text;
};

export const getExpertResponse = async (question: string, child: Child) => {
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `As a child psychologist specializing in ${child.challenges.join(", ")}, please provide an in-depth, expert response to this parent's question regarding their ${child.age} year old child: "${question}". Include developmental context and specific therapeutic techniques.`,
    config: {
      thinkingConfig: { thinkingBudget: 4000 }
    }
  });
  return response.text;
};

export const getParentWellnessAdvice = async () => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: "Provide 3 quick mental health micro-habits for busy parents. Format as a bulleted list.",
  });
  return response.text;
};

import React, { useState, useEffect } from 'react';
import { UserProfile, View, Child } from './types';
import Onboarding from './components/Onboarding';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AiChat from './components/AiChat';
import ExpertSection from './components/ExpertSection';
import ParentWellness from './components/ParentWellness';

const STORAGE_KEY = 'kindred_parent_profile';

const App: React.FC = () => {
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [currentView, setCurrentView] = useState<View>(View.DASHBOARD);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      setProfile(JSON.parse(saved));
    }
    setIsLoading(false);
  }, []);

  const handleOnboardingComplete = (newProfile: UserProfile) => {
    setProfile(newProfile);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(newProfile));
  };

  const handleUpdateChildren = (children: Child[]) => {
    if (!profile) return;
    const newProfile = { ...profile, children };
    setProfile(newProfile);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(newProfile));
  };

  if (isLoading) return <div className="h-screen flex items-center justify-center">Loading...</div>;

  if (!profile || !profile.onboarded) {
    return <Onboarding onComplete={handleOnboardingComplete} />;
  }

  const renderView = () => {
    switch (currentView) {
      case View.DASHBOARD:
        return <Dashboard profile={profile} />;
      case View.AI_CHAT:
        return <AiChat profile={profile} />;
      case View.EXPERT:
        return <ExpertSection profile={profile} />;
      case View.WELLNESS:
        return <ParentWellness />;
      default:
        return <Dashboard profile={profile} />;
    }
  };

  return (
    <Layout currentView={currentView} setView={setCurrentView}>
      {renderView()}
    </Layout>
  );
};

export default App;

import React from 'react';
import { View } from '../types';

