export default Layout;

import React, { useState } from 'react';
import { UserProfile, Child } from '../types';

interface OnboardingProps {
  onComplete: (profile: UserProfile) => void;
}

const Onboarding: React.FC<OnboardingProps> = ({ onComplete }) => {
  const [step, setStep] = useState(1);
  const [parentName, setParentName] = useState('');
  const [children, setChildren] = useState<Child[]>([]);

  const [tempChild, setTempChild] = useState<Partial<Child>>({
    name: '',
    age: 5,
    challenges: [],
    interests: []
  });

  const [challengeInput, setChallengeInput] = useState('');
  const [interestInput, setInterestInput] = useState('');

  const addChild = () => {
    if (tempChild.name) {
      const newChild: Child = {
        id: Math.random().toString(36).substr(2, 9),
        name: tempChild.name || 'Child',
        age: tempChild.age || 5,
        challenges: tempChild.challenges || [],
        interests: tempChild.interests || []
      };
      setChildren([...children, newChild]);
      setTempChild({ name: '', age: 5, challenges: [], interests: [] });
    }
  };

  const handleFinish = () => {
    if (parentName && children.length > 0) {
      onComplete({
        name: parentName,
        children,
        onboarded: true
      });
    }
  };

  return (
    <div className="min-h-screen bg-rose-50 flex items-center justify-center p-4">
      <div className="max-w-md w-full bg-white rounded-3xl shadow-xl p-8 space-y-8">
        <div className="text-center">
          <h2 className="text-3xl font-bold text-stone-800 font-display">Welcome to KindredParent</h2>
          <p className="text-stone-500 mt-2">Let's personalize your experience.</p>
        </div>

        {step === 1 && (
          <div className="space-y-4">
            <label className="block text-sm font-medium text-stone-700">What's your name?</label>
            <input
              type="text"
              value={parentName}
              onChange={(e) => setParentName(e.target.value)}
              className="w-full p-4 bg-stone-50 border border-stone-200 rounded-xl focus:ring-2 focus:ring-rose-500 outline-none"
              placeholder="e.g. Sarah"
            />
            <button
              onClick={() => setStep(2)}
              disabled={!parentName}
              className="w-full bg-rose-500 text-white p-4 rounded-xl font-bold hover:bg-rose-600 transition-colors disabled:opacity-50"
            >
              Continue
            </button>
          </div>
        )}

        {step === 2 && (
          <div className="space-y-6">
            <div className="space-y-4">
              <h3 className="font-semibold text-stone-700">Add your child</h3>
              <input
                type="text"
                placeholder="Child's Name"
                className="w-full p-3 border border-stone-200 rounded-lg outline-none"
                value={tempChild.name}
                onChange={(e) => setTempChild({...tempChild, name: e.target.value})}
              />
              <div className="flex items-center space-x-4">
                <span className="text-sm text-stone-500">Age:</span>
                <input
                  type="number"
                  min="0"
                  max="18"
                  className="w-20 p-2 border border-stone-200 rounded-lg outline-none"
                  value={tempChild.age}
                  onChange={(e) => setTempChild({...tempChild, age: parseInt(e.target.value)})}
                />
              </div>

              <div className="space-y-2">
                <div className="flex space-x-2">
                  <input
                    type="text"
                    placeholder="Add a challenge (e.g. Tantrums)"
                    className="flex-1 p-3 border border-stone-200 rounded-lg outline-none"
                    value={challengeInput}
                    onChange={(e) => setChallengeInput(e.target.value)}
                  />
                  <button 
                    onClick={() => {
                      if (challengeInput) {
                        setTempChild({...tempChild, challenges: [...(tempChild.challenges || []), challengeInput]});
                        setChallengeInput('');
                      }
                    }}
                    className="bg-stone-200 p-3 rounded-lg px-4"
                  >+</button>
                </div>
                <div className="flex flex-wrap gap-2">
                  {tempChild.challenges?.map((c, i) => (
                    <span key={i} className="bg-rose-100 text-rose-700 text-xs px-2 py-1 rounded-full">{c}</span>
                  ))}
                </div>
              </div>

              <div className="space-y-2">
                <div className="flex space-x-2">
                  <input
                    type="text"
                    placeholder="Add an interest (e.g. Dinosaurs)"
                    className="flex-1 p-3 border border-stone-200 rounded-lg outline-none"
                    value={interestInput}
                    onChange={(e) => setInterestInput(e.target.value)}
                  />
                  <button 
                    onClick={() => {
                      if (interestInput) {
                        setTempChild({...tempChild, interests: [...(tempChild.interests || []), interestInput]});
                        setInterestInput('');
                      }
                    }}
                    className="bg-stone-200 p-3 rounded-lg px-4"
                  >+</button>
                </div>
                <div className="flex flex-wrap gap-2">
                  {tempChild.interests?.map((c, i) => (
                    <span key={i} className="bg-emerald-100 text-emerald-700 text-xs px-2 py-1 rounded-full">{c}</span>
                  ))}
                </div>
              </div>

              <button
                onClick={addChild}
                className="w-full border-2 border-dashed border-rose-300 text-rose-500 p-3 rounded-xl font-medium hover:bg-rose-50 transition-colors"
              >
                + Save Child
              </button>
            </div>

            <div className="space-y-2">
              <h4 className="text-sm font-semibold text-stone-500 uppercase tracking-wider">Added Children</h4>
              {children.length === 0 && <p className="text-stone-400 text-sm italic">No children added yet.</p>}
              {children.map((c) => (
                <div key={c.id} className="bg-stone-50 p-3 rounded-lg flex justify-between items-center border border-stone-100">
                  <div>
                    <span className="font-medium text-stone-700">{c.name}</span>
                    <span className="text-stone-400 ml-2">({c.age} yrs)</span>
                  </div>
                </div>
              ))}
            </div>

            <button
              onClick={handleFinish}
              disabled={children.length === 0}
              className="w-full bg-stone-800 text-white p-4 rounded-xl font-bold hover:bg-stone-900 transition-all disabled:opacity-50"
            >
              Get Started
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default Onboarding;

import React, { useState, useEffect } from 'react';
import { UserProfile, DailyTip } from '../types';
import { getDailyTip } from '../services/gemini';

interface DashboardProps {
  profile: UserProfile;
}

const Dashboard: React.FC<DashboardProps> = ({ profile }) => {
  const [tip, setTip] = useState<DailyTip | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchTip = async () => {
      try {
        const data = await getDailyTip(profile.children);
        setTip(data);
      } catch (e) {
        console.error("Failed to fetch daily tip", e);
      } finally {
        setLoading(false);
      }
    };
    fetchTip();
  }, [profile.children]);

  return (
    <div className="space-y-8 animate-in fade-in duration-700">
      <header>
        <h2 className="text-3xl font-bold text-stone-800 font-display">Hello, {profile.name}! 👋</h2>
        <p className="text-stone-500 mt-1">Here's your personalized support for today.</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Main Daily Tip */}
        <div className="lg:col-span-2 bg-white rounded-3xl shadow-sm border border-stone-100 p-8 space-y-6">
          {loading ? (
            <div className="animate-pulse space-y-4">
              <div className="h-8 bg-stone-100 rounded w-3/4"></div>
              <div className="h-32 bg-stone-50 rounded w-full"></div>
            </div>
          ) : (
            <>
              <div className="flex items-center space-x-3 text-rose-600 font-semibold tracking-wide uppercase text-sm">
                <span>✨ Daily Focus</span>
              </div>
              <h3 className="text-2xl font-bold text-stone-800 font-display leading-tight">
                {tip?.title}
              </h3>
              <p className="text-stone-600 leading-relaxed text-lg">
                {tip?.content}
              </p>

              {tip?.script && (
                <div className="bg-stone-50 border-l-4 border-rose-300 p-6 rounded-r-2xl">
                  <h4 className="text-rose-700 font-bold mb-2 flex items-center space-x-2">
                    <span>💬 Helpful Script</span>
                  </h4>
                  <p className="italic text-stone-700">"{tip.script}"</p>
                </div>
              )}
            </>
          )}
        </div>

        {/* Action Sidebar */}
        <div className="space-y-6">
          <div className="bg-emerald-50 rounded-3xl p-6 border border-emerald-100">
            <h4 className="text-emerald-800 font-bold mb-3 flex items-center space-x-2">
              <span>🎨 Fun Activity</span>
            </h4>
            {loading ? (
              <div className="animate-pulse h-20 bg-emerald-100 rounded"></div>
            ) : (
              <p className="text-emerald-700 text-sm leading-relaxed">
                {tip?.activity}
              </p>
            )}
          </div>

          <div className="bg-stone-800 rounded-3xl p-8 text-white">
            <h4 className="font-display text-xl mb-4 font-bold">Your Family</h4>
            <div className="space-y-4">
              {profile.children.map((child) => (
                <div key={child.id} className="flex items-center justify-between border-b border-stone-700 pb-3 last:border-0">
                  <div>
                    <p className="font-bold text-lg">{child.name}</p>
                    <p className="text-xs text-stone-400 uppercase tracking-widest">{child.age} Years Old</p>
                  </div>
                  <div className="flex -space-x-1">
                    {child.challenges.slice(0, 2).map((c, i) => (
                      <span key={i} className="bg-rose-500/20 text-rose-300 text-[10px] px-2 py-1 rounded-full border border-rose-500/30">
                        {c}
                      </span>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      <section className="bg-rose-50 rounded-3xl p-8 border border-rose-100">
        <div className="max-w-2xl">
          <h3 className="text-xl font-bold text-stone-800 font-display mb-3">Quick Check-in</h3>
          <p className="text-stone-600 mb-6 italic">"You cannot pour from an empty cup. Remember to take five minutes today for just you."</p>
          <div className="flex flex-wrap gap-4">
            <button className="bg-white px-6 py-2 rounded-full text-stone-700 font-medium shadow-sm hover:shadow-md transition-shadow">I did 5 mins yoga</button>
            <button className="bg-white px-6 py-2 rounded-full text-stone-700 font-medium shadow-sm hover:shadow-md transition-shadow">Drank my coffee hot</button>
            <button className="bg-white px-6 py-2 rounded-full text-stone-700 font-medium shadow-sm hover:shadow-md transition-shadow">Read a page</button>
          </div>
        </div>
      </section>
    </div>
  );
};

export default Dashboard;

import React, { useState, useRef, useEffect } from 'react';
import { UserProfile, ChatMessage } from '../types';
import { getAiChatResponse } from '../services/gemini';

interface AiChatProps {
  profile: UserProfile;
}

const AiChat: React.FC<AiChatProps> = ({ profile }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { role: 'assistant', content: "Hi! I'm your Kindred coach. Ask me anything about your kids or parenting challenges today." }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userMsg }]);
    setIsTyping(true);

    try {
      const response = await getAiChatResponse(messages, userMsg, profile.children);
      setMessages(prev => [...prev, { role: 'assistant', content: response }]);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'assistant', content: "I'm having a little trouble connecting. Please try again in a moment." }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-140px)] md:h-[calc(100vh-100px)]">
      <header className="mb-4">
        <h2 className="text-2xl font-bold text-stone-800 font-display">Instant Advice</h2>
        <p className="text-stone-500">Get quick answers and coaching scripts.</p>
      </header>

      <div className="flex-1 bg-white rounded-3xl shadow-sm border border-stone-100 overflow-hidden flex flex-col">
        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          {messages.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] p-4 rounded-2xl ${
                msg.role === 'user' 
                  ? 'bg-rose-500 text-white rounded-tr-none' 
                  : 'bg-stone-100 text-stone-800 rounded-tl-none'
              }`}>
                {msg.content}
              </div>
            </div>
          ))}
          {isTyping && (
            <div className="flex justify-start">
              <div className="bg-stone-100 p-4 rounded-2xl rounded-tl-none flex space-x-1">
                <div className="w-2 h-2 bg-stone-400 rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-stone-400 rounded-full animate-bounce delay-75"></div>
                <div className="w-2 h-2 bg-stone-400 rounded-full animate-bounce delay-150"></div>
              </div>
            </div>
          )}
          <div ref={scrollRef} />
        </div>

        <div className="p-4 border-t border-stone-100 bg-stone-50/50">
          <div className="flex space-x-2">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              placeholder="How do I handle a transition with my toddler?"
              className="flex-1 p-4 bg-white border border-stone-200 rounded-2xl outline-none focus:ring-2 focus:ring-rose-400"
            />
            <button
              onClick={handleSend}
              disabled={!input.trim() || isTyping}
              className="bg-rose-500 text-white px-6 rounded-2xl font-bold hover:bg-rose-600 disabled:opacity-50 transition-colors"
            >
              Send
            </button>
          </div>
          <div className="mt-2 flex flex-wrap gap-2">
            {['Bedtime battle', 'Sibling rivalry', 'School anxiety'].map((tag) => (
              <button
                key={tag}
                onClick={() => setInput(tag)}
                className="text-[10px] uppercase font-bold tracking-widest text-stone-500 border border-stone-200 px-3 py-1 rounded-full hover:bg-white transition-colors"
              >
                {tag}
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default AiChat;

import React, { useState } from 'react';
import { UserProfile, Child } from '../types';
import { getExpertResponse } from '../services/gemini';

interface ExpertSectionProps {
  profile: UserProfile;
}

const ExpertSection: React.FC<ExpertSectionProps> = ({ profile }) => {
  const [selectedChildId, setSelectedChildId] = useState(profile.children[0]?.id || '');
  const [question, setQuestion] = useState('');
  const [response, setResponse] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  const handleSubmit = async () => {
    if (!question || !selectedChildId) return;
    setLoading(true);
    setResponse(null);
    setSubmitted(false);

    const child = profile.children.find(c => c.id === selectedChildId);
    if (!child) return;

    try {
      // We simulate a "waiting for expert" experience, though Gemini Pro returns quickly
      const result = await getExpertResponse(question, child);
      setResponse(result);
      setSubmitted(true);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  return (
