import { GoogleGenAI, Type } from "@google/genai";
import { Child, DailyTip } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

export const getChallengeAdvice = async (child: Child, challenge: string): Promise<DailyTip> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `As an expert child developmental specialist at MindBloom, provide advice for a parent facing this challenge: "${challenge}" with their ${child.age}-year-old child named ${child.name}. 
    Provide a short snippet, a fun activity related to it, a script to say, and a 'details' section for more in-depth clinical context.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          content: { type: Type.STRING },
          activity: { type: Type.STRING },
          script: { type: Type.STRING },
          details: { type: Type.STRING, description: "Detailed clinical/developmental context for the behavior." },
        },
        required: ["title", "content", "activity", "details"],
      },
    },
  });

  return JSON.parse(response.text) as DailyTip;
};

export const getAiChatResponse = async (history: {role: string, content: string}[], message: string, children: Child[]) => {
  const childContext = children.map(c => `${c.name} (${c.age})`).join(", ");
  const chat = ai.chats.create({
    model: "gemini-3-flash-preview",
    config: {
      systemInstruction: `You are MindBloom Coach AI, an expert empathetic parenting coach. The parent has these children: ${childContext}. Keep responses warm, encouraging, and under 150 words. Focus on social-emotional skills.`,
    }
  });

  const result = await chat.sendMessage({ message });
  return result.text;
};

export const getExpertResponse = async (question: string, child: Child) => {
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `MindBloom Expert Analysis: Deep dive into "${question}" for a ${child.age}-year-old. Include evidence-based strategies and potential developmental milestones.`,
    config: {
      thinkingConfig: { thinkingBudget: 4000 }
    }
  });
  return response.text;
};

export const getSelfCareLessons = async () => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: "Provide 3 parenting micro-lessons for emotional resilience. Short, bulleted points.",
  });
  return response.text;
};

