import React, { useState } from 'react';
import { UserProfile, Child } from '../types';

interface OnboardingProps {
  onComplete: (profile: UserProfile) => void;
}

const COMMON_CHALLENGES: Record<string, string[]> = {
  infant: ['Sleep Issues', 'Feeding Challenges', 'Separation Anxiety'],
  toddler: ['Tantrums', 'Potty Training', 'Biting/Hitting', 'Transitioning'],
  preschool: ['Sibling Rivalry', 'Making Friends', 'Listening', 'Bedtime Battles'],
  school_age: ['Homework Stress', 'Focus/Attention', 'Social Skills', 'Anxiety'],
  teen: ['Screen Time', 'Body Image', 'Independence', 'Mood Swings', 'Peer Pressure']
};

const getAgeKey = (age: number) => {
  if (age <= 1) return 'infant';
  if (age <= 3) return 'toddler';
  if (age <= 6) return 'preschool';
  if (age <= 12) return 'school_age';
  return 'teen';
};

const Onboarding: React.FC<OnboardingProps> = ({ onComplete }) => {
  const [step, setStep] = useState(1);
  const [parentName, setParentName] = useState('');
  const [children, setChildren] = useState<Child[]>([]);

  const [tempChild, setTempChild] = useState<Partial<Child>>({
    name: '',
    age: 5,
    challenges: [],
    interests: []
  });

  const toggleChallenge = (c: string) => {
    const current = tempChild.challenges || [];
    if (current.includes(c)) {
      setTempChild({...tempChild, challenges: current.filter(item => item !== c)});
    } else {
      setTempChild({...tempChild, challenges: [...current, c]});
    }
  };

  const addChild = () => {
    if (tempChild.name) {
      const newChild: Child = {
        id: Math.random().toString(36).substr(2, 9),
        name: tempChild.name || 'Child',
        age: tempChild.age || 5,
        challenges: tempChild.challenges || [],
        interests: tempChild.interests || []
      };
      setChildren([...children, newChild]);
      setTempChild({ name: '', age: 5, challenges: [], interests: [] });
    }
  };

  return (
    <div className="min-h-screen bg-emerald-50 flex items-center justify-center p-4">
      <div className="max-w-xl w-full bg-white rounded-[2.5rem] shadow-2xl p-10 space-y-8">
        <div className="text-center space-y-2">
          <h2 className="text-4xl font-bold text-emerald-900 font-display">MindBloom</h2>
          <p className="text-stone-500 text-lg">Your parenting growth partner.</p>
        </div>

        {step === 1 ? (
          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-sm font-bold uppercase tracking-wider text-stone-400">What's your name?</label>
              <input
                type="text"
                value={parentName}
                onChange={(e) => setParentName(e.target.value)}
                className="w-full p-5 bg-stone-50 border border-stone-100 rounded-3xl focus:ring-4 focus:ring-emerald-100 outline-none transition-all text-xl"
                placeholder="Sarah..."
              />
            </div>
            <button
              onClick={() => setStep(2)}
              disabled={!parentName}
              className="w-full bg-emerald-600 text-white p-5 rounded-3xl font-bold text-xl hover:bg-emerald-700 transition-all disabled:opacity-50 shadow-lg"
            >
              Continue
            </button>
          </div>
        ) : (
          <div className="space-y-8">
            <div className="space-y-6">
              <div className="grid grid-cols-2 gap-4">
                <input
                  type="text"
                  placeholder="Child's Name"
                  className="p-4 bg-stone-50 border border-stone-100 rounded-2xl outline-none"
                  value={tempChild.name}
                  onChange={(e) => setTempChild({...tempChild, name: e.target.value})}
                />
                <input
                  type="number"
                  placeholder="Age"
                  className="p-4 bg-stone-50 border border-stone-100 rounded-2xl outline-none"
                  value={tempChild.age}
                  onChange={(e) => setTempChild({...tempChild, age: parseInt(e.target.value) || 0})}
                />
              </div>

              {tempChild.name && (
                <div className="space-y-3 animate-in fade-in slide-in-from-top-4 duration-300">
                  <p className="text-sm font-bold text-stone-600 uppercase tracking-wide">Common challenges at {tempChild.age}:</p>
                  <div className="flex flex-wrap gap-2">
                    {COMMON_CHALLENGES[getAgeKey(tempChild.age || 0)].map(c => (
                      <button
                        key={c}
                        onClick={() => toggleChallenge(c)}
                        className={`px-4 py-2 rounded-full text-xs font-semibold transition-all border ${
                          tempChild.challenges?.includes(c) 
                            ? 'bg-emerald-100 border-emerald-300 text-emerald-700' 
                            : 'bg-white border-stone-200 text-stone-400'
                        }`}
                      >
                        {c}
                      </button>
                    ))}
                  </div>
                </div>
              )}

              <button
                onClick={addChild}
                className="w-full border-2 border-dashed border-emerald-200 text-emerald-600 p-4 rounded-3xl font-bold hover:bg-emerald-50 transition-all"
              >
                + Save Child
              </button>
            </div>

            {children.length > 0 && (
              <div className="space-y-4 pt-6 border-t border-stone-100">
                <p className="text-xs font-bold uppercase tracking-widest text-stone-400">Registered Little Ones</p>
                {children.map(c => (
                  <div key={c.id} className="flex items-center justify-between p-4 bg-stone-50 rounded-2xl border border-stone-100">
                    <span className="font-bold text-stone-800">{c.name} <span className="text-stone-400 font-medium">({c.age})</span></span>
                  </div>
                ))}
                <button
                  onClick={() => onComplete({ name: parentName, children, onboarded: true })}
                  className="w-full bg-stone-900 text-white p-5 rounded-3xl font-bold text-xl hover:bg-black transition-all shadow-xl"
                >
                  Enter MindBloom
                </button>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default Onboarding;

