import React, { useState } from 'react';
import { UserProfile, Child } from '../types';
import { getExpertResponse } from '../services/gemini';

interface ExpertSectionProps {
  profile: UserProfile;
}

const ExpertSection: React.FC<ExpertSectionProps> = ({ profile }) => {
  const [selectedChildId, setSelectedChildId] = useState(profile.children[0]?.id || '');
  const [question, setQuestion] = useState('');
  const [response, setResponse] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  const handleSubmit = async () => {
    if (!question || !selectedChildId) return;
    setLoading(true);
    setResponse(null);
    setSubmitted(false);

    const child = profile.children.find(c => c.id === selectedChildId);
    if (!child) return;

    try {
      const result = await getExpertResponse(question, child);
      setResponse(result);
      setSubmitted(true);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-8">
      <div className="bg-white rounded-[3rem] shadow-xl border border-stone-100 p-8 md:p-12">
        <header className="mb-10 space-y-4">
          <div className="inline-block bg-emerald-50 text-emerald-700 px-4 py-1 rounded-full text-xs font-bold uppercase tracking-widest">
            Clinical Insights
          </div>
          <h2 className="text-3xl md:text-4xl font-bold text-stone-800 font-display">Ask a MindBloom Specialist</h2>
          <p className="text-stone-500 max-w-xl">Deep clinical context for your child's specific developmental milestones.</p>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
          <div className="space-y-6">
            <div className="space-y-3">
              <label className="text-xs font-bold uppercase tracking-widest text-stone-400">Child context</label>
              <div className="flex flex-wrap gap-2">
                {profile.children.map(c => (
                  <button
                    key={c.id}
                    onClick={() => setSelectedChildId(c.id)}
                    className={`px-6 py-2 rounded-full text-sm font-bold transition-all border ${
                      selectedChildId === c.id ? 'bg-stone-800 text-white' : 'bg-white border-stone-200 text-stone-400'
                    }`}
                  >
                    {c.name}
                  </button>
                ))}
              </div>
            </div>

            <div className="space-y-3">
              <label className="text-xs font-bold uppercase tracking-widest text-stone-400">Your query</label>
              <textarea
                className="w-full h-48 p-6 bg-stone-50 border border-stone-100 rounded-[2rem] outline-none focus:ring-4 focus:ring-emerald-100 transition-all"
                placeholder="Describe your concern in detail..."
                value={question}
                onChange={(e) => setQuestion(e.target.value)}
              />
            </div>

            <button
              onClick={handleSubmit}
              disabled={loading || !question}
              className="w-full py-5 bg-emerald-600 text-white rounded-[2rem] font-bold text-lg hover:bg-emerald-700 transition-all disabled:opacity-50 shadow-lg"
            >
              {loading ? 'Reviewing Query...' : 'Submit to Specialist'}
            </button>
          </div>

          <div className="bg-stone-50 rounded-[2.5rem] p-10 flex flex-col items-center justify-center text-center space-y-6 min-h-[400px]">
            {!submitted && !loading ? (
              <>
                <div className="text-5xl">📄</div>
                <h4 className="text-xl font-bold text-stone-800">Your Report Awaits</h4>
                <p className="text-sm text-stone-500">The specialist will provide a research-backed breakdown of your situation.</p>
              </>
            ) : loading ? (
              <div className="animate-pulse space-y-6 w-full">
                <div className="h-4 bg-stone-200 rounded w-3/4 mx-auto"></div>
                <div className="h-4 bg-stone-200 rounded w-full"></div>
                <div className="h-4 bg-stone-200 rounded w-5/6 mx-auto"></div>
              </div>
            ) : (
              <div className="text-left w-full space-y-6 animate-in fade-in duration-500 overflow-y-auto max-h-[400px] pr-2">
                <h4 className="text-xl font-bold text-emerald-900 border-b border-emerald-100 pb-4">Specialist Analysis</h4>
                <div className="text-stone-700 leading-relaxed whitespace-pre-wrap text-sm">
                  {response}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

