import React, { useState, useEffect } from 'react';
import { UserProfile, View, Child } from './types';
import Onboarding from './components/Onboarding';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AiChat from './components/AiChat';
import ExpertSection from './components/ExpertSection';

const STORAGE_KEY = 'mindbloom_profile';

const App: React.FC = () => {
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [currentView, setCurrentView] = useState<View>(View.DASHBOARD);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      setProfile(JSON.parse(saved));
    }
    setIsLoading(false);
  }, []);

  const handleOnboardingComplete = (newProfile: UserProfile) => {
    setProfile(newProfile);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(newProfile));
  };

  if (isLoading) return <div className="h-screen flex items-center justify-center bg-emerald-50 font-display text-2xl font-bold text-emerald-800 animate-pulse">MindBloom...</div>;

  if (!profile || !profile.onboarded) {
    return <Onboarding onComplete={handleOnboardingComplete} />;
  }

  const renderView = () => {
    // The Dashboard now handles the requested 6-part order on the home page.
    // Other views allow quick access to those specific sections.
    switch (currentView) {
      case View.DASHBOARD:
        return <Dashboard profile={profile} />;
      case View.ACTIVITIES:
        return (
          <div className="space-y-8">
            <h2 className="text-3xl font-bold text-stone-800 font-display">Play-Based Learning</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="bg-emerald-50 p-8 rounded-[2rem] border border-emerald-100">
                <h3 className="font-bold text-emerald-800 mb-2">Social Skills Game</h3>
                <p className="text-emerald-600 text-sm">Select a challenge on the home page to unlock specific activity scripts.</p>
              </div>
            </div>
          </div>
        );
      case View.AI_CHAT:
        return <AiChat profile={profile} />;
      case View.EXPERT:
        return <ExpertSection profile={profile} />;
      case View.WELLNESS:
        return (
          <div className="space-y-12">
            <h2 className="text-3xl font-bold text-stone-800 font-display text-center">Your Sanctuary</h2>
            <div className="bg-white p-10 rounded-[3rem] shadow-sm border border-stone-100">
              <h3 className="text-2xl font-bold text-stone-800 mb-6 font-display">Mindfulness Library</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="p-6 bg-stone-50 rounded-2xl">Affirmations</div>
                <div className="p-6 bg-stone-50 rounded-2xl">Grounding Exercises</div>
                <div className="p-6 bg-stone-50 rounded-2xl">Micro-lessons</div>
                <div className="p-6 bg-stone-50 rounded-2xl">Breathwork</div>
              </div>
            </div>
          </div>
        );
      default:
        return <Dashboard profile={profile} />;
    }
  };

  return (
    <Layout currentView={currentView} setView={setCurrentView}>
      {renderView()}
    </Layout>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { Child, DailyTip } from "../types";

// Always use process.env.API_KEY directly as per guidelines.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getChallengeAdvice = async (child: Child, challenge: string): Promise<DailyTip> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `As an expert child developmental specialist at MindBloom, provide advice for a parent facing this challenge: "${challenge}" with their ${child.age}-year-old child named ${child.name}. 
    Provide a short snippet, a fun activity related to it, a script to say, and a 'details' section for more in-depth clinical context.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          content: { type: Type.STRING },
          activity: { type: Type.STRING },
          script: { type: Type.STRING },
          details: { type: Type.STRING, description: "Detailed clinical/developmental context for the behavior." },
        },
        required: ["title", "content", "activity", "details"],
      },
    },
  });

  // Accessing text property directly as per guidelines
  const text = response.text || "{}";
  return JSON.parse(text) as DailyTip;
};

export const getAiChatResponse = async (history: {role: string, content: string}[], message: string, children: Child[]) => {
  const childContext = children.map(c => `${c.name} (${c.age})`).join(", ");

  // Mapping history to the format expected by the chat session
  const formattedHistory = history.map(h => ({
    role: h.role === 'assistant' ? 'model' : 'user',
    parts: [{ text: h.content }]
  }));

  const chat = ai.chats.create({
    model: "gemini-3-flash-preview",
    history: formattedHistory,
    config: {
      systemInstruction: `You are MindBloom Coach AI, an expert empathetic parenting coach. The parent has these children: ${childContext}. Keep responses warm, encouraging, and under 150 words. Focus on social-emotional skills.`,
    }
  });

  const result = await chat.sendMessage({ message });
  return result.text || "";
};

export const getExpertResponse = async (question: string, child: Child) => {
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `MindBloom Expert Analysis: Deep dive into "${question}" for a ${child.age}-year-old. Include evidence-based strategies and potential developmental milestones.`,
    config: {
      // Max thinking budget for gemini-3-pro-preview is 32768
      thinkingConfig: { thinkingBudget: 32768 }
    }
  });
  return response.text || "";
};

