import { GoogleGenAI, Type } from "@google/genai";
import { Child, DailyTip, SelfCareCategory } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Get advice for specific parenting challenges using the latest flash model
export const getChallengeAdvice = async (child: Child, challenge: string): Promise<DailyTip> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `As an expert child developmental specialist at MindBloom, provide advice for a parent facing this challenge: "${challenge}" with their ${child.age}-year-old child named ${child.name}. 
    Provide a short snippet, a fun activity related to it, a script to say, and a 'details' section for more in-depth clinical context.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          content: { type: Type.STRING },
          activity: { type: Type.STRING },
          script: { type: Type.STRING },
          details: { type: Type.STRING, description: "Detailed clinical/developmental context for the behavior." },
        },
        required: ["title", "content", "activity", "details"],
      },
    },
  });

  const text = response.text || "{}";
  return JSON.parse(text) as DailyTip;
};

// Interactive AI coaching chat using gemini-3-flash
export const getAiChatResponse = async (history: {role: string, content: string}[], message: string, children: Child[]) => {
  const childContext = children.map(c => `${c.name} (${c.age})`).join(", ");
  const formattedHistory = history.map(h => ({
    role: h.role === 'assistant' ? 'model' : 'user',
    parts: [{ text: h.content }]
  }));

  const chat = ai.chats.create({
    model: "gemini-3-flash-preview",
    history: formattedHistory,
    config: {
      systemInstruction: `You are MindBloom Coach AI, an expert empathetic parenting coach. The parent has these children: ${childContext}. Keep responses warm, encouraging, and under 150 words. Focus on social-emotional skills. Respond in a friendly, conversational way.`,
    }
  });

  const result = await chat.sendMessage({ message });
  return result.text || "";
};

// Get self-care content for parents
export const getSelfCareContent = async (category: SelfCareCategory): Promise<{ title: string; content: string }> => {
  const prompts: Record<SelfCareCategory, string> = {
    'Grounding': "Provide a simple grounding exercise for a parent (e.g. 5-4-3-2-1 or breathwork).",
    'Affirmation': "Provide 3 powerful, empathetic affirmations for a parent having a hard day.",
    'Micro-Lesson': "Provide a 3-sentence micro-lesson on emotional intelligence in parenting.",
    'Calm Down Tool': "Provide a specific tool or mental technique for a parent to use when they feel their anger rising."
  };

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompts[category],
  });

  return { title: category, content: response.text || "" };
};

// Get general parent wellness advice
export const getParentWellnessAdvice = async (): Promise<string> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: "Provide a few short sentences of encouraging, empathetic advice for a parent who is feeling overwhelmed.",
  });
  return response.text || "";
};

// Fix: Implement getExpertResponse for Specialist analysis using the advanced gemini-3-pro-preview model
export const getExpertResponse = async (question: string, child: Child): Promise<string> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `As a clinical developmental specialist at MindBloom, provide a research-backed, detailed analysis for this parenting concern: "${question}" regarding a ${child.age}-year-old child named ${child.name}. 
    Focus on developmental milestones, psychological context, and evidence-based strategies. Keep the tone professional yet empathetic.`,
