import React, { useState, useEffect } from 'react';
import { UserProfile, View } from './types';
import Onboarding from './components/Onboarding';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import AdviceActivities from './components/AdviceActivities';
import CoachAIView from './components/CoachAIView';
import ExpertComingSoon from './components/ExpertComingSoon';
import SelfCareHub from './components/SelfCareHub';

const STORAGE_KEY = 'mindbloom_profile_v2';

const App: React.FC = () => {
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [currentView, setCurrentView] = useState<View>(View.DASHBOARD);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      setProfile(JSON.parse(saved));
    }
    setIsLoading(false);
  }, []);

  const handleOnboardingComplete = (newProfile: UserProfile) => {
    setProfile(newProfile);
    localStorage.setItem(STORAGE_KEY, JSON.stringify(newProfile));
  };

  if (isLoading) return <div className="h-screen flex items-center justify-center bg-emerald-50 font-display text-2xl font-bold text-emerald-800">MindBloom...</div>;

  if (!profile || !profile.onboarded) {
    return <Onboarding onComplete={handleOnboardingComplete} />;
  }

  const renderView = () => {
    switch (currentView) {
      case View.DASHBOARD:
        return <Dashboard profile={profile} setView={setCurrentView} />;
      case View.ADVICE_ACTIVITIES:
        return <AdviceActivities profile={profile} onBack={() => setCurrentView(View.DASHBOARD)} />;
      case View.COACH_AI:
        return <CoachAIView profile={profile} onBack={() => setCurrentView(View.DASHBOARD)} />;
      case View.EXPERT:
        return <ExpertComingSoon profile={profile} onBack={() => setCurrentView(View.DASHBOARD)} />;
      case View.SELF_CARE:
        return <SelfCareHub onBack={() => setCurrentView(View.DASHBOARD)} />;
      default:
        return <Dashboard profile={profile} setView={setCurrentView} />;
    }
  };

  return (
    <Layout currentView={currentView} setView={setCurrentView}>
      {renderView()}
    </Layout>
  );
};

export default App;

