import { GoogleGenAI, Type } from "@google/genai";
import { Child, DailyTip, SelfCareCategory } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Optimized for speed: uses more direct instructions.
 */
export const getChallengeAdvice = async (child: Child, challenge: string): Promise<DailyTip> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Specialist at MindBloom. Quick help for: "${challenge}" (${child.age}yo). 
    Provide:
    1. Short summary (content).
    2. One activity.
    3. One script.
    4. Details.
    Keep it snappy.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          content: { type: Type.STRING },
          activity: { type: Type.STRING },
          script: { type: Type.STRING },
          details: { type: Type.STRING },
        },
        required: ["title", "content", "activity", "details"],
      },
    },
  });

  const text = response.text || "{}";
  return JSON.parse(text) as DailyTip;
};

/**
 * Enhanced for readability: Bullet points and line breaks.
 */
export const getAiChatResponse = async (history: {role: string, content: string}[], message: string, children: Child[]) => {
  const childContext = children.map(c => `${c.name} (${c.age})`).join(", ");
  const chat = ai.chats.create({
    model: "gemini-3-flash-preview",
    config: {
      systemInstruction: `You are MindBloom Coach AI. 
      FORMATTING RULES: 
      - Use bullet points for steps or lists.
      - Use separate lines (paragraphs) for readability.
      - Keep it warm and concise (max 100 words).
      Context: children ${childContext}.`,
    }
  });

  const result = await chat.sendMessage({ message });
  return result.text || "";
};

export const getSelfCareContent = async (category: string): Promise<{ title: string; content: string }> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `MindBloom Sanctuary: Provide a NEW and unique high-impact, 2-sentence ${category} for a parent. Avoid common clichés; provide a specific technique or mantra. Be very concise for speed. Randomize output to ensure variety.`,
  });

  return { title: category, content: response.text || "" };
};

export const getExpertResponse = async (question: string, child: Child): Promise<string> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `Clinical specialist. Deep analysis for: "${question}" (${child.name}, ${child.age}yo). 
    Known challenges: ${child.challenges.join(', ')}.`,
  });
  return response.text || "I apologize, but I couldn't generate a specialist analysis at this moment.";
};

export const getParentWellnessAdvice = async (): Promise<string> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: "One short micro-moment of zen for a parent. Max 2 sentences.",
  });
  return response.text || "Breathe deeply. You are providing exactly what your child needs right now: love and presence.";
};

