const ALL_CHALLENGES = {
  early: ['Sleep Issues', 'Feeding Challenges', 'Tantrums', 'Potty Training', 'Transitions', 'Biting/Hitting', 'Separation Anxiety', 'Hygiene', 'Listening', 'Sensory Play'],
  preschool: ['Listening', 'Sibling Rivalry', 'Making Friends', 'Bedtime Battles', 'Focus/Attention', 'Social Skills', 'Anxiety', 'Tantrums', 'Screen Time', 'Night Fears'],
  schoolAge: ['Homework Stress', 'Screen Time', 'Independence', 'Bullying', 'Peer Pressure', 'Anxiety', 'Social Skills', 'Listening', 'Hygiene', 'Confidence'],
  teen: ['Mood Swings', 'Body Image', 'Peer Pressure', 'Independence', 'Screen Time', 'Anxiety', 'Homework', 'Social Media', 'Trust', 'Sleep Habits']
};

const COMMON_INTERESTS = [
  'Dinosaurs', 'Space', 'Sports', 'Drawing/Art', 'Coding', 'Music', 'Nature', 
  'Reading', 'Gaming', 'Animals', 'Cooking', 'Building/LEGO', 'Dancing'
];

const Onboarding: React.FC<OnboardingProps> = ({ onComplete }) => {
  const [parentName, setParentName] = useState('');
  const [children, setChildren] = useState<Child[]>([]);

  const [tempChild, setTempChild] = useState<Partial<Child>>({
    name: '',
    age: 5,
    challenges: [],
    interests: []
  });

  const [customChallenge, setCustomChallenge] = useState('');
  const [customInterest, setCustomInterest] = useState('');

  const filteredChallenges = useMemo(() => {
    const age = tempChild.age || 0;
    if (age <= 3) return ALL_CHALLENGES.early;
    if (age <= 6) return ALL_CHALLENGES.preschool;
    if (age <= 12) return ALL_CHALLENGES.schoolAge;
    return ALL_CHALLENGES.teen;
  }, [tempChild.age]);

  const toggleItem = (item: string, key: 'challenges' | 'interests') => {
    const current = (tempChild[key] as string[]) || [];
    if (current.includes(item)) {
      setTempChild({...tempChild, [key]: current.filter(i => i !== item)});
    } else {
      setTempChild({...tempChild, [key]: [...current, item]});
    }
  };

  const addChild = () => {
    if (tempChild.name && tempChild.age !== undefined) {
      const newChild: Child = {
        id: Math.random().toString(36).substr(2, 9),
        name: tempChild.name,
        age: tempChild.age,
        challenges: tempChild.challenges || [],
        interests: tempChild.interests || []
      };
      setChildren([...children, newChild]);
      setTempChild({ name: '', age: 5, challenges: [], interests: [] });
    }
  };

  const canFinish = parentName.trim().length > 0 && (children.length > 0 || (tempChild.name && tempChild.name.trim().length > 0));

  const handleFinish = () => {
    let finalChildren = [...children];
    if (tempChild.name) {
      const lastChild: Child = {
        id: Math.random().toString(36).substr(2, 9),
        name: tempChild.name,
        age: tempChild.age || 5,
        challenges: tempChild.challenges || [],
        interests: tempChild.interests || []
      };
      finalChildren.push(lastChild);
    }
    // Fixed: Added empty logs array to match UserProfile interface
    onComplete({ 
      name: parentName, 
      children: finalChildren, 
      onboarded: true,
      logs: [] 
    });
  };

  return (
    <div className="min-h-screen bg-[#f0f7ff] flex items-center justify-center p-4 py-12">
      <div className="max-w-3xl w-full bg-white rounded-[3rem] shadow-xl p-8 md:p-12 space-y-10 border border-emerald-100">
        <div className="text-center space-y-3">
          <h2 className="text-5xl font-bold text-emerald-900 font-display">Welcome to MindBloom</h2>
          <p className="text-stone-500 text-lg">Let's personalize your parenting journey.</p>
        </div>

        <div className="space-y-10">
          {/* Parent Info */}
          <section className="space-y-4">
            <h3 className="text-xl font-bold text-emerald-800 font-display border-b border-emerald-50 pb-2">About You</h3>
            <div className="space-y-2">
              <label className="text-xs font-bold uppercase tracking-widest text-stone-400 px-1">Your Name</label>
              <input
                type="text"
                value={parentName}
                onChange={(e) => setParentName(e.target.value)}
                className="w-full p-5 bg-stone-50 border border-stone-100 rounded-3xl focus:ring-4 focus:ring-emerald-100 outline-none transition-all text-xl"
                placeholder="e.g. Sarah"
              />
            </div>
          </section>

          {/* Child Entry */}
          <section className="space-y-6">
            <h3 className="text-xl font-bold text-emerald-800 font-display border-b border-emerald-50 pb-2">Your Child</h3>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-xs font-bold uppercase tracking-widest text-stone-400 px-1">Child's Name</label>
                <input
                  type="text"
                  placeholder="e.g. Leo"
                  className="w-full p-4 bg-stone-50 border border-stone-100 rounded-2xl outline-none focus:ring-2 focus:ring-emerald-100"
                  value={tempChild.name}
                  onChange={(e) => setTempChild({...tempChild, name: e.target.value})}
                />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-bold uppercase tracking-widest text-stone-400 px-1">Age</label>
                <input
                  type="number"
                  placeholder="Age"
                  className="w-full p-4 bg-stone-50 border border-stone-100 rounded-2xl outline-none focus:ring-2 focus:ring-emerald-100"
                  value={tempChild.age}
                  onChange={(e) => setTempChild({...tempChild, age: parseInt(e.target.value) || 0})}
                />
              </div>
            </div>

            {tempChild.name && (
              <div className="space-y-8 animate-in fade-in slide-in-from-top-2 duration-500">
                <div className="space-y-4">
                  <div className="flex justify-between items-end">
                    <p className="text-sm font-bold text-stone-600 uppercase tracking-wide">Top 10 Challenges for Age {tempChild.age}:</p>
                    <span className="text-[10px] text-stone-400 italic">Select all that apply</span>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {filteredChallenges.map(c => (
                      <button
                        key={c}
                        onClick={() => toggleItem(c, 'challenges')}
                        className={`px-4 py-2 rounded-full text-xs font-semibold border transition-all ${
                          tempChild.challenges?.includes(c) ? 'bg-emerald-600 border-emerald-700 text-white shadow-md' : 'bg-white border-stone-100 text-stone-400 hover:border-emerald-200'
                        }`}
                      >
                        {c}
                      </button>
                    ))}
                  </div>
                  <div className="flex gap-2">
                    <input
                      type="text"
                      placeholder="Add another challenge..."
                      className="flex-1 p-3 bg-stone-50 border border-stone-100 rounded-xl text-sm outline-none"
                      value={customChallenge}
                      onChange={(e) => setCustomChallenge(e.target.value)}
                    />
                    <button 
                      onClick={() => { if(customChallenge) { toggleItem(customChallenge, 'challenges'); setCustomChallenge(''); }}}
                      className="bg-emerald-100 text-emerald-700 px-5 rounded-xl font-bold hover:bg-emerald-200 transition-colors"
                    >+</button>
                  </div>
                </div>

                <div className="space-y-4">
                  <p className="text-sm font-bold text-stone-600 uppercase tracking-wide">Interests:</p>
                  <div className="flex flex-wrap gap-2">
                    {COMMON_INTERESTS.map(i => (
                      <button
                        key={i}
                        onClick={() => toggleItem(i, 'interests')}
                        className={`px-4 py-2 rounded-full text-xs font-semibold border transition-all ${
                          tempChild.interests?.includes(i) ? 'bg-sky-600 border-sky-700 text-white shadow-md' : 'bg-white border-stone-100 text-stone-400 hover:border-sky-200'
                        }`}
                      >
                        {i}
                      </button>
                    ))}
                  </div>
                  <div className="flex gap-2">
                    <input
                      type="text"
                      placeholder="Add another interest..."
                      className="flex-1 p-3 bg-stone-50 border border-stone-100 rounded-xl text-sm outline-none"
                      value={customInterest}
                      onChange={(e) => setCustomInterest(e.target.value)}
                    />
                    <button 
                      onClick={() => { if(customInterest) { toggleItem(customInterest, 'interests'); setCustomInterest(''); }}}
                      className="bg-sky-100 text-sky-700 px-5 rounded-xl font-bold hover:bg-sky-200 transition-colors"
                    >+</button>
                  </div>
                </div>

                <button
                  onClick={addChild}
                  className="w-full border-2 border-dashed border-emerald-200 text-emerald-600 p-4 rounded-3xl font-bold hover:bg-emerald-50 transition-all flex items-center justify-center gap-2"
                >
                  <span className="text-xl">+</span> Add Child to List
                </button>
              </div>
            )}
          </section>

          {/* Children List */}
          {children.length > 0 && (
            <section className="space-y-4">
              <h4 className="text-xs font-bold uppercase tracking-widest text-stone-400 px-1">Family Members Added:</h4>
              <div className="flex flex-wrap gap-3">
                {children.map(c => (
                  <div key={c.id} className="px-5 py-3 bg-emerald-50 rounded-2xl border border-emerald-100 flex items-center gap-3">
                    <span className="text-lg">🌱</span>
                    <div>
                      <p className="font-bold text-emerald-900 leading-none">{c.name}</p>
                      <p className="text-[10px] text-emerald-700 uppercase tracking-tighter">Age {c.age}</p>
                    </div>
                    <button 
                      onClick={() => setChildren(children.filter(child => child.id !== c.id))}
                      className="ml-2 text-stone-400 hover:text-red-500"
                    >✕</button>
                  </div>
                ))}
              </div>
            </section>
          )}

          {/* Action Footer */}
          <div className="pt-8 border-t border-stone-100">
            <button
              onClick={handleFinish}
              disabled={!canFinish}
              className="w-full bg-emerald-900 text-white p-6 rounded-[2rem] font-bold text-xl hover:bg-black transition-all shadow-xl disabled:opacity-50 disabled:cursor-not-allowed transform hover:scale-[1.01]"
            >
              Start Blooming Together
            </button>
            <p className="text-center text-stone-400 text-xs mt-4">
              Your data is stored locally on this device.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

