import React, { useState } from 'react';
import { getSelfCareContent } from '../services/gemini';
import Modal from './Modal';

interface Props {
  onBack: () => void;
}

const SelfCareHub: React.FC<Props> = ({ onBack }) => {
  const [loading, setLoading] = useState(false);
  const [content, setContent] = useState<{ title: string; content: string } | null>(null);

  const handleSelect = async (category: string) => {
    setLoading(true);
    try {
      // getSelfCareContent prompt ensures NEW and UNIQUE content on every request
      const res = await getSelfCareContent(category);
      setContent(res);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const categories = [
    { label: 'Calm Down Tools', icon: '❄️', color: 'bg-sky-50 text-sky-800' },
    { label: 'Grounding', icon: '🧘', color: 'bg-emerald-50 text-emerald-800' },
    { label: 'Affirmations', icon: '✨', color: 'bg-rose-50 text-rose-800' },
  ];

  return (
    <div className="max-w-2xl mx-auto py-10 space-y-8">
      <button onClick={onBack} className="text-emerald-700 font-bold flex items-center gap-2 mb-4 hover:translate-x-[-4px] transition-transform">← Back to Hub</button>

      <div className="text-center space-y-6">
        <h2 className="text-4xl font-bold text-emerald-900 font-display">Parent Self Care</h2>
        <p className="text-stone-500 leading-relaxed">
          You cannot pour from an empty cup.<br />
          Every click here provides a fresh micro-moment for your own regulation.
        </p>

        <div className="grid grid-cols-1 sm:grid-cols-3 gap-6 pt-6">
          {categories.map((cat) => (
            <button
              key={cat.label}
              onClick={() => handleSelect(cat.label)}
              disabled={loading}
              className={`${cat.color} p-8 rounded-[2.5rem] flex flex-col items-center justify-center space-y-4 shadow-sm hover:shadow-xl hover:scale-105 transition-all border border-transparent hover:border-current/10`}
            >
              <span className="text-4xl group-hover:scale-110 transition-transform">{cat.icon}</span>
              <span className="font-bold text-sm leading-tight">{cat.label}</span>
            </button>
          ))}
        </div>
        {loading && <p className="text-emerald-600 font-bold animate-pulse py-4">Generating a fresh tool just for you...</p>}
      </div>

      <Modal 
        isOpen={!!content} 
        onClose={() => setContent(null)} 
        title={content?.title || ''}
      >
        <div className="text-center space-y-8 py-4">
          <div className="p-8 bg-stone-50 rounded-[3rem] text-2xl font-display text-stone-800 leading-relaxed border border-stone-100 shadow-inner">
            {content?.content}
          </div>
          <div className="space-y-4">
            <p className="text-xs font-bold uppercase tracking-widest text-stone-400">MindBloom Restorative Practice</p>
            <button 
              onClick={() => setContent(null)}
              className="w-full bg-emerald-900 text-white py-5 rounded-2xl font-bold text-lg hover:bg-black transition-all shadow-lg"
            >
              I feel centered
            </button>
            <button 
              onClick={() => { if(content) handleSelect(content.title); }}
              className="text-emerald-700 font-bold text-sm hover:underline"
            >
              Give me another one
            </button>
          </div>
        </div>
      </Modal>
    </div>
  );
};

