import React, { useState } from 'react';
import { UserProfile } from '../types';
import { getAiChatResponse } from '../services/gemini';
import Modal from './Modal';

interface Props {
  profile: UserProfile;
  onBack: () => void;
}

const CoachAIView: React.FC<Props> = ({ profile, onBack }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [response, setResponse] = useState<string | null>(null);
  const [showModal, setShowModal] = useState(false);

  const handleSend = async () => {
    if (!input.trim()) return;
    setLoading(true);
    try {
      const res = await getAiChatResponse([], input, profile.children);
      setResponse(res);
      setShowModal(true);
      setInput('');
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto py-10 space-y-8">
      <button onClick={onBack} className="text-sky-700 font-bold flex items-center gap-2 mb-4 hover:translate-x-[-4px] transition-transform">
        ← Back to Hub
      </button>

      <div className="text-center space-y-6">
        <h2 className="text-4xl font-bold text-emerald-900 font-display">Ask Coach AI</h2>
        <p className="text-stone-600">
          Get immediate advice. Ask Coach AI how to tackle any challenge you are facing. Coach AI is here to provide empathetic, 24/7 support.
        </p>

        <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-stone-100 space-y-6">
          <textarea
            className="w-full h-40 p-6 bg-sky-50/50 border border-stone-100 rounded-3xl outline-none focus:ring-4 focus:ring-sky-100 transition-all text-lg"
            placeholder="E.g. I'm feeling so overwhelmed with the morning routine. What can I say to my 5-year-old?"
            value={input}
            onChange={(e) => setInput(e.target.value)}
          />
          <button
            onClick={handleSend}
            disabled={loading || !input.trim()}
            className="w-full py-5 bg-sky-600 text-white rounded-[2rem] font-bold text-xl hover:bg-sky-700 disabled:opacity-50 transition-all shadow-lg"
          >
            {loading ? 'Coach is typing...' : 'Ask Coach AI'}
          </button>
        </div>
      </div>

      <Modal isOpen={showModal} onClose={() => setShowModal(false)} title="Coach AI Response">
        <div className="space-y-6">
          <div className="p-8 bg-sky-50 rounded-[2.5rem] text-stone-800 text-lg leading-relaxed border border-sky-100 whitespace-pre-wrap">
            {response}
          </div>
          <button 
            onClick={() => setShowModal(false)}
            className="w-full bg-sky-600 text-white py-4 rounded-2xl font-bold hover:bg-sky-700 transition-colors"
          >
            Thank you, Coach!
          </button>
        </div>
      </Modal>
    </div>
  );
};

