/**
 * Simple analytics service for MindBloom
 * In a real production app, this would send data to a backend.
 */
export const trackEvent = (eventName: string, properties?: any) => {
  const timestamp = new Date().toISOString();
  const logEntry = {
    event: eventName,
    time: timestamp,
    ...properties
  };

  // Builder can see these in the browser console
  console.log('%c[MindBloom Analytics]', 'color: #7D9D85; font-weight: bold;', logEntry);

  // Optionally persist logs locally for later retrieval
  const logs = JSON.parse(localStorage.getItem('mindbloom_analytics') || '[]');
  logs.push(logEntry);
  localStorage.setItem('mindbloom_analytics', JSON.stringify(logs.slice(-100))); // Keep last 100
};

import React, { useState, useMemo } from 'react';
import { UserProfile, Child } from '../types';
import { trackEvent } from '../services/analytics';

interface OnboardingProps {
  onComplete: (profile: UserProfile) => void;
}

const CHALLENGE_MAP = {
  '0-5': ['Big Emotions', 'Tantrums', 'Separation Anxiety', 'Listening Skills', 'Sleep Routines', 'Activity Transitions', 'Picky Eating', 'Turn Taking', 'Screen Limits', 'Independence Struggles'],
  '6-10': ['Emotional Regulation', 'Friendship Issues', 'Self Confidence', 'Homework Resistance', 'Respectful Listening', 'Disappointment Tolerance', 'Screen Balance', 'Honesty', 'Sibling Conflict', 'Teacher Expectations'],
  '10-15': ['Mood Swings', 'Peer Pressure', 'Communication Breakdown', 'Boundary Testing', 'Self Esteem', 'Motivation Struggles', 'Screen Time', 'Friend Drama', 'Authority Resistance', 'Stress Management'],
  '16-18': ['Independence Tension', 'Trust Building', 'Accountability', 'Emotional Control', 'Decision Making', 'Social Comparison', 'Time Management', 'Conflict Resolution', 'Life Readiness', 'Relationship Shifts']
};

const Onboarding: React.FC<OnboardingProps> = ({ onComplete }) => {
  const [parentName, setParentName] = useState('');
  const [children, setChildren] = useState<Child[]>([]);
  const [tempChild, setTempChild] = useState<Partial<Child>>({ name: '', age: 5, challenges: [], interests: [] });

  const filteredChallenges = useMemo(() => {
    const age = tempChild.age || 0;
    if (age <= 5) return CHALLENGE_MAP['0-5'];
    if (age <= 10) return CHALLENGE_MAP['6-10'];
    if (age <= 15) return CHALLENGE_MAP['10-15'];
    return CHALLENGE_MAP['16-18'];
  }, [tempChild.age]);

  const toggleItem = (item: string, key: 'challenges' | 'interests') => {
    const current = (tempChild[key] as string[]) || [];
    setTempChild({...tempChild, [key]: current.includes(item) ? current.filter(i => i !== item) : [...current, item]});
  };

  const handleFinish = () => {
    let finalChildren = [...children];
    if (tempChild.name) {
      finalChildren.push({
        id: Math.random().toString(36).substr(2, 9),
        name: tempChild.name,
        age: tempChild.age || 5,
        challenges: tempChild.challenges || [],
        interests: tempChild.interests || []
      });
    }
    trackEvent('onboarding_complete', { childrenCount: finalChildren.length });
    onComplete({ 
      name: parentName, 
      children: finalChildren, 
      onboarded: true,
      logs: [],
      favorites: [],
      chatHistory: []
    });
  };

  return (
    <div className="min-h-screen bg-[#FDFBF7] flex items-center justify-center p-4 py-12">
      <div className="max-w-3xl w-full bg-white rounded-[3rem] shadow-xl p-8 md:p-12 space-y-10 border border-emerald-100">
        <div className="text-center space-y-3">
          <h2 className="text-5xl font-bold text-emerald-900 font-display">Welcome to MindBloom</h2>
          <p className="text-stone-500 text-lg">Empowering your parenting journey with AI-driven guidance.</p>
        </div>

        <div className="space-y-10">
          <section className="space-y-4">
            <label className="text-xs font-bold uppercase tracking-widest text-stone-400 px-1">Your Name</label>
            <input
              type="text"
              value={parentName}
              onChange={(e) => setParentName(e.target.value)}
              className="w-full p-5 bg-stone-50 border border-stone-100 rounded-3xl focus:ring-4 focus:ring-emerald-100 outline-none text-xl"
              placeholder="e.g. Sarah"
            />
          </section>

          <section className="space-y-6">
            <h3 className="text-xl font-bold text-emerald-800 font-display">Add a Child</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <input
                type="text"
                placeholder="Name"
                className="p-4 bg-stone-50 border border-stone-100 rounded-2xl outline-none"
                value={tempChild.name}
                onChange={(e) => setTempChild({...tempChild, name: e.target.value})}
              />
              <input
                type="number"
                placeholder="Age"
                className="p-4 bg-stone-50 border border-stone-100 rounded-2xl outline-none"
                value={tempChild.age}
                onChange={(e) => setTempChild({...tempChild, age: parseInt(e.target.value) || 0})}
              />
            </div>

            {tempChild.name && (
              <div className="space-y-4 pt-4">
                <p className="text-sm font-bold text-stone-600 uppercase">Challenges for age {tempChild.age}:</p>
                <div className="flex flex-wrap gap-2">
                  {filteredChallenges.map(c => (
                    <button
                      key={c}
                      onClick={() => toggleItem(c, 'challenges')}
                      className={`px-4 py-2 rounded-full text-xs font-semibold border transition-all ${
                        tempChild.challenges?.includes(c) ? 'bg-emerald-600 border-emerald-700 text-white shadow-md' : 'bg-white border-stone-100 text-stone-400'
                      }`}
                    >
                      {c}
                    </button>
                  ))}
                </div>
              </div>
            )}
          </section>

          <button
            onClick={handleFinish}
            disabled={!parentName || (!tempChild.name && children.length === 0)}
            className="w-full bg-emerald-900 text-white p-6 rounded-[2rem] font-bold text-xl hover:bg-black transition-all shadow-xl disabled:opacity-50"
          >
            Start Blooming Together
          </button>
        </div>
      </div>
    </div>
  );
};

export default Onboarding;

