                    value={tempChild.name}
                    onChange={(e) => setTempChild({ ...tempChild, name: e.target.value })}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-bold uppercase tracking-widest text-stone-400">Age</label>
                  <input
                    type="number"
                    placeholder="Age"
                    className="w-full p-4 bg-stone-50 border border-stone-100 rounded-2xl outline-none focus:ring-2 focus:ring-emerald-100"
                    value={tempChild.age}
                    onChange={(e) => setTempChild({ ...tempChild, age: parseInt(e.target.value) || 0 })}
                  />
                </div>
              </div>

              {tempChild.name && (
                <div className="space-y-6 pt-4 animate-in fade-in duration-300">
                  <div className="space-y-3">
                    <p className="text-[11px] font-bold text-stone-600 uppercase tracking-widest">Select Challenges (Age {tempChild.age}):</p>
                    <div className="flex flex-wrap gap-2">
                      {currentChallenges.map(c => (
                        <button
                          key={c}
                          onClick={() => toggleItem(c, 'challenges')}
