import React, { useState, useMemo } from 'react';
import { UserProfile, Child } from '../types';
import { trackEvent } from '../services/analytics';

interface OnboardingProps {
  onComplete: (profile: UserProfile) => void;
}

const CHALLENGE_MAP = {
  '0-5': ['Big Emotions', 'Tantrums', 'Separation Anxiety', 'Listening Skills', 'Sleep Routines', 'Activity Transitions', 'Picky Eating', 'Turn Taking', 'Screen Limits', 'Independence Struggles'],
  '6-10': ['Emotional Regulation', 'Friendship Issues', 'Self Confidence', 'Homework Resistance', 'Respectful Listening', 'Disappointment Tolerance', 'Screen Balance', 'Honesty', 'Sibling Conflict', 'Teacher Expectations'],
  '11-15': ['Mood Swings', 'Peer Pressure', 'Communication Breakdown', 'Boundary Testing', 'Self Esteem', 'Motivation Struggles', 'Screen Time', 'Friend Drama', 'Authority Resistance', 'Stress Management'],
  '16-18': ['Independence Tension', 'Trust Building', 'Accountability', 'Emotional Control', 'Decision Making', 'Social Comparison', 'Time Management', 'Conflict Resolution', 'Life Readiness', 'Relationship Shifts']
};

const INTERESTS_MAP = {
  '0-5': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Dolls/Cars', 'Building', 'Nature', 'Dance/Music', 'Pretend Play', 'Blocks'],
  '6-10': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Building', 'Games', 'Technology', 'Sports', 'Nature', 'Puzzles'],
  '11-15': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Technology', 'Coding', 'Gaming', 'Debate', 'Social Media', 'Drama'],
  '16-18': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Technology', 'Coding', 'Gaming', 'Travel', 'Career', 'Fitness']
};

const Onboarding: React.FC<OnboardingProps> = ({ onComplete }) => {
  const [parentName, setParentName] = useState('');
  const [children, setChildren] = useState<Child[]>([]);
  const [step, setStep] = useState<'parent' | 'child'>('parent');
  const [tempChild, setTempChild] = useState<Partial<Child>>({ 
    name: '', 
    age: 5, 
    challenges: [], 
    interests: [] 
  });

  const currentChallenges = useMemo(() => {
    const age = tempChild.age || 0;
    if (age <= 5) return CHALLENGE_MAP['0-5'];
    if (age <= 10) return CHALLENGE_MAP['6-10'];
    if (age <= 15) return CHALLENGE_MAP['11-15'];
    return CHALLENGE_MAP['16-18'];
  }, [tempChild.age]);

  const currentInterests = useMemo(() => {
    const age = tempChild.age || 0;
    if (age <= 5) return INTERESTS_MAP['0-5'];
    if (age <= 10) return INTERESTS_MAP['6-10'];
    if (age <= 15) return INTERESTS_MAP['11-15'];
    return INTERESTS_MAP['16-18'];
  }, [tempChild.age]);

  const toggleItem = (item: string, key: 'challenges' | 'interests') => {
    const current = (tempChild[key] as string[]) || [];
    setTempChild({
      ...tempChild, 
      [key]: current.includes(item) ? current.filter(i => i !== item) : [...current, item]
    });
  };

  const handleAddChild = () => {
    if (!tempChild.name) return;
    const newChild: Child = {
      id: Math.random().toString(36).substr(2, 9),
      name: tempChild.name,
      age: tempChild.age || 5,
      challenges: tempChild.challenges || [],
      interests: tempChild.interests || []
    };
    setChildren([...children, newChild]);
    setTempChild({ name: '', age: 5, challenges: [], interests: [] });
    trackEvent('child_added', { age: newChild.age });
  };

  const handleFinish = () => {
    let finalChildren = [...children];
    if (tempChild.name && !children.some(c => c.name === tempChild.name)) {
      finalChildren.push({
        id: Math.random().toString(36).substr(2, 9),
        name: tempChild.name,
        age: tempChild.age || 5,
        challenges: tempChild.challenges || [],
        interests: tempChild.interests || []
      });
    }

    trackEvent('onboarding_complete', { childrenCount: finalChildren.length });
    onComplete({ 
      name: parentName, 
      children: finalChildren, 
      onboarded: true,
      favorites: [],
      chatHistory: []
    });
  };

  return (
    <div className="min-h-screen bg-[#FDFBF7] flex items-center justify-center p-4 py-12">
      <div className="max-w-3xl w-full bg-white rounded-[3rem] shadow-xl p-8 md:p-12 space-y-10 border border-emerald-100">
        <div className="text-center space-y-3">
          <h2 className="text-5xl font-bold text-emerald-900 font-display">MindBloom</h2>
          <p className="text-stone-500 text-lg">Your gentle companion for parenting challenges.</p>
        </div>

        {step === 'parent' ? (
          <div className="space-y-8 animate-in fade-in duration-500">
            <section className="space-y-4">
              <label className="text-xs font-bold uppercase tracking-widest text-stone-400 px-1">What's your name?</label>
              <input
                type="text"
                value={parentName}
                onChange={(e) => setParentName(e.target.value)}
                className="w-full p-5 bg-stone-50 border border-stone-100 rounded-3xl focus:ring-4 focus:ring-emerald-100 outline-none text-xl"
                placeholder="Sarah"
              />
            </section>
            <button
              onClick={() => setStep('child')}
              disabled={!parentName}
              className="w-full bg-emerald-900 text-white p-6 rounded-[2rem] font-bold text-xl hover:bg-black transition-all shadow-xl disabled:opacity-50"
            >
              Continue
            </button>
          </div>
        ) : (
          <div className="space-y-8 animate-in fade-in duration-500">
            {children.length > 0 && (
              <div className="space-y-3">
                <p className="text-[10px] font-bold text-stone-400 uppercase tracking-widest px-1">My Children</p>
                <div className="flex flex-wrap gap-2">
                  {children.map(c => (
                    <div key={c.id} className="bg-emerald-50 text-emerald-800 px-4 py-2 rounded-2xl text-sm font-bold border border-emerald-100">
                      {c.name}, {c.age}
                    </div>
                  ))}
                </div>
              </div>
            )}

            <section className="space-y-6">
              <h3 className="text-xl font-bold text-emerald-800 font-display">
                {children.length === 0 ? "Tell us about your child" : "Add another child"}
              </h3>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-bold uppercase tracking-widest text-stone-400 px-1">Name</label>
                  <input
                    type="text"
                    placeholder="Child's Name"
                    className="w-full p-4 bg-stone-50 border border-stone-100 rounded-2xl outline-none"
                    value={tempChild.name}
                    onChange={(e) => setTempChild({...tempChild, name: e.target.value})}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-bold uppercase tracking-widest text-stone-400 px-1">Age</label>
                  <input
                    type="number"
                    placeholder="Age"
                    className="w-full p-4 bg-stone-50 border border-stone-100 rounded-2xl outline-none"
                    value={tempChild.age}
                    onChange={(e) => setTempChild({...tempChild, age: parseInt(e.target.value) || 0})}
                  />
                </div>
              </div>

              {tempChild.name && (
                <div className="space-y-8 pt-4 animate-in fade-in duration-500">
                  <div className="space-y-4">
                    <p className="text-[11px] font-bold text-stone-600 uppercase tracking-widest">Select Challenges for age {tempChild.age}:</p>
                    <div className="flex flex-wrap gap-2">
                      {currentChallenges.map(c => (
                        <button
                          key={c}
                          onClick={() => toggleItem(c, 'challenges')}
                          className={`px-4 py-2 rounded-full text-xs font-semibold border transition-all ${
                            tempChild.challenges?.includes(c) ? 'bg-emerald-600 border-emerald-700 text-white shadow-md' : 'bg-white border-stone-100 text-stone-400'
                          }`}
                        >
                          {c}
                        </button>
                      ))}
                    </div>
                  </div>

                  <div className="space-y-4">
                    <p className="text-[11px] font-bold text-stone-600 uppercase tracking-widest">Select Interests:</p>
                    <div className="flex flex-wrap gap-2">
                      {currentInterests.map(i => (
                        <button
                          key={i}
                          onClick={() => toggleItem(i, 'interests')}
                          className={`px-4 py-2 rounded-full text-xs font-semibold border transition-all ${
                            tempChild.interests?.includes(i) ? 'bg-sky-600 border-sky-700 text-white shadow-md' : 'bg-white border-stone-100 text-stone-400'
                          }`}
                        >
                          {i}
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
              )}
            </section>

            <div className="flex flex-col sm:flex-row gap-4 pt-4">
              <button
                onClick={handleAddChild}
                disabled={!tempChild.name}
                className="flex-1 bg-white text-emerald-900 border-2 border-emerald-900 p-5 rounded-2xl font-bold text-lg hover:bg-emerald-50 transition-all disabled:opacity-30"
              >
                Add This Child
              </button>
              <button
                onClick={handleFinish}
                disabled={children.length === 0 && !tempChild.name}
                className="flex-1 bg-emerald-900 text-white p-5 rounded-2xl font-bold text-lg hover:bg-black transition-all shadow-xl disabled:opacity-50"
              >
                Start Blooming
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Onboarding;

