import React, { useState, useEffect, useRef } from 'react';
import { UserProfile, ChatMessage, FavoriteItem } from '../types';
import { getAiChatResponse } from '../services/gemini';
import { trackEvent } from '../services/analytics';

interface Props {
  profile: UserProfile;
  onUpdateProfile: (profile: UserProfile) => void;
  onBack: () => void;
}

const CoachAIView: React.FC<Props> = ({ profile, onUpdateProfile, onBack }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [profile.chatHistory]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg: ChatMessage = { 
      role: 'user', 
      content: input, 
      timestamp: new Date().toISOString() 
    };

    const updatedHistory = [...profile.chatHistory, userMsg];
    onUpdateProfile({ ...profile, chatHistory: updatedHistory });
    setInput('');
    setLoading(true);
    trackEvent('coach_query', { length: input.length });

    try {
      const resText = await getAiChatResponse(updatedHistory.map(m => ({ role: m.role, content: m.content })), input, profile.children);
      const aiMsg: ChatMessage = { 
        role: 'assistant', 
        content: resText, 
        timestamp: new Date().toISOString() 
      };
      onUpdateProfile({ ...profile, chatHistory: [...updatedHistory, aiMsg] });
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const saveToFavorites = (content: string) => {
    const newItem: FavoriteItem = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'advice',
      title: "Coach AI Insight",
      content,
      dateSaved: new Date().toISOString()
    };
    onUpdateProfile({ ...profile, favorites: [...profile.favorites, newItem] });
    trackEvent('favorite_saved', { type: 'coach_advice' });
    alert("Saved to My Favorites! 🌻");
  };

  return (
    <div className="max-w-3xl mx-auto py-10 flex flex-col h-[80vh]">
      <div className="flex justify-between items-center mb-6">
        <button onClick={onBack} className="text-sky-700 font-bold flex items-center gap-2 hover:translate-x-[-4px] transition-transform">← Back to Hub</button>
        <div className="text-right">
          <h2 className="text-2xl font-bold text-slate-800 font-display">Ask Coach AI</h2>
          <p className="text-[10px] text-stone-400 font-bold uppercase tracking-widest">History is preserved</p>
        </div>
      </div>

      <div className="flex-1 bg-white rounded-[3rem] shadow-sm border border-stone-100 overflow-hidden flex flex-col">
        <div className="flex-1 overflow-y-auto p-6 space-y-6">
          {profile.chatHistory.length === 0 && (
            <div className="h-full flex flex-col items-center justify-center text-center p-10 space-y-4 text-stone-300">
               <span className="text-6xl">🤖</span>
               <p className="font-display text-xl italic">"I'm here to listen. Ask me how to tackle any challenge you're facing today."</p>
            </div>
          )}
          {profile.chatHistory.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[85%] space-y-2`}>
                <div className={`p-6 rounded-[2.5rem] shadow-sm ${
                  msg.role === 'user' ? 'bg-[#A3C9D6] text-white rounded-tr-none' : 'bg-stone-50 text-slate-700 rounded-tl-none border border-stone-100'
                }`}>
                  <p className="whitespace-pre-wrap text-sm leading-relaxed">{msg.content}</p>
                </div>
                {msg.role === 'assistant' && (
                  <button 
                    onClick={() => saveToFavorites(msg.content)} 
                    className="text-[10px] font-bold text-sky-600 hover:underline ml-2 uppercase tracking-widest"
                  >
                    Save To My Favorite
                  </button>
                )}
              </div>
            </div>
          ))}
          {loading && (
            <div className="flex justify-start">
              <div className="bg-stone-50 p-4 rounded-2xl animate-pulse text-xs font-bold text-stone-400">Coach is thinking...</div>
            </div>
          )}
          <div ref={scrollRef} />
        </div>

        <div className="p-6 bg-stone-50/50 border-t border-stone-100">
          <div className="flex gap-2">
            <input
              type="text"
              className="flex-1 p-4 bg-white border border-stone-100 rounded-2xl outline-none focus:ring-2 focus:ring-sky-100 text-sm"
              placeholder="Ask anything..."
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            />
            <button
              onClick={handleSend}
              disabled={loading || !input.trim()}
              className="bg-sky-600 text-white px-8 py-4 rounded-2xl font-bold hover:bg-sky-700 disabled:opacity-50 transition-all shadow-md"
            >
              Ask
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CoachAIView;

