import React, { useState } from 'react';
import { UserProfile, Child, DailyTip, FavoriteItem } from '../types';
import { getChallengeAdvice } from '../services/gemini';
import Modal from './Modal';
import { trackEvent } from '../services/analytics';

interface Props {
  profile: UserProfile;
  onUpdateProfile: (profile: UserProfile) => void;
  onBack: () => void;
}

const AdviceActivities: React.FC<Props> = ({ profile, onUpdateProfile, onBack }) => {
  const [selectedChild, setSelectedChild] = useState<Child>(profile.children[0]);
  const [selectedChallenge, setSelectedChallenge] = useState<string>('');
  const [advice, setAdvice] = useState<DailyTip | null>(null);
  const [loading, setLoading] = useState(false);
  const [showMainModal, setShowMainModal] = useState(false);
  const [feedbackGiven, setFeedbackGiven] = useState<string | null>(null);
  const [savedItems, setSavedItems] = useState<Set<string>>(new Set());

  const handleChallengeClick = async (challenge: string) => {
    setSelectedChallenge(challenge);
    setLoading(true);
    setFeedbackGiven(null);
    setSavedItems(new Set());
    trackEvent('advice_request', { challenge, childAge: selectedChild.age });
    try {
      const res = await getChallengeAdvice(selectedChild, challenge);
      setAdvice(res);
      setShowMainModal(true);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const saveToFavorites = (type: 'advice' | 'script' | 'activity', content: string) => {
    const key = `${type}-${content.substring(0, 10)}`;
    if (savedItems.has(key)) return;

    const newItem: FavoriteItem = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      title: `${selectedChallenge} (${type})`,
      content,
      childContext: `${selectedChild.name} (Age ${selectedChild.age})`,
      dateSaved: new Date().toISOString()
    };

    onUpdateProfile({ ...profile, favorites: [...profile.favorites, newItem] });
    setSavedItems(prev => new Set(prev).add(key));
    trackEvent('favorite_saved', { type });
  };

  const handleFeedback = (val: string) => {
    setFeedbackGiven(val);
    trackEvent('advice_feedback', { challenge: selectedChallenge, feedback: val });
  };

  const isSaved = (type: string, content: string) => {
    const key = `${type}-${content.substring(0, 10)}`;
    return savedItems.has(key);
  };

  return (
    <div className="space-y-12 max-w-2xl mx-auto py-10">
      <button onClick={onBack} className="text-emerald-700 font-bold flex items-center gap-2 hover:translate-x-[-4px] transition-transform">← Back to Hub</button>

      <div className="text-center space-y-8 animate-in fade-in duration-500">
        <div className="space-y-2">
          <h2 className="text-4xl font-bold text-emerald-900 font-display">Help with my child</h2>
          <p className="text-stone-500">Tailored guidance for social-emotional growth.</p>
        </div>

        <div className="space-y-10 bg-white p-8 rounded-[3rem] shadow-sm border border-emerald-100">
          <div className="space-y-4">
            <label className="text-xs font-bold uppercase tracking-widest text-stone-400">Step 1: Choose Child</label>
            <div className="flex justify-center gap-2 flex-wrap">
              {profile.children.map(c => (
                <button
                  key={c.id}
                  onClick={() => setSelectedChild(c)}
                  className={`px-6 py-2 rounded-full text-sm font-bold transition-all border ${
                    selectedChild.id === c.id ? 'bg-emerald-600 text-white shadow-md' : 'bg-white text-stone-400'
                  }`}
                >
                  {c.name}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-4">
            <label className="text-xs font-bold uppercase tracking-widest text-stone-400">Step 2: Today's Challenge</label>
            <div className="flex justify-center gap-2 flex-wrap">
              {selectedChild.challenges.map(c => (
                <button
                  key={c}
                  disabled={loading}
                  onClick={() => handleChallengeClick(c)}
                  className="px-6 py-2 rounded-full text-sm font-bold bg-white border border-stone-100 text-stone-600 hover:bg-emerald-50 transition-colors"
                >
                  {c}
                </button>
              ))}
            </div>
          </div>
          {loading && <div className="py-4 text-emerald-600 font-bold animate-pulse">Specialist is thinking...</div>}
        </div>
      </div>

      <Modal isOpen={showMainModal} onClose={() => setShowMainModal(false)} title={`${selectedChallenge} Support`}>
        <div className="space-y-8">
          <div className="flex flex-col gap-2 p-4 bg-stone-50 rounded-2xl border border-stone-100 text-[11px] font-bold text-stone-500 uppercase tracking-wider">
            <span>✔️ Recommended for ages {selectedChild.age - 1}-{selectedChild.age + 1}</span>
            <span>✔️ Based on current interests: {selectedChild.interests.join(', ')}</span>
          </div>

          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <h4 className="font-bold text-emerald-900 uppercase text-xs tracking-widest">Expert Advice</h4>
              <button 
                onClick={() => saveToFavorites('advice', advice?.content || '')}
                className={`text-[10px] font-bold border px-3 py-1 rounded-full transition-all ${
                  isSaved('advice', advice?.content || '') 
                  ? 'bg-emerald-600 text-white border-emerald-600' 
                  : 'text-emerald-600 border-emerald-100 hover:bg-emerald-50'
                }`}
              >
                {isSaved('advice', advice?.content || '') ? 'Saved ⭐' : 'Save to Favorites'}
              </button>
            </div>
            <p className="text-lg text-stone-700 leading-relaxed">{advice?.content}</p>
          </div>

          <div className="space-y-4 bg-stone-50 p-6 rounded-3xl border border-stone-100">
            <div className="flex justify-between items-center">
              <h5 className="font-bold text-stone-800 text-xs uppercase tracking-widest">The Script</h5>
              <button 
                onClick={() => saveToFavorites('script', advice?.script || '')}
                className={`text-[10px] font-bold border px-3 py-1 rounded-full transition-all ${
                  isSaved('script', advice?.script || '') 
                  ? 'bg-emerald-600 text-white border-emerald-600' 
                  : 'text-emerald-600 border-emerald-100 hover:bg-emerald-50'
                }`}
              >
                {isSaved('script', advice?.script || '') ? 'Saved ⭐' : 'Save to Favorites'}
              </button>
            </div>
            <p className="italic text-stone-600 text-xl font-display">"{advice?.script}"</p>
          </div>

          <div className="space-y-4 bg-emerald-50/50 p-6 rounded-3xl border border-emerald-100">
            <div className="flex justify-between items-center">
              <h5 className="font-bold text-emerald-800 text-xs uppercase tracking-widest">Tailored Activity</h5>
              <button 
                onClick={() => saveToFavorites('activity', advice?.activity || '')}
                className={`text-[10px] font-bold border px-3 py-1 rounded-full transition-all ${
                  isSaved('activity', advice?.activity || '') 
                  ? 'bg-emerald-600 text-white border-emerald-600' 
                  : 'text-emerald-600 border-emerald-100 hover:bg-emerald-50'
                }`}
              >
                {isSaved('activity', advice?.activity || '') ? 'Saved ⭐' : 'Save to Favorites'}
              </button>
            </div>
            <p className="text-stone-700">{advice?.activity}</p>
          </div>

          <div className="pt-6 border-t border-stone-100 text-center space-y-4">
            <p className="text-xs font-bold text-stone-400 uppercase tracking-widest">Did this help?</p>
            {feedbackGiven ? (
              <p className="text-emerald-600 font-bold">Thank you for your feedback! 🌻</p>
            ) : (
              <div className="flex justify-center gap-3">
                {['Yes', 'Somewhat', 'Not yet'].map(val => (
                  <button
                    key={val}
                    onClick={() => handleFeedback(val)}
                    className="px-6 py-2 rounded-xl bg-white border border-stone-200 text-sm font-bold hover:bg-stone-50 active:scale-95 transition-all"
                  >
                    {val}
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>
      </Modal>
    </div>
  );
};

export default AdviceActivities;

