import React, { useState } from 'react';
import { UserProfile, Child, DailyTip, FavoriteItem } from '../types';
import { getChallengeAdvice } from '../services/gemini';
import Modal from './Modal';
import { trackEvent } from '../services/analytics';

interface Props {
  profile: UserProfile;
  onUpdateProfile: (profile: UserProfile) => void;
  onBack: () => void;
}

const AdviceActivities: React.FC<Props> = ({ profile, onUpdateProfile, onBack }) => {
  const [selectedChild, setSelectedChild] = useState<Child>(profile.children[0]);
  const [selectedChallenge, setSelectedChallenge] = useState<string>('');
  const [advice, setAdvice] = useState<DailyTip | null>(null);
  const [loading, setLoading] = useState(false);
  const [showMainModal, setShowMainModal] = useState(false);
  const [feedbackGiven, setFeedbackGiven] = useState<string | null>(null);
  const [savedItems, setSavedItems] = useState<Set<string>>(new Set());

  const handleChallengeClick = async (challenge: string) => {
    setSelectedChallenge(challenge);
    setLoading(true);
    setFeedbackGiven(null);
    setSavedItems(new Set());
    trackEvent('advice_request', { challenge, childAge: selectedChild.age });
    try {
      const res = await getChallengeAdvice(selectedChild, challenge);
      setAdvice(res);
      setShowMainModal(true);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const saveToFavorites = (type: 'advice' | 'script' | 'activity', content: string) => {
    const key = `${type}-${content.substring(0, 10)}`;
    if (savedItems.has(key)) return;

    const newItem: FavoriteItem = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      title: `${selectedChallenge} (${type})`,
      content,
      childContext: `${selectedChild.name} (Age ${selectedChild.age})`,
      dateSaved: new Date().toISOString()
    };

    onUpdateProfile({ ...profile, favorites: [...profile.favorites, newItem] });
    setSavedItems(prev => new Set(prev).add(key));
    trackEvent('favorite_saved', { type });
  };

  const handleFeedback = (val: string) => {
    setFeedbackGiven(val);
    trackEvent('advice_feedback', { challenge: selectedChallenge, feedback: val });
  };

  const isSaved = (type: string, content: string) => {
    const key = `${type}-${content.substring(0, 10)}`;
    return savedItems.has(key);
  };

  return (
    <div className="space-y-12 max-w-3xl mx-auto py-10">
      <button onClick={onBack} className="text-[#FF9F66] font-bold flex items-center gap-2 hover:translate-x-[-4px] transition-transform font-display">
        <span className="text-2xl">←</span> Back to Home
      </button>

      <div className="text-center space-y-10 animate-in fade-in duration-500">
        <div className="space-y-3">
          <h2 className="text-4xl md:text-5xl font-bold text-[#433E3E] font-display">Help with my child</h2>
          <p className="text-[#433E3E]/60 font-medium">Tailored guidance for social-emotional growth.</p>
        </div>

        <div className="space-y-12 bg-white p-10 md:p-14 rounded-[4rem] shadow-xl shadow-orange-900/5 border-2 border-orange-100/50">
          <div className="space-y-6">
            <label className="text-[10px] font-black uppercase tracking-[0.25em] text-[#FF9F66]">Step 1: Choose Child</label>
            <div className="flex justify-center gap-3 flex-wrap">
              {profile.children.map(c => (
                <button
                  key={c.id}
                  onClick={() => setSelectedChild(c)}
                  className={`px-8 py-3 rounded-full text-sm font-bold transition-all border-2 ${
                    selectedChild.id === c.id 
                    ? 'bg-[#FF9F66] border-[#FF9F66] text-white shadow-lg shadow-orange-200' 
                    : 'bg-white border-orange-50 text-orange-300 hover:border-orange-100'
                  }`}
                >
                  {c.name}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-6">
            <label className="text-[10px] font-black uppercase tracking-[0.25em] text-[#FF9F66]">Step 2: Today's Challenge</label>
            <div className="flex justify-center gap-3 flex-wrap">
              {selectedChild.challenges.map(c => (
                <button
                  key={c}
                  disabled={loading}
                  onClick={() => handleChallengeClick(c)}
                  className="px-6 py-3 rounded-full text-sm font-bold bg-[#F1F5E9] border-2 border-[#789461]/10 text-[#789461] hover:bg-[#789461] hover:text-white transition-all transform hover:-translate-y-1"
                >
                  {c}
                </button>
              ))}
            </div>
          </div>
          {loading && (
            <div className="py-4 flex flex-col items-center gap-3">
              <div className="w-8 h-8 border-4 border-orange-200 border-t-orange-500 rounded-full animate-spin"></div>
              <p className="text-[#FF9F66] font-bold text-sm animate-pulse">Growing your advice...</p>
            </div>
          )}
        </div>
      </div>

      <Modal isOpen={showMainModal} onClose={() => setShowMainModal(false)} title={selectedChallenge}>
        <div className="space-y-10">
          <div className="flex items-start gap-3 p-5 bg-[#F1F5E9] rounded-[2rem] border-2 border-[#789461]/10 text-sm font-medium text-[#789461]">
            <span className="text-2xl">🌱</span>
            <div className="space-y-1">
              <p>Recommended for ages {selectedChild.age - 1}-{selectedChild.age + 1}</p>
              <p className="text-[10px] opacity-70 uppercase font-black tracking-widest">Based on interest: {selectedChild.interests[0]}</p>
            </div>
          </div>

          <div className="space-y-4">
