              <h4 className="font-black text-[#FF9F66] uppercase text-[10px] tracking-[0.2em]">Expert Advice</h4>
              <button 
                onClick={() => saveToFavorites('advice', advice?.content || '')}
                className={`text-[9px] font-black border-2 px-4 py-1.5 rounded-full transition-all uppercase tracking-widest ${
                  isSaved('advice', advice?.content || '') 
                  ? 'bg-[#789461] text-white border-[#789461]' 
                  : 'text-[#789461] border-[#789461]/10 hover:bg-[#789461]/5'
                }`}
              >
                {isSaved('advice', advice?.content || '') ? 'Saved ⭐' : 'Save'}
              </button>
            </div>
            <p className="text-xl text-[#433E3E] leading-relaxed font-display">{advice?.content}</p>
          </div>

          <div className="space-y-5 bg-[#FFEDE3] p-8 rounded-[3rem] border-2 border-[#FFEDE3]">
            <div className="flex justify-between items-center">
              <h5 className="font-black text-[#FF9F66] text-[10px] uppercase tracking-[0.2em]">The Script</h5>
              <button 
                onClick={() => saveToFavorites('script', advice?.script || '')}
                className={`text-[9px] font-black border-2 px-4 py-1.5 rounded-full transition-all uppercase tracking-widest ${
                  isSaved('script', advice?.script || '') 
                  ? 'bg-[#FF9F66] text-white border-[#FF9F66]' 
                  : 'text-[#FF9F66] border-[#FF9F66]/10 hover:bg-[#FF9F66]/5'
                }`}
              >
                {isSaved('script', advice?.script || '') ? 'Saved ⭐' : 'Save'}
              </button>
            </div>
            <p className="italic text-[#433E3E] text-2xl font-display leading-snug">"{advice?.script}"</p>
          </div>

          <div className="space-y-5 bg-white p-8 rounded-[3rem] border-2 border-orange-50 shadow-sm shadow-orange-900/5">
            <div className="flex justify-between items-center">
              <h5 className="font-black text-[#789461] text-[10px] uppercase tracking-[0.2em]">Activity</h5>
              <button 
                onClick={() => saveToFavorites('activity', advice?.activity || '')}
                className={`text-[9px] font-black border-2 px-4 py-1.5 rounded-full transition-all uppercase tracking-widest ${
                  isSaved('activity', advice?.activity || '') 
                  ? 'bg-[#789461] text-white border-[#789461]' 
                  : 'text-[#789461] border-[#789461]/10 hover:bg-[#789461]/5'
                }`}
              >
                {isSaved('activity', advice?.activity || '') ? 'Saved ⭐' : 'Save'}
              </button>
            </div>
            <p className="text-[#433E3E]/80 font-medium leading-relaxed">{advice?.activity}</p>
          </div>

          <div className="pt-8 border-t border-orange-100 text-center space-y-6">
            <p className="text-[10px] font-black text-[#433E3E]/30 uppercase tracking-[0.3em]">Was this helpful?</p>
            {feedbackGiven ? (
              <p className="text-[#789461] font-bold animate-in zoom-in duration-300">Thank you! 🌻</p>
            ) : (
              <div className="flex justify-center gap-3">
                {['Yes', 'Kind of', 'No'].map(val => (
                  <button
                    key={val}
                    onClick={() => handleFeedback(val)}
                    className="px-8 py-3 rounded-full bg-[#FFF8F0] border-2 border-orange-100 text-sm font-bold text-[#FF9F66] hover:bg-[#FF9F66] hover:text-white transition-all active:scale-95"
                  >
                    {val}
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>
      </Modal>
    </div>
  );
};

export default AdviceActivities;

import React, { useState, useEffect, useRef } from 'react';
import { UserProfile, ChatMessage, FavoriteItem } from '../types';
import { getAiChatResponse } from '../services/gemini';
import { trackEvent } from '../services/analytics';

interface Props {
  profile: UserProfile;
  onUpdateProfile: (profile: UserProfile) => void;
  onBack: () => void;
}

const CoachAIView: React.FC<Props> = ({ profile, onUpdateProfile, onBack }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [profile.chatHistory]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg: ChatMessage = { 
      role: 'user', 
      content: input, 
      timestamp: new Date().toISOString() 
    };

    const updatedHistory = [...profile.chatHistory, userMsg];
    onUpdateProfile({ ...profile, chatHistory: updatedHistory });
    setInput('');
    setLoading(true);
    trackEvent('coach_query', { length: input.length });

    try {
      const resText = await getAiChatResponse(updatedHistory.map(m => ({ role: m.role, content: m.content })), input, profile.children);
      const aiMsg: ChatMessage = { 
        role: 'assistant', 
        content: resText, 
        timestamp: new Date().toISOString() 
      };
      onUpdateProfile({ ...profile, chatHistory: [...updatedHistory, aiMsg] });
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const saveToFavorites = (content: string) => {
    const newItem: FavoriteItem = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'advice',
      title: "Coach AI Insight",
      content,
      dateSaved: new Date().toISOString()
    };
    onUpdateProfile({ ...profile, favorites: [...profile.favorites, newItem] });
    trackEvent('favorite_saved', { type: 'coach_advice' });
  };

  return (
    <div className="max-w-4xl mx-auto py-8 flex flex-col h-[82vh]">
      <div className="flex justify-between items-center mb-8 px-4">
        <button onClick={onBack} className="text-[#FF9F66] font-bold flex items-center gap-2 font-display">
          <span className="text-xl">←</span> Back
        </button>
        <div className="text-right">
          <h2 className="text-3xl font-bold text-[#433E3E] font-display">Coach AI</h2>
          <p className="text-[10px] text-[#FF9F66] font-black uppercase tracking-[0.2em]">Always Here to Listen</p>
        </div>
      </div>

      <div className="flex-1 bg-white rounded-[4rem] shadow-xl shadow-orange-900/5 border-2 border-orange-100/50 overflow-hidden flex flex-col">
        <div className="flex-1 overflow-y-auto p-8 md:p-12 space-y-8 scrollbar-hide">
          {profile.chatHistory.length === 0 && (
            <div className="h-full flex flex-col items-center justify-center text-center p-10 space-y-6">
               <div className="w-24 h-24 bg-[#FFEDE3] rounded-full flex items-center justify-center text-5xl animate-float">🤖</div>
               <div className="space-y-2">
                 <p className="font-display text-2xl text-[#433E3E] font-bold">"How are you feeling today?"</p>
                 <p className="text-[#433E3E]/40 font-medium">I'm here to help you navigate any parenting situation.</p>
               </div>
            </div>
          )}
          {profile.chatHistory.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 duration-300`}>
              <div className={`max-w-[85%] md:max-w-[70%] space-y-2`}>
                <div className={`p-6 md:p-8 rounded-[2.5rem] shadow-sm font-medium leading-relaxed ${
                  msg.role === 'user' 
                  ? 'bg-[#FF9F66] text-white rounded-tr-none shadow-orange-200' 
                  : 'bg-[#F1F5E9] text-[#433E3E] rounded-tl-none border-2 border-[#789461]/10'
                }`}>
                  <p className="whitespace-pre-wrap text-sm md:text-base">{msg.content}</p>
                </div>
                {msg.role === 'assistant' && (
                  <button 
                    onClick={() => saveToFavorites(msg.content)} 
                    className="text-[9px] font-black text-[#789461] uppercase tracking-widest hover:underline ml-4"
                  >
                    Save to favorites ⭐
                  </button>
                )}
              </div>
            </div>
          ))}
          {loading && (
            <div className="flex justify-start">
              <div className="bg-[#F1F5E9] px-6 py-4 rounded-full border-2 border-[#789461]/10 flex gap-2 items-center">
                <div className="w-1.5 h-1.5 bg-[#789461] rounded-full animate-bounce"></div>
                <div className="w-1.5 h-1.5 bg-[#789461] rounded-full animate-bounce [animation-delay:0.2s]"></div>
                <div className="w-1.5 h-1.5 bg-[#789461] rounded-full animate-bounce [animation-delay:0.4s]"></div>
              </div>
            </div>
          )}
          <div ref={scrollRef} />
        </div>

        <div className="p-6 md:p-8 bg-[#FFF8F0] border-t-2 border-orange-50">
          <div className="flex gap-3 max-w-3xl mx-auto">
            <input
              type="text"
              className="flex-1 p-5 bg-white border-2 border-orange-100 rounded-full outline-none focus:ring-4 focus:ring-orange-200/20 text-sm md:text-base font-medium shadow-inner transition-all"
              placeholder="Tell me what's on your mind..."
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            />
            <button
              onClick={handleSend}
              disabled={loading || !input.trim()}
              className="bg-[#FF9F66] text-white w-14 h-14 md:w-16 md:h-16 rounded-full flex items-center justify-center font-bold hover:scale-105 active:scale-95 disabled:opacity-50 transition-all shadow-lg shadow-orange-200"
            >
              <span className="text-2xl">→</span>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

