                        <button
                          key={c}
                          onClick={() => toggleItem(c, 'challenges')}
                          className={`px-5 py-2 rounded-full text-xs font-bold border-2 transition-all ${
                            tempChild.challenges?.includes(c) 
                            ? 'bg-[#789461] border-[#789461] text-white shadow-md' 
                            : 'bg-white border-orange-50 text-orange-200 hover:border-orange-100'
                          }`}
                        >
                          {c}
                        </button>
                      ))}
                    </div>
                  </div>

                  <div className="space-y-5">
                    <p className="text-[10px] font-black text-[#FF9F66] uppercase tracking-[0.2em] text-center">Interest List</p>
                    <div className="flex flex-wrap justify-center gap-2">
                      {currentInterests.map(i => (
                        <button
                          key={i}
                          onClick={() => toggleItem(i, 'interests')}
                          className={`px-5 py-2 rounded-full text-xs font-bold border-2 transition-all ${
                            tempChild.interests?.includes(i) 
                            ? 'bg-[#FF9F66] border-[#FF9F66] text-white shadow-md' 
                            : 'bg-white border-orange-50 text-orange-200 hover:border-orange-100'
                          }`}
                        >
                          {i}
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
              )}
            </section>

            <div className="flex flex-col sm:flex-row gap-4 pt-6">
              <button
                onClick={handleAddChild}
                disabled={!tempChild.name}
                className="flex-1 bg-white text-[#FF9F66] border-2 border-[#FF9F66] p-6 rounded-[2.5rem] font-bold text-lg hover:bg-[#FFEDE3] transition-all disabled:opacity-30 font-display"
              >
                Add Child
              </button>
              <button
                onClick={handleFinish}
                disabled={children.length === 0 && !tempChild.name}
                className="flex-1 bg-[#FF9F66] text-white p-6 rounded-[2.5rem] font-bold text-lg hover:bg-[#FF9F66]/90 transition-all shadow-xl shadow-orange-200 disabled:opacity-50 font-display"
              >
                Let's Start
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Onboarding;

