import React, { useState, useMemo } from 'react';
import { UserProfile, Child } from '../types';
import { trackEvent } from '../services/analytics';

interface OnboardingProps {
  onComplete: (profile: UserProfile) => void;
}

const CHALLENGE_MAP = {
  '0-5': ['Big Emotions', 'Tantrums', 'Separation Anxiety', 'Listening Skills', 'Sleep Routines', 'Activity Transitions', 'Picky Eating', 'Turn Taking', 'Screen Limits', 'Independence Struggles'],
  '6-10': ['Emotional Regulation', 'Friendship Issues', 'Self Confidence', 'Homework Resistance', 'Respectful Listening', 'Disappointment Tolerance', 'Screen Balance', 'Honesty', 'Sibling Conflict', 'Teacher Expectations'],
  '11-15': ['Mood Swings', 'Peer Pressure', 'Communication Breakdown', 'Boundary Testing', 'Self Esteem', 'Motivation Struggles', 'Screen Time', 'Friend Drama', 'Authority Resistance', 'Stress Management'],
  '16-18': ['Independence Tension', 'Trust Building', 'Accountability', 'Emotional Control', 'Decision Making', 'Social Comparison', 'Time Management', 'Conflict Resolution', 'Life Readiness', 'Relationship Shifts']
};

const INTERESTS_MAP = {
  '0-5': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Dolls/Cars', 'Building', 'Nature', 'Dance/Music', 'Pretend Play', 'Blocks'],
  '6-10': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Building', 'Games', 'Technology', 'Sports', 'Nature', 'Puzzles'],
  '11-15': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Technology', 'Coding', 'Gaming', 'Debate', 'Social Media', 'Drama'],
  '16-18': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Technology', 'Coding', 'Gaming', 'Travel', 'Career', 'Fitness']
};

const Onboarding: React.FC<OnboardingProps> = ({ onComplete }) => {
  const [parentName, setParentName] = useState('');
  const [children, setChildren] = useState<Child[]>([]);
  const [step, setStep] = useState<'parent' | 'child'>('parent');
  const [tempChild, setTempChild] = useState<Partial<Child>>({ 
    name: '', 
    age: 5, 
    challenges: [], 
    interests: [] 
  });

  const currentChallenges = useMemo(() => {
    const age = tempChild.age || 0;
    if (age <= 5) return CHALLENGE_MAP['0-5'];
    if (age <= 10) return CHALLENGE_MAP['6-10'];
    if (age <= 15) return CHALLENGE_MAP['11-15'];
    return CHALLENGE_MAP['16-18'];
  }, [tempChild.age]);

  const currentInterests = useMemo(() => {
    const age = tempChild.age || 0;
    if (age <= 5) return INTERESTS_MAP['0-5'];
    if (age <= 10) return INTERESTS_MAP['6-10'];
    if (age <= 15) return INTERESTS_MAP['11-15'];
    return INTERESTS_MAP['16-18'];
  }, [tempChild.age]);

  const toggleItem = (item: string, key: 'challenges' | 'interests') => {
    const current = (tempChild[key] as string[]) || [];
    setTempChild({
      ...tempChild, 
      [key]: current.includes(item) ? current.filter(i => i !== item) : [...current, item]
    });
  };

  const handleAddChild = () => {
    if (!tempChild.name) return;
    const newChild: Child = {
      id: Math.random().toString(36).substr(2, 9),
      name: tempChild.name,
      age: tempChild.age || 5,
      challenges: tempChild.challenges || [],
      interests: tempChild.interests || []
    };
    setChildren([...children, newChild]);
    setTempChild({ name: '', age: 5, challenges: [], interests: [] });
    trackEvent('child_added', { age: newChild.age });
  };

  const handleFinish = () => {
    let finalChildren = [...children];
    if (tempChild.name && !children.some(c => c.name === tempChild.name)) {
      finalChildren.push({
        id: Math.random().toString(36).substr(2, 9),
        name: tempChild.name,
        age: tempChild.age || 5,
        challenges: tempChild.challenges || [],
        interests: tempChild.interests || []
      });
    }

    onComplete({ 
      name: parentName, 
      children: finalChildren, 
      onboarded: true,
      favorites: [],
      chatHistory: [],
      logs: []
    });
  };

  return (
    <div className="min-h-screen bg-[#FDFBF7] flex items-center justify-center p-6 py-12">
      <div className="max-w-3xl w-full bg-white rounded-[4rem] shadow-2xl shadow-[#8B9D83]/5 p-10 md:p-16 space-y-12 border border-[#8B9D83]/10 relative overflow-hidden">
        <div className="absolute -top-12 -right-12 text-7xl opacity-5 animate-spin-slow">🌻</div>

        <div className="text-center space-y-4">
          <h2 className="text-6xl font-bold text-[#4A4A4A] font-display tracking-tight">Mind<span className="text-[#8B9D83]">Bloom</span></h2>
          <p className="text-[#4A4A4A]/50 text-xl font-medium font-display">Gentle guidance for growing families.</p>
        </div>

        {step === 'parent' ? (
          <div className="space-y-12 animate-in fade-in zoom-in duration-500 max-w-md mx-auto">
            <section className="space-y-6 text-center">
              <label className="text-[10px] font-black uppercase tracking-[0.4em] text-[#8B9D83]">Welcome! What is your name?</label>
              <input
                type="text"
                value={parentName}
                onChange={(e) => setParentName(e.target.value)}
                className="w-full p-6 bg-[#FDFBF7] border-2 border-[#8B9D83]/10 rounded-[2.5rem] focus:ring-8 focus:ring-[#8B9D83]/10 outline-none text-3xl text-center font-display font-bold text-[#4A4A4A] transition-all"
                placeholder="Sarah"
              />
            </section>
            <button
              onClick={() => setStep('child')}
              disabled={!parentName}
              className="w-full bg-[#8B9D83] text-white p-7 rounded-[3rem] font-bold text-2xl hover:scale-[1.02] transition-all shadow-xl shadow-[#8B9D83]/20 disabled:opacity-50 font-display"
            >
              Get Started →
            </button>
          </div>
        ) : (
          <div className="space-y-12 animate-in fade-in duration-500">
            {children.length > 0 && (
              <div className="space-y-4 text-center">
                <p className="text-[9px] font-black text-[#8B9D83] uppercase tracking-[0.3em]">Your Bloom List</p>
                <div className="flex flex-wrap justify-center gap-2">
                  {children.map(c => (
                    <div key={c.id} className="bg-[#D9E4DD] text-[#8B9D83] px-6 py-2 rounded-full text-sm font-bold border border-[#8B9D83]/10">
                      {c.name} ({c.age})
                    </div>
                  ))}
                </div>
              </div>
            )}

            <section className="space-y-10">
              <h3 className="text-4xl font-bold text-[#4A4A4A] font-display text-center">
                {children.length === 0 ? "About your child" : "Add another child"}
              </h3>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-3">
                  <label className="text-[10px] font-black uppercase tracking-[0.2em] text-[#8B9D83] px-4">Name</label>
                  <input
                    type="text"
                    placeholder="Child's Name"
                    className="w-full p-5 bg-[#FDFBF7] border-2 border-[#8B9D83]/10 rounded-[2rem] outline-none font-bold text-[#4A4A4A] focus:ring-4 focus:ring-[#8B9D83]/5 transition-all"
                    value={tempChild.name}
                    onChange={(e) => setTempChild({...tempChild, name: e.target.value})}
                  />
                </div>
                <div className="space-y-3">
                  <label className="text-[10px] font-black uppercase tracking-[0.2em] text-[#8B9D83] px-4">Age</label>
                  <input
                    type="number"
                    placeholder="Age"
                    className="w-full p-5 bg-[#FDFBF7] border-2 border-[#8B9D83]/10 rounded-[2rem] outline-none font-bold text-[#4A4A4A] focus:ring-4 focus:ring-[#8B9D83]/5 transition-all"
                    value={tempChild.age}
                    onChange={(e) => setTempChild({...tempChild, age: parseInt(e.target.value) || 0})}
                  />
                </div>
              </div>

              {tempChild.name && (
                <div className="space-y-12 pt-6 animate-in fade-in duration-500">
                  <div className="space-y-6">
                    <p className="text-[10px] font-black text-[#8B9D83] uppercase tracking-[0.3em] text-center">Typical Challenges (Age {tempChild.age})</p>
                    <div className="flex flex-wrap justify-center gap-3">
                      {currentChallenges.map(c => (
                        <button
                          key={c}
                          onClick={() => toggleItem(c, 'challenges')}
                          className={`px-6 py-3 rounded-full text-xs font-bold border-2 transition-all ${
                            tempChild.challenges?.includes(c) 
                            ? 'bg-[#8B9D83] border-[#8B9D83] text-white shadow-lg shadow-[#8B9D83]/10' 
                            : 'bg-white border-gray-100 text-gray-400 hover:border-[#8B9D83]/30'
                          }`}
                        >
                          {c}
                        </button>
                      ))}
                    </div>
                  </div>

                  <div className="space-y-6">
                    <p className="text-[10px] font-black text-[#E89F71] uppercase tracking-[0.3em] text-center">Interests & Hobbies</p>
                    <div className="flex flex-wrap justify-center gap-3">
                      {currentInterests.map(i => (
                        <button
                          key={i}
                          onClick={() => toggleItem(i, 'interests')}
                          className={`px-6 py-3 rounded-full text-xs font-bold border-2 transition-all ${
                            tempChild.interests?.includes(i) 
                            ? 'bg-[#E89F71] border-[#E89F71] text-white shadow-lg shadow-[#E89F71]/10' 
                            : 'bg-white border-gray-100 text-gray-400 hover:border-[#E89F71]/30'
                          }`}
                        >
                          {i}
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
              )}
            </section>

            <div className="flex flex-col sm:flex-row gap-6 pt-8">
              <button
                onClick={handleAddChild}
                disabled={!tempChild.name}
                className="flex-1 bg-white text-[#8B9D83] border-2 border-[#8B9D83] p-6 rounded-[2.5rem] font-bold text-xl hover:bg-[#D9E4DD]/20 transition-all disabled:opacity-30 font-display"
              >
                + Add Child
              </button>
              <button
                onClick={handleFinish}
                disabled={children.length === 0 && !tempChild.name}
                className="flex-1 bg-[#8B9D83] text-white p-6 rounded-[2.5rem] font-bold text-xl hover:opacity-90 transition-all shadow-xl shadow-[#8B9D83]/20 disabled:opacity-50 font-display"
              >
                Let's Bloom
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Onboarding;

import React, { useState } from 'react';
import { UserProfile, Child, DailyTip, FavoriteItem } from '../types';
import { getChallengeAdvice } from '../services/gemini';
import Modal from './Modal';
import { trackEvent } from '../services/analytics';

interface Props {
  profile: UserProfile;
  onUpdateProfile: (profile: UserProfile) => void;
  onBack: () => void;
}

const AdviceActivities: React.FC<Props> = ({ profile, onUpdateProfile, onBack }) => {
  const [selectedChild, setSelectedChild] = useState<Child>(profile.children[0]);
  const [selectedChallenge, setSelectedChallenge] = useState<string>('');
  const [advice, setAdvice] = useState<DailyTip | null>(null);
  const [loading, setLoading] = useState(false);
  const [showMainModal, setShowMainModal] = useState(false);
  const [feedbackGiven, setFeedbackGiven] = useState<string | null>(null);
  const [savedItems, setSavedItems] = useState<Set<string>>(new Set());

  const handleChallengeClick = async (challenge: string) => {
    setSelectedChallenge(challenge);
    setLoading(true);
    setFeedbackGiven(null);
    setSavedItems(new Set());
    trackEvent('advice_request', { challenge, childAge: selectedChild.age });
    try {
      const res = await getChallengeAdvice(selectedChild, challenge);
      setAdvice(res);
      setShowMainModal(true);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const saveToFavorites = (type: 'advice' | 'script' | 'activity', content: string) => {
    const key = `${type}-${content.substring(0, 10)}`;
    if (savedItems.has(key)) return;

    const newItem: FavoriteItem = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      title: `${selectedChallenge} (${type})`,
      content,
      childContext: `${selectedChild.name} (Age ${selectedChild.age})`,
      dateSaved: new Date().toISOString()
    };

    onUpdateProfile({ ...profile, favorites: [...profile.favorites, newItem] });
    setSavedItems(prev => new Set(prev).add(key));
    trackEvent('favorite_saved', { type });
  };

  const handleFeedback = (val: string) => {
    setFeedbackGiven(val);
    trackEvent('advice_feedback', { challenge: selectedChallenge, feedback: val });
  };

  const isSaved = (type: string, content: string) => {
    const key = `${type}-${content.substring(0, 10)}`;
    return savedItems.has(key);
  };

  return (
    <div className="space-y-12 max-w-4xl mx-auto py-6">
      <button onClick={onBack} className="text-[#8B9D83] font-bold flex items-center gap-3 hover:translate-x-[-4px] transition-transform font-display text-lg">
        <span className="text-2xl">←</span> Back Home
      </button>

      <div className="text-center space-y-10 animate-in fade-in duration-500">
        <div className="space-y-4">
          <h2 className="text-5xl md:text-6xl font-bold text-[#4A4A4A] font-display">Playful Advice</h2>
          <p className="text-[#4A4A4A]/50 font-medium text-lg">Choose a child and challenge for gentle, tailored guidance.</p>
        </div>

        <div className="space-y-16 bg-white p-10 md:p-16 rounded-[4rem] card-shadow border border-[#8B9D83]/10">
          <div className="space-y-8">
            <label className="text-[10px] font-black uppercase tracking-[0.4em] text-[#8B9D83]">Who are we helping?</label>
            <div className="flex justify-center gap-3 flex-wrap">
              {profile.children.map(c => (
                <button
                  key={c.id}
                  onClick={() => setSelectedChild(c)}
                  className={`px-10 py-4 rounded-full text-sm font-bold transition-all border-2 ${
                    selectedChild.id === c.id 
                    ? 'bg-[#8B9D83] border-[#8B9D83] text-white shadow-xl shadow-[#8B9D83]/20' 
                    : 'bg-[#FDFBF7] border-[#8B9D83]/10 text-[#8B9D83]/60 hover:border-[#8B9D83]/40'
                  }`}
                >
                  {c.name}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-8">
            <label className="text-[10px] font-black uppercase tracking-[0.4em] text-[#8B9D83]">Today's Topic</label>
            <div className="flex justify-center gap-4 flex-wrap">
              {selectedChild.challenges.map(c => (
                <button
                  key={c}
                  disabled={loading}
                  onClick={() => handleChallengeClick(c)}
                  className="px-8 py-4 rounded-full text-sm font-bold bg-[#D9E4DD] border border-[#8B9D83]/10 text-[#8B9D83] hover:bg-[#8B9D83] hover:text-white transition-all transform hover:-translate-y-1 shadow-sm"
                >
                  {c}
                </button>
              ))}
            </div>
          </div>
          {loading && (
            <div className="py-8 flex flex-col items-center gap-4">
              <div className="w-10 h-10 border-4 border-[#8B9D83]/20 border-t-[#8B9D83] rounded-full animate-spin"></div>
              <p className="text-[#8B9D83] font-black text-xs tracking-widest uppercase animate-pulse">Consulting the Expert AI...</p>
            </div>
          )}
        </div>
      </div>

      <Modal isOpen={showMainModal} onClose={() => setShowMainModal(false)} title={selectedChallenge}>
        <div className="space-y-10">
          <div className="flex items-start gap-4 p-6 bg-[#D9E4DD]/30 rounded-[2.5rem] border border-[#8B9D83]/10 text-sm font-medium text-[#8B9D83]">
            <span className="text-3xl">🌱</span>
            <div className="space-y-1 pt-1">
              <p className="font-bold">Developmental Context (Ages {selectedChild.age - 1}-{selectedChild.age + 1})</p>
              <p className="text-[10px] opacity-70 uppercase font-black tracking-widest">Tailored to interests: {selectedChild.interests.join(', ')}</p>
            </div>
          </div>

          <div className="space-y-5">
            <div className="flex justify-between items-center">
              <h4 className="font-black text-[#8B9D83] uppercase text-[11px] tracking-[0.3em]">Strategy</h4>
              <button 
                onClick={() => saveToFavorites('advice', advice?.content || '')}
                className={`text-[10px] font-black border-2 px-4 py-2 rounded-full transition-all uppercase tracking-widest ${
                  isSaved('advice', advice?.content || '') 
                  ? 'bg-[#8B9D83] text-white border-[#8B9D83]' 
                  : 'text-[#8B9D83] border-[#8B9D83]/20 hover:bg-[#8B9D83]/5'
                }`}
              >
                {isSaved('advice', advice?.content || '') ? 'Saved ⭐' : 'Save'}
              </button>
            </div>
            <p className="text-2xl text-[#4A4A4A] leading-relaxed font-display">{advice?.content}</p>
          </div>

          <div className="space-y-6 bg-[#FFEDE3] p-10 rounded-[3.5rem] border border-[#E89F71]/10">
            <div className="flex justify-between items-center">
              <h5 className="font-black text-[#E89F71] text-[11px] uppercase tracking-[0.3em]">Try this Script</h5>
              <button 
                onClick={() => saveToFavorites('script', advice?.script || '')}
                className={`text-[10px] font-black border-2 px-4 py-2 rounded-full transition-all uppercase tracking-widest ${
                  isSaved('script', advice?.script || '') 
                  ? 'bg-[#E89F71] text-white border-[#E89F71]' 
                  : 'text-[#E89F71] border-[#E89F71]/20 hover:bg-[#E89F71]/5'
                }`}
              >
                {isSaved('script', advice?.script || '') ? 'Saved ⭐' : 'Save'}
              </button>
            </div>
            <p className="italic text-[#4A4A4A] text-3xl font-display leading-tight">"{advice?.script}"</p>
          </div>

          <div className="space-y-6 bg-white p-10 rounded-[3.5rem] border border-gray-100 shadow-xl shadow-[#8B9D83]/5">
            <div className="flex justify-between items-center">
              <h5 className="font-black text-[#8B9D83] text-[11px] uppercase tracking-[0.3em]">Play Activity</h5>
              <button 
                onClick={() => saveToFavorites('activity', advice?.activity || '')}
                className={`text-[10px] font-black border-2 px-4 py-2 rounded-full transition-all uppercase tracking-widest ${
                  isSaved('activity', advice?.activity || '') 
                  ? 'bg-[#8B9D83] text-white border-[#8B9D83]' 
                  : 'text-[#8B9D83] border-[#8B9D83]/20 hover:bg-[#8B9D83]/5'
                }`}
              >
                {isSaved('activity', advice?.activity || '') ? 'Saved ⭐' : 'Save'}
              </button>
            </div>
            <p className="text-[#4A4A4A]/70 font-medium leading-relaxed text-lg">{advice?.activity}</p>
          </div>

          <div className="pt-10 border-t border-gray-100 text-center space-y-6">
            <p className="text-[10px] font-black text-[#4A4A4A]/30 uppercase tracking-[0.4em]">Helpful?</p>
            {feedbackGiven ? (
              <p className="text-[#8B9D83] font-bold text-xl animate-in zoom-in duration-300">Wonderful! 🌻</p>
            ) : (
              <div className="flex justify-center gap-4">
                {['Yes', 'Kind of', 'No'].map(val => (
                  <button
                    key={val}
                    onClick={() => handleFeedback(val)}
                    className="px-10 py-4 rounded-full bg-[#FDFBF7] border-2 border-gray-100 text-sm font-bold text-[#8B9D83] hover:bg-[#8B9D83] hover:text-white transition-all active:scale-95"
                  >
                    {val}
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>
      </Modal>
    </div>
  );
};

export default AdviceActivities;

import React, { useState, useEffect, useRef } from 'react';
import { UserProfile, ChatMessage, FavoriteItem } from '../types';
import { getAiChatResponse } from '../services/gemini';
import { trackEvent } from '../services/analytics';

interface Props {
  profile: UserProfile;
  onUpdateProfile: (profile: UserProfile) => void;
  onBack: () => void;
}

const CoachAIView: React.FC<Props> = ({ profile, onUpdateProfile, onBack }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [profile.chatHistory]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg: ChatMessage = { 
      role: 'user', 
      content: input, 
      timestamp: new Date().toISOString() 
    };

    const updatedHistory = [...profile.chatHistory, userMsg];
    onUpdateProfile({ ...profile, chatHistory: updatedHistory });
    setInput('');
    setLoading(true);
    trackEvent('coach_query', { length: input.length });

    try {
      const resText = await getAiChatResponse(updatedHistory.map(m => ({ role: m.role, content: m.content })), input, profile.children);
      const aiMsg: ChatMessage = { 
        role: 'assistant', 
        content: resText, 
        timestamp: new Date().toISOString() 
      };
      onUpdateProfile({ ...profile, chatHistory: [...updatedHistory, aiMsg] });
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const saveToFavorites = (content: string) => {
    const newItem: FavoriteItem = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'advice',
      title: "Coach AI Insight",
      content,
      dateSaved: new Date().toISOString()
    };
    onUpdateProfile({ ...profile, favorites: [...profile.favorites, newItem] });
    trackEvent('favorite_saved', { type: 'coach_advice' });
  };

  return (
    <div className="max-w-4xl mx-auto py-4 flex flex-col h-[85vh]">
      <div className="flex justify-between items-center mb-8 px-6">
        <button onClick={onBack} className="text-[#E89F71] font-bold flex items-center gap-3 font-display text-lg">
          <span className="text-2xl">←</span> Back
        </button>
        <div className="text-right">
          <h2 className="text-4xl font-bold text-[#4A4A4A] font-display">Coach AI</h2>
          <p className="text-[10px] text-[#E89F71] font-black uppercase tracking-[0.3em]">Compassionate Listening</p>
        </div>
      </div>

      <div className="flex-1 bg-white rounded-[4rem] card-shadow border border-gray-100 overflow-hidden flex flex-col">
        <div className="flex-1 overflow-y-auto p-10 md:p-14 space-y-10 scrollbar-hide">
          {profile.chatHistory.length === 0 && (
            <div className="h-full flex flex-col items-center justify-center text-center p-10 space-y-8">
               <div className="w-28 h-28 bg-[#FFEDE3] rounded-[2.5rem] flex items-center justify-center text-6xl animate-float">🤖</div>
               <div className="space-y-3">
                 <p className="font-display text-3xl text-[#4A4A4A] font-bold">"What's on your heart?"</p>
                 <p className="text-[#4A4A4A]/40 font-bold uppercase tracking-[0.2em] text-[11px]">Ask me anything, anytime.</p>
               </div>
            </div>
          )}
          {profile.chatHistory.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-3 duration-300`}>
              <div className={`max-w-[85%] md:max-w-[75%] space-y-3`}>
                <div className={`p-8 md:p-10 rounded-[3rem] shadow-sm font-medium leading-relaxed text-lg ${
                  msg.role === 'user' 
                  ? 'bg-[#E89F71] text-white rounded-tr-none shadow-xl shadow-[#E89F71]/10' 
                  : 'bg-[#FDFBF7] text-[#4A4A4A] rounded-tl-none border border-gray-100'
                }`}>
                  <p className="whitespace-pre-wrap">{msg.content}</p>
                </div>
                {msg.role === 'assistant' && (
                  <button 
                    onClick={() => saveToFavorites(msg.content)} 
                    className="text-[9px] font-black text-[#8B9D83] uppercase tracking-[0.3em] hover:text-[#4A4A4A] ml-6 transition-colors"
                  >
                    Save to Bloom List ⭐
                  </button>
                )}
              </div>
            </div>
          ))}
          {loading && (
            <div className="flex justify-start">
              <div className="bg-[#D9E4DD] px-8 py-5 rounded-full border border-[#8B9D83]/10 flex gap-2.5 items-center shadow-sm">
                <div className="w-2 h-2 bg-[#8B9D83] rounded-full animate-bounce"></div>
                <div className="w-2 h-2 bg-[#8B9D83] rounded-full animate-bounce [animation-delay:0.2s]"></div>
                <div className="w-2 h-2 bg-[#8B9D83] rounded-full animate-bounce [animation-delay:0.4s]"></div>
              </div>
            </div>
          )}
          <div ref={scrollRef} />
        </div>

        <div className="p-8 md:p-10 bg-[#FDFBF7] border-t border-gray-100">
          <div className="flex gap-4 max-w-4xl mx-auto">
            <input
              type="text"
              className="flex-1 p-6 bg-white border border-gray-100 rounded-[2.5rem] outline-none focus:ring-8 focus:ring-[#E89F71]/5 text-lg font-medium shadow-inner transition-all"
              placeholder="How can I help with bedtime?"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            />
            <button
              onClick={handleSend}
              disabled={loading || !input.trim()}
              className="bg-[#E89F71] text-white w-20 h-20 rounded-[2rem] flex items-center justify-center font-bold hover:scale-105 active:scale-95 disabled:opacity-50 transition-all shadow-xl shadow-[#E89F71]/20"
            >
              <span className="text-4xl">→</span>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CoachAIView;

