import React, { useState } from 'react';
import { UserProfile, Child, DailyTip, FavoriteItem } from '../types';
import { getChallengeAdvice } from '../services/gemini';
import Modal from './Modal';
import { trackEvent } from '../services/analytics';

interface Props {
  profile: UserProfile;
  onUpdateProfile: (profile: UserProfile) => void;
  onBack: () => void;
}

const AdviceActivities: React.FC<Props> = ({ profile, onUpdateProfile, onBack }) => {
  const [selectedChild, setSelectedChild] = useState<Child>(profile.children[0]);
  const [selectedChallenge, setSelectedChallenge] = useState<string>('');
  const [advice, setAdvice] = useState<DailyTip | null>(null);
  const [loading, setLoading] = useState(false);
  const [showMainModal, setShowMainModal] = useState(false);
  const [feedbackGiven, setFeedbackGiven] = useState<string | null>(null);
  const [savedItems, setSavedItems] = useState<Set<string>>(new Set());

  const handleChallengeClick = async (challenge: string) => {
    setSelectedChallenge(challenge);
    setLoading(true);
    setFeedbackGiven(null);
    setSavedItems(new Set());
    trackEvent('advice_request', { challenge, childAge: selectedChild.age });
    try {
      const res = await getChallengeAdvice(selectedChild, challenge);
      setAdvice(res);
      setShowMainModal(true);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const saveToFavorites = (type: 'advice' | 'script' | 'activity', content: string) => {
    const key = `${type}-${content.substring(0, 10)}`;
    if (savedItems.has(key)) return;

    const newItem: FavoriteItem = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      title: `${selectedChallenge} (${type})`,
      content,
      childContext: `${selectedChild.name} (Age ${selectedChild.age})`,
      dateSaved: new Date().toISOString()
    };

    onUpdateProfile({ ...profile, favorites: [...profile.favorites, newItem] });
    setSavedItems(prev => new Set(prev).add(key));
    trackEvent('favorite_saved', { type });
  };

  const handleFeedback = (val: string) => {
    setFeedbackGiven(val);
    trackEvent('advice_feedback', { challenge: selectedChallenge, feedback: val });
  };

  const isSaved = (type: string, content: string) => {
    const key = `${type}-${content.substring(0, 10)}`;
    return savedItems.has(key);
  };

  return (
    <div className="space-y-16 max-w-4xl mx-auto py-6">
      <button onClick={onBack} className="text-[#7D9D85] font-black flex items-center gap-4 hover:translate-x-[-6px] transition-transform font-display text-xl uppercase tracking-widest">
        <span className="text-3xl">←</span> Back Home
      </button>

      <div className="text-center space-y-12 animate-in fade-in duration-500">
        <div className="space-y-4">
          <h2 className="text-5xl md:text-7xl font-bold text-[#3A3A3A] font-display">Playful Advice</h2>
          <p className="text-[#3A3A3A]/50 font-medium text-xl">Expert guidance tailored to your child’s development.</p>
        </div>

        <div className="space-y-20 bg-white p-12 md:p-20 rounded-[4.5rem] card-shadow border border-[#7D9D85]/10">
          <div className="space-y-10">
            <label className="text-[12px] font-black uppercase tracking-[0.5em] text-[#7D9D85]">1. Who are we blooming?</label>
            <div className="flex justify-center gap-4 flex-wrap">
              {profile.children.map(c => (
                <button
                  key={c.id}
                  onClick={() => setSelectedChild(c)}
                  className={`px-12 py-5 rounded-full text-sm font-bold transition-all border-2 ${
                    selectedChild.id === c.id 
                    ? 'bg-[#7D9D85] border-[#7D9D85] text-white shadow-2xl shadow-[#7D9D85]/30' 
                    : 'bg-[#FDFBF7] border-[#7D9D85]/10 text-[#7D9D85]/60 hover:border-[#7D9D85]/40'
                  }`}
                >
                  {c.name}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-10">
            <label className="text-[12px] font-black uppercase tracking-[0.5em] text-[#7D9D85]">2. Today's Milestone</label>
            <div className="flex justify-center gap-5 flex-wrap">
              {selectedChild.challenges.map(c => (
                <button
                  key={c}
                  disabled={loading}
                  onClick={() => handleChallengeClick(c)}
                  className="px-10 py-5 rounded-full text-sm font-bold bg-[#F1F5E9] border-2 border-[#7D9D85]/10 text-[#7D9D85] hover:bg-[#7D9D85] hover:text-white transition-all transform hover:-translate-y-2 shadow-sm"
                >
                  {c}
                </button>
              ))}
            </div>
          </div>
          {loading && (
            <div className="py-10 flex flex-col items-center gap-6">
              <div className="w-12 h-12 border-4 border-[#7D9D85]/20 border-t-[#7D9D85] rounded-full animate-spin"></div>
              <p className="text-[#7D9D85] font-black text-xs tracking-[0.4em] uppercase animate-pulse">Consulting Specialist AI...</p>
            </div>
          )}
        </div>
      </div>

      <Modal isOpen={showMainModal} onClose={() => setShowMainModal(false)} title={selectedChallenge}>
        <div className="space-y-12">
          <div className="flex items-start gap-6 p-8 bg-[#F1F5E9] rounded-[3rem] border-2 border-[#7D9D85]/10 text-sm font-medium text-[#7D9D85]">
            <span className="text-4xl">🌱</span>
            <div className="space-y-2 pt-1">
              <p className="font-bold text-lg">Developmental Insight (Age {selectedChild.age})</p>
              <p className="text-[11px] opacity-70 uppercase font-black tracking-[0.2em]">Context: {selectedChild.interests.join(', ')}</p>
            </div>
          </div>

          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h4 className="font-black text-[#7D9D85] uppercase text-[12px] tracking-[0.4em]">Expert Strategy</h4>
              <button 
                onClick={() => saveToFavorites('advice', advice?.content || '')}
                className={`text-[11px] font-black border-2 px-5 py-2.5 rounded-full transition-all uppercase tracking-[0.2em] ${
                  isSaved('advice', advice?.content || '') 
                  ? 'bg-[#7D9D85] text-white border-[#7D9D85] shadow-lg shadow-[#7D9D85]/20' 
                  : 'text-[#7D9D85] border-[#7D9D85]/20 hover:bg-[#7D9D85]/5'
                }`}
              >
                {isSaved('advice', advice?.content || '') ? 'Saved ⭐' : 'Save To Favorites'}
              </button>
            </div>
            <p className="text-2xl text-[#3A3A3A] leading-relaxed font-display font-medium">{advice?.content}</p>
          </div>

          <div className="space-y-8 bg-[#FFEDE3] p-12 rounded-[4rem] border-2 border-[#E89F71]/10 shadow-lg shadow-[#E89F71]/5">
            <div className="flex justify-between items-center">
              <h5 className="font-black text-[#E89F71] text-[12px] uppercase tracking-[0.4em]">The Script</h5>
              <button 
                onClick={() => saveToFavorites('script', advice?.script || '')}
                className={`text-[11px] font-black border-2 px-5 py-2.5 rounded-full transition-all uppercase tracking-[0.2em] ${
                  isSaved('script', advice?.script || '') 
                  ? 'bg-[#E89F71] text-white border-[#E89F71] shadow-lg shadow-[#E89F71]/20' 
                  : 'text-[#E89F71] border-[#E89F71]/20 hover:bg-[#E89F71]/5'
                }`}
              >
                {isSaved('script', advice?.script || '') ? 'Saved ⭐' : 'Save To Favorites'}
              </button>
            </div>
            <p className="italic text-[#3A3A3A] text-4xl font-display leading-tight">"{advice?.script}"</p>
          </div>

          <div className="space-y-8 bg-white p-12 rounded-[4rem] border-2 border-gray-100 shadow-2xl shadow-[#7D9D85]/10">
            <div className="flex justify-between items-center">
              <h5 className="font-black text-[#7D9D85] text-[12px] uppercase tracking-[0.4em]">Bloom Activity</h5>
              <button 
                onClick={() => saveToFavorites('activity', advice?.activity || '')}
                className={`text-[11px] font-black border-2 px-5 py-2.5 rounded-full transition-all uppercase tracking-[0.2em] ${
                  isSaved('activity', advice?.activity || '') 
                  ? 'bg-[#7D9D85] text-white border-[#7D9D85] shadow-lg shadow-[#7D9D85]/20' 
                  : 'text-[#7D9D85] border-[#7D9D85]/20 hover:bg-[#7D9D85]/5'
                }`}
              >
                {isSaved('activity', advice?.activity || '') ? 'Saved ⭐' : 'Save To Favorites'}
              </button>
            </div>
            <p className="text-[#3A3A3A]/70 font-medium leading-relaxed text-xl">{advice?.activity}</p>
          </div>

          <div className="pt-12 border-t border-gray-100 text-center space-y-8">
            <p className="text-[12px] font-black text-[#3A3A3A]/30 uppercase tracking-[0.5em]">Did this help?</p>
            {feedbackGiven ? (
              <p className="text-[#7D9D85] font-black text-2xl animate-in zoom-in duration-500 uppercase tracking-widest">Thank you! 🌻</p>
            ) : (
              <div className="flex justify-center gap-5">
                {['Yes', 'Kind of', 'No'].map(val => (
                  <button
                    key={val}
                    onClick={() => handleFeedback(val)}
                    className="px-12 py-5 rounded-full bg-[#FDFBF7] border-2 border-gray-100 text-sm font-bold text-[#7D9D85] hover:bg-[#7D9D85] hover:text-white transition-all active:scale-95 shadow-md"
                  >
                    {val}
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>
      </Modal>
    </div>
  );
};

export default AdviceActivities;

import React, { useState, useEffect, useRef } from 'react';
import { UserProfile, ChatMessage, FavoriteItem } from '../types';
import { getAiChatResponse } from '../services/gemini';
import { trackEvent } from '../services/analytics';

interface Props {
  profile: UserProfile;
  onUpdateProfile: (profile: UserProfile) => void;
  onBack: () => void;
}

const CoachAIView: React.FC<Props> = ({ profile, onUpdateProfile, onBack }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [profile.chatHistory]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg: ChatMessage = { 
      role: 'user', 
      content: input, 
      timestamp: new Date().toISOString() 
    };

    const updatedHistory = [...profile.chatHistory, userMsg];
    onUpdateProfile({ ...profile, chatHistory: updatedHistory });
    setInput('');
    setLoading(true);
    trackEvent('coach_query', { length: input.length });

    try {
      const resText = await getAiChatResponse(updatedHistory.map(m => ({ role: m.role, content: m.content })), input, profile.children);
      const aiMsg: ChatMessage = { 
        role: 'assistant', 
        content: resText, 
        timestamp: new Date().toISOString() 
      };
      onUpdateProfile({ ...profile, chatHistory: [...updatedHistory, aiMsg] });
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const saveToFavorites = (content: string) => {
    const newItem: FavoriteItem = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'advice',
      title: "Coach AI Insight",
      content,
      dateSaved: new Date().toISOString()
    };
    onUpdateProfile({ ...profile, favorites: [...profile.favorites, newItem] });
    trackEvent('favorite_saved', { type: 'coach_advice' });
  };

  return (
    <div className="max-w-5xl mx-auto py-6 flex flex-col h-[85vh]">
      <div className="flex justify-between items-center mb-10 px-6">
        <button onClick={onBack} className="text-[#E89F71] font-black flex items-center gap-4 font-display text-xl uppercase tracking-widest">
          <span className="text-3xl">←</span> Back Home
        </button>
        <div className="text-right">
          <h2 className="text-4xl font-bold text-[#3A3A3A] font-display">Coach AI</h2>
          <p className="text-[12px] text-[#E89F71] font-black uppercase tracking-[0.4em]">Your Compassionate Partner</p>
        </div>
      </div>

      <div className="flex-1 bg-white rounded-[4.5rem] card-shadow border border-gray-100 overflow-hidden flex flex-col">
        <div className="flex-1 overflow-y-auto p-12 md:p-16 space-y-12 scrollbar-hide">
          {profile.chatHistory.length === 0 && (
            <div className="h-full flex flex-col items-center justify-center text-center p-12 space-y-10">
               <div className="w-32 h-32 bg-[#FFEDE3] rounded-[3rem] flex items-center justify-center text-7xl animate-float shadow-xl shadow-[#E89F71]/10">🤖</div>
               <div className="space-y-4">
                 <p className="font-display text-4xl text-[#3A3A3A] font-bold leading-tight">"How's the journey going today?"</p>
                 <p className="text-[#3A3A3A]/40 font-black uppercase tracking-[0.3em] text-[12px]">I'm here to listen, analyze, and guide.</p>
               </div>
            </div>
          )}
          {profile.chatHistory.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-4 duration-500`}>
              <div className={`max-w-[85%] md:max-w-[75%] space-y-4`}>
                <div className={`p-10 md:p-12 rounded-[3.5rem] shadow-sm font-medium leading-relaxed text-xl ${
                  msg.role === 'user' 
                  ? 'bg-[#E89F71] text-white rounded-tr-none shadow-2xl shadow-[#E89F71]/20' 
                  : 'bg-[#FDFBF7] text-[#3A3A3A] rounded-tl-none border-2 border-[#7D9D85]/10 shadow-lg shadow-[#7D9D85]/5'
                }`}>
                  <p className="whitespace-pre-wrap">{msg.content}</p>
                </div>
                {msg.role === 'assistant' && (
                  <button 
                    onClick={() => saveToFavorites(msg.content)} 
                    className="text-[10px] font-black text-[#7D9D85] uppercase tracking-[0.4em] hover:text-[#3A3A3A] ml-8 transition-colors flex items-center gap-2"
                  >
                    <span>⭐</span> Save to Bloom List
                  </button>
                )}
              </div>
            </div>
          ))}
          {loading && (
            <div className="flex justify-start">
              <div className="bg-[#F1F5E9] px-10 py-6 rounded-full border-2 border-[#7D9D85]/10 flex gap-3 items-center shadow-lg shadow-[#7D9D85]/5">
                <div className="w-2.5 h-2.5 bg-[#7D9D85] rounded-full animate-bounce"></div>
                <div className="w-2.5 h-2.5 bg-[#7D9D85] rounded-full animate-bounce [animation-delay:0.2s]"></div>
                <div className="w-2.5 h-2.5 bg-[#7D9D85] rounded-full animate-bounce [animation-delay:0.4s]"></div>
              </div>
            </div>
          )}
          <div ref={scrollRef} />
        </div>

        <div className="p-10 md:p-12 bg-[#FDFBF7] border-t border-gray-100">
          <div className="flex gap-6 max-w-5xl mx-auto">
            <input
              type="text"
              className="flex-1 p-7 bg-white border-2 border-gray-100 rounded-[3rem] outline-none focus:ring-12 focus:ring-[#E89F71]/5 text-xl font-medium shadow-inner transition-all placeholder-[#3A3A3A]/20"
              placeholder="Ask me anything about parenting..."
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            />
            <button
              onClick={handleSend}
              disabled={loading || !input.trim()}
              className="bg-[#E89F71] text-white w-24 h-24 rounded-[2.5rem] flex items-center justify-center font-bold hover:scale-110 active:scale-95 disabled:opacity-50 transition-all shadow-2xl shadow-[#E89F71]/30"
            >
              <span className="text-5xl">→</span>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CoachAIView;

