import React, { useState, useEffect, useRef } from 'react';
import { UserProfile, ChatMessage, FavoriteItem } from '../types';
import { getAiChatResponse } from '../services/gemini';
import { trackEvent } from '../services/analytics';

interface Props {
  profile: UserProfile;
  onUpdateProfile: (profile: UserProfile) => void;
  onBack: () => void;
}

const CoachAIView: React.FC<Props> = ({ profile, onUpdateProfile, onBack }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [profile.chatHistory]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg: ChatMessage = { 
      role: 'user', 
      content: input, 
      timestamp: new Date().toISOString() 
    };

    const updatedHistory = [...profile.chatHistory, userMsg];
    onUpdateProfile({ ...profile, chatHistory: updatedHistory });
    setInput('');
    setLoading(true);
    trackEvent('coach_query', { length: input.length });

    try {
      const resText = await getAiChatResponse(updatedHistory.map(m => ({ role: m.role, content: m.content })), input, profile.children);
      const aiMsg: ChatMessage = { 
        role: 'assistant', 
        content: resText, 
        timestamp: new Date().toISOString() 
      };
      onUpdateProfile({ ...profile, chatHistory: [...updatedHistory, aiMsg] });
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const saveToFavorites = (content: string) => {
    const newItem: FavoriteItem = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'advice',
      title: "Coach AI Insight",
      content,
      dateSaved: new Date().toISOString()
    };
    onUpdateProfile({ ...profile, favorites: [...profile.favorites, newItem] });
    trackEvent('favorite_saved', { type: 'coach_advice' });
  };

  return (
    <div className="max-w-5xl mx-auto py-6 flex flex-col h-[85vh]">
      <div className="flex justify-between items-center mb-10 px-6">
        <button onClick={onBack} className="text-[#F7A072] font-black flex items-center gap-4 font-display text-xl uppercase tracking-widest">
          <span className="text-3xl">←</span> Back Home
        </button>
        <div className="text-right">
          <h2 className="text-4xl font-bold text-[#3A3A3A] font-display">Coach AI</h2>
          <p className="text-[12px] text-[#F7A072] font-black uppercase tracking-[0.4em]">Your Compassionate Partner</p>
        </div>
      </div>

      <div className="flex-1 bg-white rounded-[4.5rem] card-shadow border border-gray-100 overflow-hidden flex flex-col">
        <div className="flex-1 overflow-y-auto p-12 md:p-16 space-y-12 scrollbar-hide">
          {profile.chatHistory.length === 0 && (
            <div className="h-full flex flex-col items-center justify-center text-center p-12 space-y-10">
               <div className="w-32 h-32 bg-[#FFEDE3] rounded-[3rem] flex items-center justify-center text-7xl animate-float shadow-xl shadow-[#F7A072]/10">🤖</div>
               <div className="space-y-4">
                 <p className="font-display text-4xl text-[#3A3A3A] font-bold leading-tight">"How's the journey going today?"</p>
                 <p className="text-[#3A3A3A]/40 font-black uppercase tracking-[0.3em] text-[12px]">I'm here to listen, analyze, and guide.</p>
               </div>
            </div>
          )}
          {profile.chatHistory.map((msg, i) => (
            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-4 duration-500`}>
              <div className={`max-w-[85%] md:max-w-[75%] space-y-4`}>
                <div className={`p-10 md:p-12 rounded-[3.5rem] shadow-sm font-medium leading-relaxed text-xl ${
                  msg.role === 'user' 
                  ? 'bg-[#F7A072] text-white rounded-tr-none shadow-2xl shadow-[#F7A072]/20' 
                  : 'bg-[#FDFBF7] text-[#3A3A3A] rounded-tl-none border-2 border-[#4E8B83]/10 shadow-lg shadow-[#4E8B83]/5'
                }`}>
                  <p className="whitespace-pre-wrap">{msg.content}</p>
                </div>
                {msg.role === 'assistant' && (
                  <button 
                    onClick={() => saveToFavorites(msg.content)} 
                    className="text-[10px] font-black text-[#4E8B83] uppercase tracking-[0.4em] hover:text-[#3A3A3A] ml-8 transition-colors flex items-center gap-2"
                  >
                    <span>⭐</span> Save to Bloom List
                  </button>
                )}
              </div>
            </div>
          ))}
          {loading && (
            <div className="flex justify-start">
              <div className="bg-[#E8F1F0] px-10 py-6 rounded-full border-2 border-[#4E8B83]/10 flex gap-3 items-center shadow-lg shadow-[#4E8B83]/5">
                <div className="w-2.5 h-2.5 bg-[#4E8B83] rounded-full animate-bounce"></div>
                <div className="w-2.5 h-2.5 bg-[#4E8B83] rounded-full animate-bounce [animation-delay:0.2s]"></div>
                <div className="w-2.5 h-2.5 bg-[#4E8B83] rounded-full animate-bounce [animation-delay:0.4s]"></div>
              </div>
            </div>
          )}
          <div ref={scrollRef} />
        </div>

        <div className="p-10 md:p-12 bg-[#FDFBF7] border-t border-gray-100">
          <div className="flex gap-6 max-w-5xl mx-auto">
            <input
              type="text"
              className="flex-1 p-7 bg-white border-2 border-gray-100 rounded-[3rem] outline-none focus:ring-12 focus:ring-[#F7A072]/5 text-xl font-medium shadow-inner transition-all placeholder-[#3A3A3A]/20"
              placeholder="Ask me anything about parenting..."
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            />
            <button
              onClick={handleSend}
              disabled={loading || !input.trim()}
              className="bg-[#F7A072] text-white w-24 h-24 rounded-[2.5rem] flex items-center justify-center font-bold hover:scale-110 active:scale-95 disabled:opacity-50 transition-all shadow-2xl shadow-[#F7A072]/30"
            >
              <span className="text-5xl">→</span>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CoachAIView;

