                <div className="w-1.5 h-1.5 bg-[#4E8B83] rounded-full animate-bounce [animation-delay:0.4s]"></div>
              </div>
            </div>
          )}
          <div ref={scrollRef} />
        </div>

        <div className="p-8 md:p-10 bg-[#FDFBF7] border-t border-gray-100">
          <div className="flex gap-4 max-w-4xl mx-auto">
            <input
              type="text"
              className="flex-1 p-5 bg-white border border-gray-100 rounded-[2rem] outline-none focus:ring-8 focus:ring-[#F7A072]/5 text-lg font-medium shadow-inner transition-all placeholder-[#434343]/20"
              placeholder="How can I help with bedtime?"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            />
            <button
              onClick={handleSend}
              disabled={loading || !input.trim()}
              className="bg-[#F7A072] text-white w-16 h-16 rounded-[1.5rem] flex items-center justify-center font-bold hover:scale-105 active:scale-95 disabled:opacity-50 transition-all shadow-xl shadow-[#F7A072]/20"
            >
              <span className="text-3xl">→</span>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

