import React, { useState } from 'react';
import { getSelfCareContent } from '../services/gemini';
import { UserProfile, FavoriteItem } from '../types';
import Modal from './Modal';
import { trackEvent } from '../services/analytics';

interface Props {
  profile: UserProfile;
  onUpdateProfile: (profile: UserProfile) => void;
  onBack: () => void;
}

const SelfCareHub: React.FC<Props> = ({ profile, onUpdateProfile, onBack }) => {
  const [loadingCategory, setLoadingCategory] = useState<string | null>(null);
  const [content, setContent] = useState<{ title: string; content: string } | null>(null);
  const [feedbackGiven, setFeedbackGiven] = useState(false);

  const handleSelect = async (category: string) => {
    setLoadingCategory(category);
    setFeedbackGiven(false);
    setContent(null); // Ensure fresh content each time
    trackEvent('self_care_request', { category });
    try {
      const res = await getSelfCareContent(category);
      setContent(res);
    } catch (e) {
      console.error(e);
    } finally {
      setLoadingCategory(null);
    }
  };

  const saveToFavorites = () => {
    if (!content) return;
    const newItem: FavoriteItem = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'self_care',
      title: `Zen: ${content.title}`,
      content: content.content,
      dateSaved: new Date().toISOString()
    };
    onUpdateProfile({ ...profile, favorites: [...profile.favorites, newItem] });
    trackEvent('favorite_saved', { type: 'self_care' });
  };

  const handleFeedback = (val: string) => {
    setFeedbackGiven(true);
    trackEvent('self_care_feedback', { feedback: val });
  };

  const categories = [
    { label: 'Calm Down Tools', icon: '❄️', color: 'bg-sky-50 text-sky-800' },
    { label: 'Grounding', icon: '🧘', color: 'bg-emerald-50 text-emerald-800' },
    { label: 'Affirmations', icon: '✨', color: 'bg-rose-50 text-rose-800' },
  ];

  return (
    <div className="max-w-2xl mx-auto py-10 space-y-8">
      <button onClick={onBack} className="text-emerald-700 font-bold flex items-center gap-2 mb-4 hover:translate-x-[-4px] transition-transform">← Back to Hub</button>

      <div className="text-center space-y-6">
        <h2 className="text-4xl font-bold text-emerald-900 font-display">Parent Self Care</h2>
        <div className="text-stone-500 leading-relaxed space-y-1">
          <p>You cannot pour from an empty cup.</p>
          <p>Every click here provides a fresh micro-moment for your own regulation.</p>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-3 gap-6 pt-6">
          {categories.map((cat) => (
            <button
              key={cat.label}
              onClick={() => handleSelect(cat.label)}
              disabled={!!loadingCategory}
              className={`${cat.color} p-8 rounded-[2.5rem] flex flex-col items-center justify-center space-y-4 shadow-sm hover:scale-105 transition-all relative overflow-hidden`}
            >
              {loadingCategory === cat.label ? (
                <div className="flex flex-col items-center gap-2 animate-pulse">
                  <div className="w-8 h-8 border-4 border-current border-t-transparent rounded-full animate-spin"></div>
                  <span className="text-[10px] font-bold uppercase tracking-widest">Finding Zen...</span>
                </div>
              ) : (
                <>
                  <span className="text-4xl">{cat.icon}</span>
                  <span className="font-bold text-sm leading-tight">{cat.label}</span>
                </>
              )}
            </button>
          ))}
        </div>
      </div>

      <Modal isOpen={!!content} onClose={() => setContent(null)} title={content?.title || ''}>
        <div className="text-center space-y-8 py-4">
          <div className="p-8 bg-stone-50 rounded-[3rem] text-2xl font-display text-stone-800 border border-stone-100 shadow-inner">
            {content?.content}
          </div>
          <div className="space-y-4">
            <button onClick={saveToFavorites} className="text-emerald-700 font-bold text-sm hover:underline">⭐ Save to My Favorites</button>
            <button onClick={() => setContent(null)} className="w-full bg-emerald-900 text-white py-5 rounded-2xl font-bold shadow-lg">I feel centered</button>
          </div>

          <div className="pt-6 border-t border-stone-100 space-y-4">
            <p className="text-xs font-bold text-stone-400 uppercase tracking-widest">Did this help?</p>
            {feedbackGiven ? (
              <p className="text-emerald-600 font-bold">Thanks for your feedback! 🌻</p>
            ) : (
              <div className="flex justify-center gap-3">
                {['Yes', 'Somewhat', 'Not yet'].map(val => (
                  <button key={val} onClick={() => handleFeedback(val)} className="px-6 py-2 rounded-xl bg-white border border-stone-200 text-sm font-bold">{val}</button>
                ))}
              </div>
            )}
          </div>
        </div>
      </Modal>
    </div>
  );
};

export default SelfCareHub;

