import React, { useState } from 'react';
import { getSelfCareContent } from '../services/gemini';
import { UserProfile, FavoriteItem } from '../types';
import Modal from './Modal';
import { trackEvent } from '../services/analytics';

interface Props {
  profile: UserProfile;
  onUpdateProfile: (profile: UserProfile) => void;
  onBack: () => void;
}

const SelfCareHub: React.FC<Props> = ({ profile, onUpdateProfile, onBack }) => {
  const [loadingCategory, setLoadingCategory] = useState<string | null>(null);
  const [content, setContent] = useState<{ title: string; content: string } | null>(null);
  const [feedbackGiven, setFeedbackGiven] = useState(false);

  const handleSelect = async (category: string) => {
    setLoadingCategory(category);
    setFeedbackGiven(false);
    setContent(null); // Reset content to ensure modal feels fresh
    trackEvent('self_care_request', { category });
    try {
      // Small timeout to allow spinner to be visible if API is extremely fast
      const [res] = await Promise.all([
        getSelfCareContent(category),
        new Promise(resolve => setTimeout(resolve, 300))
      ]);
      setContent(res);
    } catch (e) {
      console.error(e);
    } finally {
      setLoadingCategory(null);
    }
  };

  const saveToFavorites = () => {
    if (!content) return;
    const newItem: FavoriteItem = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'self_care',
      title: `Zen: ${content.title}`,
      content: content.content,
      dateSaved: new Date().toISOString()
    };
    onUpdateProfile({ ...profile, favorites: [...profile.favorites, newItem] });
    trackEvent('favorite_saved', { type: 'self_care' });
  };

  const handleFeedback = (val: string) => {
    setFeedbackGiven(true);
    trackEvent('self_care_feedback', { feedback: val });
  };

  const categories = [
    { label: 'Calm Down Tools', icon: '❄️', color: 'bg-sky-50 text-sky-800' },
    { label: 'Grounding', icon: '🧘', color: 'bg-emerald-50 text-emerald-800' },
    { label: 'Affirmations', icon: '✨', color: 'bg-rose-50 text-rose-800' },
  ];

  return (
    <div className="max-w-2xl mx-auto py-10 space-y-8">
      <button onClick={onBack} className="text-emerald-700 font-bold flex items-center gap-2 mb-4 hover:translate-x-[-4px] transition-transform">← Back to Hub</button>

      <div className="text-center space-y-6">
        <h2 className="text-4xl font-bold text-emerald-900 font-display">Parent Self Care</h2>
        <div className="text-stone-500 leading-relaxed space-y-1">
          <p>You cannot pour from an empty cup.</p>
          <p>Every click here provides a fresh micro-moment for your own regulation.</p>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-3 gap-6 pt-6">
          {categories.map((cat) => (
            <button
              key={cat.label}
              onClick={() => handleSelect(cat.label)}
              disabled={!!loadingCategory}
              className={`${cat.color} p-8 rounded-[2.5rem] flex flex-col items-center justify-center space-y-4 shadow-sm hover:scale-105 transition-all relative overflow-hidden`}
            >
              {loadingCategory === cat.label ? (
                <div className="flex flex-col items-center gap-2 animate-pulse">
                  <div className="w-8 h-8 border-4 border-current border-t-transparent rounded-full animate-spin"></div>
                  <span className="text-[10px] font-bold uppercase tracking-widest">Finding Zen...</span>
                </div>
              ) : (
                <>
                  <span className="text-4xl">{cat.icon}</span>
                  <span className="font-bold text-sm leading-tight">{cat.label}</span>
                </>
              )}
            </button>
          ))}
        </div>
      </div>

      <Modal isOpen={!!content} onClose={() => setContent(null)} title={content?.title || ''}>
        <div className="text-center space-y-8 py-4">
          <div className="p-8 bg-stone-50 rounded-[3rem] text-2xl font-display text-stone-800 border border-stone-100 shadow-inner">
            {content?.content}
          </div>
          <div className="space-y-4">
            <button onClick={saveToFavorites} className="text-emerald-700 font-bold text-sm hover:underline">⭐ Save to My Favorites</button>
            <button onClick={() => setContent(null)} className="w-full bg-emerald-900 text-white py-5 rounded-2xl font-bold shadow-lg">I feel centered</button>
          </div>

          <div className="pt-6 border-t border-stone-100 space-y-4">
            <p className="text-xs font-bold text-stone-400 uppercase tracking-widest">Did this help?</p>
            {feedbackGiven ? (
              <p className="text-emerald-600 font-bold">Thanks for your feedback! 🌻</p>
            ) : (
              <div className="flex justify-center gap-3">
                {['Yes', 'Somewhat', 'Not yet'].map(val => (
                  <button key={val} onClick={() => handleFeedback(val)} className="px-6 py-2 rounded-xl bg-white border border-stone-200 text-sm font-bold">{val}</button>
                ))}
              </div>
            )}
          </div>
        </div>
      </Modal>
    </div>
  );
};

export default SelfCareHub;

import { GoogleGenAI, Type } from "@google/genai";
import { Child, DailyTip, SelfCareCategory } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Optimized for speed: uses more direct instructions.
 */
export const getChallengeAdvice = async (child: Child, challenge: string): Promise<DailyTip> => {
  const interestsContext = child.interests.length > 0 ? `Child interests: ${child.interests.join(', ')}.` : "";
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `Specialist at MindBloom. Quick help for: "${challenge}" (${child.age}yo). 
    ${interestsContext}
    Provide:
    1. Short summary (content).
    2. One activity (specifically tailored to the child's interests if provided).
    3. One script.
    4. Details.
    Keep it snappy.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          title: { type: Type.STRING },
          content: { type: Type.STRING },
          activity: { type: Type.STRING },
          script: { type: Type.STRING },
          details: { type: Type.STRING },
        },
        required: ["title", "content", "activity", "details"],
      },
    },
  });

  const text = response.text || "{}";
  return JSON.parse(text) as DailyTip;
};

/**
 * Fetches a very short one-liner tip for the dashboard.
 */
export const getDailyOneLiner = async (child: Child, challenge: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `MindBloom Specialist. Give one extremely short, supportive one-liner tip for a parent of a ${child.age}yo dealing with "${challenge}". MUST BE UNDER 10 WORDS. NO PERIOD AT END.`,
  });
  return response.text?.replace(/"/g, '').replace(/\.$/, '') || "Breathe deeply; you are enough";
};

/**
 * Enhanced for readability: Bullet points and line breaks.
 */
export const getAiChatResponse = async (history: {role: string, content: string}[], message: string, children: Child[]) => {
  const childContext = children.map(c => `${c.name} (${c.age})`).join(", ");
  const chat = ai.chats.create({
    model: "gemini-3-flash-preview",
    config: {
      systemInstruction: `You are MindBloom Coach AI. 
      FORMATTING RULES: 
      - Use bullet points for steps or lists.
      - Use separate lines (paragraphs) for readability.
      - Keep it warm and concise (max 100 words).
      Context: children ${childContext}.`,
    }
  });

  const result = await chat.sendMessage({ message });
  return result.text || "";
};

export const getSelfCareContent = async (category: string): Promise<{ title: string; content: string }> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: `MindBloom Sanctuary: Provide a unique, simple 1-sentence ${category} for a parent. 
    If Affirmation: keep it to 10 words max, strictly one line.
    If Grounding: simple one-step action, max 2 lines.
    ALWAYS DIFFERENT from previous common advice. 
    Be extremely concise for instant reading.`,
  });

  return { title: category, content: response.text || "" };
};

export const getExpertResponse = async (question: string, child: Child): Promise<string> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: `Clinical specialist. Deep analysis for: "${question}" (${child.name}, ${child.age}yo). 
    Known challenges: ${child.challenges.join(', ')}.`,
  });
  return response.text || "I apologize, but I couldn't generate a specialist analysis at this moment.";
};

export const getParentWellnessAdvice = async (): Promise<string> => {
  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: "One short micro-moment of zen for a parent. Max 2 sentences.",
  });
  return response.text || "Breathe deeply. You are providing exactly what your child needs right now: love and presence.";
};

import React, { useState, useMemo } from 'react';
import { UserProfile, Child } from '../types';
import { trackEvent } from '../services/analytics';

interface OnboardingProps {
  onComplete: (profile: UserProfile) => void;
}

const PlantIcon = ({ className = "" }: { className?: string }) => (
  <svg width="48" height="48" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" className={`${className} animate-pulse`}>
    <path d="M12 22V12M12 12C12 12 12 8 16 8M12 12C12 12 12 8 8 8M12 15C12 15 15 14 15 11C15 8 12 8 12 8M12 15C12 15 9 14 9 11C9 8 12 8 12 8" stroke="#4E8B83" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
    <path d="M12 8V5M12 5C12 5 12 3 14 3M12 5C12 5 12 3 10 3" stroke="#4E8B83" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/>
  </svg>
);

const CHALLENGE_MAP = {
  '0-5': ['Big Emotions', 'Tantrums', 'Separation Anxiety', 'Listening Skills', 'Sleep Routines', 'Activity Transitions', 'Picky Eating', 'Turn Taking', 'Screen Limits', 'Independence Struggles'],
  '6-10': ['Emotional Regulation', 'Friendship Issues', 'Self Confidence', 'Homework Resistance', 'Respectful Listening', 'Disappointment Tolerance', 'Screen Balance', 'Honesty', 'Sibling Conflict', 'Teacher Expectations'],
  '11-15': ['Mood Swings', 'Peer Pressure', 'Communication Breakdown', 'Boundary Testing', 'Self Esteem', 'Motivation Struggles', 'Screen Time', 'Friend Drama', 'Authority Resistance', 'Stress Management'],
  '16-18': ['Independence Tension', 'Trust Building', 'Accountability', 'Emotional Control', 'Decision Making', 'Social Comparison', 'Time Management', 'Conflict Resolution', 'Life Readiness', 'Relationship Shifts']
};

const INTERESTS_MAP = {
  '0-5': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Dolls/Cars', 'Building', 'Nature', 'Dance/Music', 'Pretend Play', 'Blocks'],
  '6-10': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Building', 'Games', 'Technology', 'Sports', 'Nature', 'Puzzles'],
  '11-15': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Technology', 'Coding', 'Gaming', 'Debate', 'Social Media', 'Drama'],
  '16-18': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Technology', 'Coding', 'Gaming', 'Travel', 'Career', 'Fitness']
};

const Onboarding: React.FC<OnboardingProps> = ({ onComplete }) => {
  const [parentName, setParentName] = useState('');
  const [children, setChildren] = useState<Child[]>([]);
  const [step, setStep] = useState<'parent' | 'child'>('parent');
  const [tempChild, setTempChild] = useState<Partial<Child>>({ 
    name: '', 
    age: undefined, 
    challenges: [], 
    interests: [] 
  });

  const currentChallenges = useMemo(() => {
    const age = Number(tempChild.age) || 0;
    if (age <= 5) return CHALLENGE_MAP['0-5'];
    if (age <= 10) return CHALLENGE_MAP['6-10'];
    if (age <= 15) return CHALLENGE_MAP['11-15'];
    return CHALLENGE_MAP['16-18'];
  }, [tempChild.age]);

  const currentInterests = useMemo(() => {
    const age = Number(tempChild.age) || 0;
    if (age <= 5) return INTERESTS_MAP['0-5'];
    if (age <= 10) return INTERESTS_MAP['6-10'];
    if (age <= 15) return INTERESTS_MAP['11-15'];
    return INTERESTS_MAP['16-18'];
  }, [tempChild.age]);

  const toggleItem = (item: string, key: 'challenges' | 'interests') => {
    const current = (tempChild[key] as string[]) || [];
    setTempChild({
      ...tempChild, 
      [key]: current.includes(item) ? current.filter(i => i !== item) : [...current, item]
    });
  };

  const handleAddChild = () => {
    if (!tempChild.name || tempChild.age === undefined) return;
    const newChild: Child = {
      id: Math.random().toString(36).substr(2, 9),
      name: tempChild.name,
      age: Number(tempChild.age),
      challenges: tempChild.challenges || [],
      interests: tempChild.interests || []
    };
    setChildren([...children, newChild]);
    setTempChild({ name: '', age: undefined, challenges: [], interests: [] });
    trackEvent('child_added', { age: newChild.age });
  };

  const handleFinish = () => {
    let finalChildren = [...children];
    if (tempChild.name && tempChild.age !== undefined && !children.some(c => c.name === tempChild.name)) {
      finalChildren.push({
        id: Math.random().toString(36).substr(2, 9),
        name: tempChild.name,
        age: Number(tempChild.age),
        challenges: tempChild.challenges || [],
        interests: tempChild.interests || []
      });
    }

    onComplete({ 
      name: parentName, 
      children: finalChildren, 
      onboarded: true,
      favorites: [],
      chatHistory: [],
      logs: []
    });
  };

  return (
    <div className="min-h-screen bg-[#FDFBF7] flex items-center justify-center p-6 py-12">
      <div className="max-w-3xl w-full bg-white rounded-[3.5rem] shadow-2xl shadow-[#4E8B83]/5 p-10 md:p-14 space-y-10 border border-[#4E8B83]/10 relative overflow-hidden">
        <div className="absolute -top-12 -right-12 text-6xl opacity-5 animate-spin-slow text-[#4E8B83]">🌻</div>

        <div className="text-center space-y-3">
          <div className="flex items-center justify-center gap-4 sm:gap-8">
            <PlantIcon className="opacity-80 scale-75 sm:scale-100" />
            <h2 className="text-4xl sm:text-5xl font-bold text-[#434343] font-display tracking-tight">Mind<span className="text-[#4E8B83]">Bloom</span></h2>
            <PlantIcon className="opacity-80 scale-75 sm:scale-100 -scale-x-100" />
          </div>
          <p className="text-[#434343]/50 text-lg font-medium font-display">Gentle guidance for growing families.</p>
        </div>

        {step === 'parent' ? (
          <div className="space-y-10 animate-in fade-in zoom-in duration-500 max-w-sm mx-auto">
            <section className="space-y-4 text-center">
              <label className="text-[10px] font-bold uppercase tracking-[0.3em] text-[#4E8B83]">Welcome! What is your name?</label>
              <input
                type="text"
                value={parentName}
                onChange={(e) => setParentName(e.target.value)}
                className="w-full p-5 bg-[#FDFBF7] border-2 border-[#4E8B83]/10 rounded-3xl focus:ring-4 focus:ring-[#4E8B83]/10 outline-none text-2xl text-center font-display font-bold text-[#434343] transition-all"
                placeholder="Name"
              />
            </section>
            <button
              onClick={() => setStep('child')}
              disabled={!parentName}
              className="w-full bg-[#4E8B83] text-white p-5 rounded-3xl font-bold text-xl hover:scale-[1.02] transition-all shadow-xl shadow-[#4E8B83]/20 disabled:opacity-50 font-display"
            >
              Get Started →
            </button>
          </div>
        ) : (
          <div className="space-y-10 animate-in fade-in duration-500">
            {children.length > 0 && (
              <div className="space-y-3 text-center">
                <p className="text-[8px] font-bold text-[#4E8B83] uppercase tracking-[0.2em]">Your Bloom List</p>
                <div className="flex flex-wrap justify-center gap-2">
                  {children.map(c => (
                    <div key={c.id} className="bg-[#E8F1F0] text-[#4E8B83] px-5 py-2 rounded-full text-xs font-bold border border-[#4E8B83]/10">
                      {c.name} ({c.age})
                    </div>
                  ))}
                </div>
              </div>
            )}

            <section className="space-y-8">
              <h3 className="text-3xl font-bold text-[#434343] font-display text-center">
                {children.length === 0 ? "About your child" : "Add another child"}
              </h3>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[9px] font-bold uppercase tracking-[0.1em] text-[#4E8B83] px-3">Name</label>
                  <input
                    type="text"
                    placeholder="Child's Name"
                    className="w-full p-4 bg-[#FDFBF7] border-2 border-[#4E8B83]/10 rounded-2xl outline-none font-bold text-[#434343]"
                    value={tempChild.name}
                    onChange={(e) => setTempChild({...tempChild, name: e.target.value})}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-bold uppercase tracking-[0.1em] text-[#4E8B83] px-3">Age</label>
                  <input
                    type="number"
                    placeholder="Age"
                    className="w-full p-4 bg-[#FDFBF7] border-2 border-[#4E8B83]/10 rounded-2xl outline-none font-bold text-[#434343]"
                    value={tempChild.age === undefined ? '' : tempChild.age}
                    onChange={(e) => setTempChild({...tempChild, age: e.target.value === '' ? undefined : Number(e.target.value)})}
                  />
                </div>
              </div>

              {tempChild.name && tempChild.age !== undefined && (
                <div className="space-y-10 pt-4 animate-in fade-in duration-500">
                  <div className="space-y-4">
                    <p className="text-[9px] font-bold text-[#4E8B83] uppercase tracking-[0.2em] text-center">Typical Challenges</p>
                    <div className="flex flex-wrap justify-center gap-2">
                      {currentChallenges.map(c => (
                        <button
                          key={c}
                          onClick={() => toggleItem(c, 'challenges')}
                          className={`px-4 py-2 rounded-full text-[10px] font-bold border-2 transition-all ${
                            tempChild.challenges?.includes(c) 
                            ? 'bg-[#4E8B83] border-[#4E8B83] text-white' 
                            : 'bg-white border-gray-100 text-gray-400 hover:border-[#4E8B83]/30'
                          }`}
                        >
                          {c}
                        </button>
                      ))}
                    </div>
                  </div>

                  <div className="space-y-4">
                    <p className="text-[9px] font-bold text-[#F7A072] uppercase tracking-[0.2em] text-center">Interests</p>
                    <div className="flex flex-wrap justify-center gap-2">
                      {currentInterests.map(i => (
                        <button
                          key={i}
                          onClick={() => toggleItem(i, 'interests')}
                          className={`px-4 py-2 rounded-full text-[10px] font-bold border-2 transition-all ${
                            tempChild.interests?.includes(i) 
                            ? 'bg-[#F7A072] border-[#F7A072] text-white' 
                            : 'bg-white border-gray-100 text-gray-400 hover:border-[#F7A072]/30'
                          }`}
                        >
                          {i}
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
              )}
            </section>

            <div className="flex flex-col sm:flex-row gap-4 pt-4">
              <button
                onClick={handleAddChild}
                disabled={!tempChild.name || tempChild.age === undefined}
                className="flex-1 bg-white text-[#4E8B83] border-2 border-[#4E8B83] p-4 rounded-3xl font-bold text-base hover:bg-[#E8F1F0]/40 transition-all disabled:opacity-30 font-display"
              >
                + Add Child
              </button>
              <button
                onClick={handleFinish}
                disabled={children.length === 0 && (!tempChild.name || tempChild.age === undefined)}
                className="flex-1 bg-[#4E8B83] text-white p-4 rounded-3xl font-bold text-base hover:opacity-90 transition-all shadow-xl shadow-[#4E8B83]/20 disabled:opacity-50 font-display"
              >
                Let's Bloom
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Onboarding;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { UserProfile, ChatMessage, FavoriteItem } from '../types';
import { getAiChatResponse } from '../services/gemini';
import { trackEvent } from '../services/analytics';

interface Props {
  profile: UserProfile;
  onUpdateProfile: (profile: UserProfile) => void;
  onBack: () => void;
}

const CoachAIView: React.FC<Props> = ({ profile, onUpdateProfile, onBack }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Group history for "Past Questions" summary
  const pastQuestions = useMemo(() => {
    return profile.chatHistory
      .filter(m => m.role === 'user')
      .slice(-5) // Last 5 questions
      .reverse();
  }, [profile.chatHistory]);

  useEffect(() => {
    // Scroll to bottom on load if there's history
    if (profile.chatHistory.length > 0) {
      scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, []);

  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [profile.chatHistory]);

  const handleSend = async (text: string = input) => {
    const finalInput = text.trim();
    if (!finalInput || loading) return;

    const userMsg: ChatMessage = { 
      role: 'user', 
      content: finalInput, 
      timestamp: new Date().toISOString() 
    };

    const updatedHistory = [...profile.chatHistory, userMsg];
    onUpdateProfile({ ...profile, chatHistory: updatedHistory });
    setInput('');
    setLoading(true);
    trackEvent('coach_query', { length: finalInput.length });

    try {
      const resText = await getAiChatResponse(updatedHistory.map(m => ({ role: m.role, content: m.content })), finalInput, profile.children);
      const aiMsg: ChatMessage = { 
        role: 'assistant', 
        content: resText, 
        timestamp: new Date().toISOString() 
      };
      onUpdateProfile({ ...profile, chatHistory: [...updatedHistory, aiMsg] });
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const saveToFavorites = (content: string) => {
    const newItem: FavoriteItem = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'advice',
      title: "Coach AI Insight",
      content,
      dateSaved: new Date().toISOString()
    };
    onUpdateProfile({ ...profile, favorites: [...profile.favorites, newItem] });
    trackEvent('favorite_saved', { type: 'coach_advice' });
  };

  const clearHistory = () => {
    if (confirm("Clear your conversation history?")) {
      onUpdateProfile({ ...profile, chatHistory: [] });
    }
  };

  return (
    <div className="max-w-4xl mx-auto py-4 flex flex-col h-[82vh]">
      <div className="flex justify-between items-center mb-8 px-6">
        <button onClick={onBack} className="text-[#F7A072] font-bold flex items-center gap-3 font-display text-lg uppercase tracking-wider">
          <span className="text-2xl">←</span> Back Home
        </button>
        <div className="flex flex-col items-end">
          <div className="flex items-center gap-4">
            {profile.chatHistory.length > 0 && (
              <button onClick={clearHistory} className="text-[9px] font-bold text-[#434343]/30 hover:text-red-400 uppercase tracking-widest transition-colors">
                Clear History
              </button>
            )}
            <div className="text-right">
              <h2 className="text-3xl font-bold text-[#434343] font-display">Coach AI</h2>
              <p className="text-[10px] text-[#F7A072] font-bold uppercase tracking-[0.3em]">Compassionate Listening</p>
            </div>
          </div>
        </div>
      </div>

      <div className="flex-1 bg-white rounded-[3.5rem] card-shadow border border-gray-100 overflow-hidden flex flex-col">
        <div className="flex-1 overflow-y-auto p-10 md:p-12 space-y-10 scrollbar-hide">
          {profile.chatHistory.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center p-10 space-y-8">
               <div className="w-24 h-24 bg-[#FFEDE3] rounded-[2rem] flex items-center justify-center text-6xl animate-float shadow-xl shadow-[#F7A072]/5">🤖</div>
               <div className="space-y-3">
                 <p className="font-display text-3xl text-[#434343] font-bold">"How can I help make your day better?"</p>
                 <p className="text-[#434343]/40 font-bold uppercase tracking-widest text-[10px]">Ask me anything, anytime.</p>
               </div>
            </div>
          ) : (
            <>
              {/* Recent Questions Quick Links */}
              <div className="bg-[#FDFBF7] p-6 rounded-[2rem] border border-[#4E8B83]/10 space-y-4 mb-4">
                <p className="text-[9px] font-bold text-[#4E8B83] uppercase tracking-widest border-b border-[#4E8B83]/10 pb-2">Recent Questions</p>
                <div className="flex flex-wrap gap-2">
                  {pastQuestions.map((q, idx) => (
                    <button 
                      key={idx}
                      onClick={() => setInput(q.content)}
                      className="text-[10px] bg-white px-3 py-1.5 rounded-full border border-gray-100 text-[#434343]/60 hover:border-[#4E8B83] hover:text-[#4E8B83] transition-all truncate max-w-[150px]"
                    >
                      {q.content}
                    </button>
                  ))}
                </div>
              </div>

              {profile.chatHistory.map((msg, i) => (
                <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-3 duration-400`}>
                  <div className={`max-w-[85%] md:max-w-[75%] space-y-3`}>
                    <div className={`p-8 md:p-10 rounded-[2.5rem] shadow-sm font-medium leading-relaxed text-lg ${
                      msg.role === 'user' 
                      ? 'bg-[#F7A072] text-white rounded-tr-none shadow-xl shadow-[#F7A072]/10' 
                      : 'bg-[#FDFBF7] text-[#434343] rounded-tl-none border-2 border-[#4E8B83]/10 shadow-lg shadow-[#4E8B83]/5'
                    }`}>
                      <p className="whitespace-pre-wrap">{msg.content}</p>
                    </div>
                    {msg.role === 'assistant' && (
                      <button 
                        onClick={() => saveToFavorites(msg.content)} 
                        className="text-[9px] font-bold text-[#4E8B83] uppercase tracking-widest hover:text-[#434343] ml-6 transition-colors flex items-center gap-1.5"
                      >
                        <span>⭐</span> Save to Bloom List
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </>
          )}
          {loading && (
            <div className="flex justify-start">
              <div className="bg-[#E8F1F0] px-8 py-4 rounded-full border border-[#4E8B83]/10 flex gap-2 items-center shadow-sm">
                <div className="w-1.5 h-1.5 bg-[#4E8B83] rounded-full animate-bounce"></div>
                <div className="w-1.5 h-1.5 bg-[#4E8B83] rounded-full animate-bounce [animation-delay:0.2s]"></div>
                <div className="w-1.5 h-1.5 bg-[#4E8B83] rounded-full animate-bounce [animation-delay:0.4s]"></div>
              </div>
            </div>
          )}
          <div ref={scrollRef} />
        </div>

        <div className="p-8 md:p-10 bg-[#FDFBF7] border-t border-gray-100">
          <div className="flex gap-4 max-w-4xl mx-auto">
            <input
              type="text"
              className="flex-1 p-5 bg-white border border-gray-100 rounded-[2rem] outline-none focus:ring-8 focus:ring-[#F7A072]/5 text-lg font-medium shadow-inner transition-all placeholder-[#434343]/20"
              placeholder="How can I help with bedtime?"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            />
            <button
              onClick={() => handleSend()}
              disabled={loading || !input.trim()}
              className="bg-[#F7A072] text-white w-16 h-16 rounded-[1.5rem] flex items-center justify-center font-bold hover:scale-105 active:scale-95 disabled:opacity-50 transition-all shadow-xl shadow-[#F7A072]/20"
            >
              <span className="text-3xl">→</span>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CoachAIView;

import React, { useState } from 'react';
import { UserProfile, Child, DailyTip, FavoriteItem } from '../types';
import { getChallengeAdvice } from '../services/gemini';
import Modal from './Modal';
import { trackEvent } from '../services/analytics';

interface Props {
  profile: UserProfile;
  onUpdateProfile: (profile: UserProfile) => void;
  onBack: () => void;
}

const AdviceActivities: React.FC<Props> = ({ profile, onUpdateProfile, onBack }) => {
  const [selectedChild, setSelectedChild] = useState<Child>(profile.children[0]);
  const [selectedChallenge, setSelectedChallenge] = useState<string>('');
  const [advice, setAdvice] = useState<DailyTip | null>(null);
  const [loading, setLoading] = useState(false);
  const [showMainModal, setShowMainModal] = useState(false);
  const [feedbackGiven, setFeedbackGiven] = useState<string | null>(null);
  const [savedItems, setSavedItems] = useState<Set<string>>(new Set());
  const [newChallengeInput, setNewChallengeInput] = useState('');
  const [isAddingChallenge, setIsAddingChallenge] = useState(false);

  const handleChallengeClick = async (challenge: string) => {
    setSelectedChallenge(challenge);
    setLoading(true);
    setFeedbackGiven(null);
    setSavedItems(new Set());
    trackEvent('advice_request', { challenge, childAge: selectedChild.age });
    try {
      const res = await getChallengeAdvice(selectedChild, challenge);
      setAdvice(res);
      setShowMainModal(true);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleAddCustomChallenge = () => {
    if (!newChallengeInput.trim()) {
      setIsAddingChallenge(false);
      return;
    }

    const trimmedChallenge = newChallengeInput.trim();
    if (selectedChild.challenges.includes(trimmedChallenge)) {
      setNewChallengeInput('');
      setIsAddingChallenge(false);
      return;
    }

    const updatedChildren = profile.children.map(c => {
      if (c.id === selectedChild.id) {
        return {
          ...c,
          challenges: [...c.challenges, trimmedChallenge]
        };
      }
      return c;
    });

    const updatedChild = updatedChildren.find(c => c.id === selectedChild.id)!;

    onUpdateProfile({
      ...profile,
      children: updatedChildren
    });

    setSelectedChild(updatedChild);
    setNewChallengeInput('');
    setIsAddingChallenge(false);
    trackEvent('custom_challenge_added', { challenge: trimmedChallenge });
  };

  const saveToFavorites = (type: 'advice' | 'script' | 'activity', content: string) => {
    const key = `${type}-${content.substring(0, 10)}`;
    if (savedItems.has(key)) return;

    const newItem: FavoriteItem = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      title: `${selectedChallenge} (${type})`,
      content,
      childContext: `${selectedChild.name} (Age ${selectedChild.age})`,
      dateSaved: new Date().toISOString()
    };

    onUpdateProfile({ ...profile, favorites: [...profile.favorites, newItem] });
    setSavedItems(prev => new Set(prev).add(key));
    trackEvent('favorite_saved', { type });
  };

  const handleFeedback = (val: string) => {
    setFeedbackGiven(val);
    trackEvent('advice_feedback', { challenge: selectedChallenge, feedback: val });
  };

  const isSaved = (type: string, content: string) => {
    const key = `${type}-${content.substring(0, 10)}`;
    return savedItems.has(key);
  };

  // Helper for developmental range
  const minAge = Math.max(0, selectedChild.age - 1);
  const maxAge = selectedChild.age + 1;

  // Shared font styles for consistency
  const contentFontClass = "text-lg md:text-xl text-[#434343] leading-relaxed font-display font-medium";

  return (
    <div className="space-y-8 max-w-5xl mx-auto py-4">
      <div className="flex items-center justify-between">
        <button onClick={onBack} className="text-[#4E8B83] font-bold flex items-center gap-3 hover:translate-x-[-4px] transition-transform font-display text-lg uppercase tracking-wider">
          <span className="text-2xl">←</span> Back
        </button>
        <div className="flex bg-white p-1.5 rounded-full card-shadow border border-[#4E8B83]/10">
          {profile.children.map(c => (
            <button
              key={c.id}
              onClick={() => setSelectedChild(c)}
              className={`px-6 py-2 rounded-full text-[11px] font-bold transition-all ${
                selectedChild.id === c.id 
                ? 'bg-[#4E8B83] text-white shadow-md' 
                : 'text-[#434343]/50 hover:text-[#4E8B83]'
              }`}
            >
              {c.name}
            </button>
          ))}
        </div>
      </div>

      <div className="bg-white p-8 md:p-12 rounded-[3.5rem] card-shadow border border-[#4E8B83]/10 min-h-[60vh] flex flex-col items-center justify-start space-y-12 animate-in fade-in duration-500">
        <header className="text-center space-y-4">
          <div className="inline-block px-4 py-1.5 bg-[#E8F1F0] rounded-full text-[10px] font-bold text-[#4E8B83] uppercase tracking-[0.3em] mb-2">
            Blooming {selectedChild.name} (Age {selectedChild.age})
          </div>
          <h2 className="text-4xl md:text-5xl font-bold text-[#434343] font-display">Pick a Challenge</h2>
          <p className="text-[#434343]/50 font-medium text-lg">Select a milestone or area where {selectedChild.name} needs some gentle guidance.</p>
        </header>

        <div className="w-full max-w-4xl grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-4">
          {selectedChild.challenges.map(c => (
            <button
              key={c}
              disabled={loading}
              onClick={() => handleChallengeClick(c)}
              className="px-4 py-6 rounded-[2rem] text-sm font-bold bg-[#FDFBF7] border border-[#4E8B83]/10 text-[#4E8B83] hover:bg-[#4E8B83] hover:text-white transition-all transform hover:-translate-y-1 shadow-sm flex items-center justify-center text-center"
            >
              {c}
            </button>
          ))}

          {isAddingChallenge ? (
            <div className="col-span-2 flex items-center gap-2 animate-in slide-in-from-right-2 duration-300">
              <input
                autoFocus
                type="text"
                value={newChallengeInput}
                onChange={(e) => setNewChallengeInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleAddCustomChallenge()}
                onBlur={() => !newChallengeInput && setIsAddingChallenge(false)}
                placeholder="What's the challenge?"
                className="flex-1 px-6 py-5 rounded-[2rem] text-sm font-bold border-2 border-[#F7A072] outline-none text-[#434343] shadow-inner"
              />
              <button 
                onClick={handleAddCustomChallenge}
                className="w-14 h-14 bg-[#F7A072] text-white rounded-2xl flex items-center justify-center font-bold shadow-lg shadow-[#F7A072]/20 text-xl"
              >
                ✓
              </button>
            </div>
          ) : (
            <button
              onClick={() => setIsAddingChallenge(true)}
              className="px-4 py-6 rounded-[2rem] text-sm font-bold border-2 border-dashed border-[#F7A072]/40 text-[#F7A072] hover:bg-[#F7A072]/5 transition-all flex items-center justify-center text-center"
            >
              + Add Custom
            </button>
          )}
        </div>

        {loading && (
          <div className="py-8 flex flex-col items-center gap-4">
            <div className="w-12 h-12 border-4 border-[#4E8B83]/20 border-t-[#4E8B83] rounded-full animate-spin"></div>
            <p className="text-[#4E8B83] font-bold text-xs tracking-widest uppercase animate-pulse">Consulting Specialist AI...</p>
          </div>
        )}
      </div>

      <Modal isOpen={showMainModal} onClose={() => setShowMainModal(false)} title={selectedChallenge}>
        <div className="space-y-8">
          {/* Developmental Labels */}
          <div className="flex flex-col gap-2 p-5 bg-[#FDFBF7] rounded-[2rem] border border-[#4E8B83]/10 text-[11px] font-bold text-[#4E8B83]/70 uppercase tracking-widest">
            <div className="flex items-center gap-2">
              <span className="text-[#4E8B83]">✔️</span> Recommended for ages {minAge}–{maxAge}
            </div>
            <div className="flex items-center gap-2">
              <span className="text-[#4E8B83]">✔️</span> Developmentally common at this age
            </div>
          </div>

          {/* Advice Section */}
          <div className="space-y-4">
            <div className="flex justify-between items-center bg-[#E8F1F0]/50 p-6 rounded-t-[2.5rem] border-x border-t border-[#4E8B83]/10">
              <h4 className="font-black text-[#4E8B83] uppercase text-2xl md:text-3xl tracking-tight flex items-center gap-3">
                <span className="text-3xl">💡</span> Gentle Strategy
              </h4>
              <button 
                onClick={() => saveToFavorites('advice', advice?.content || '')}
                className={`text-[9px] font-bold border-2 px-3 py-1.5 rounded-full transition-all uppercase tracking-wider ${
                  isSaved('advice', advice?.content || '') 
                  ? 'bg-[#4E8B83] text-white border-[#4E8B83]' 
                  : 'text-[#4E8B83] border-[#4E8B83]/20 hover:bg-[#4E8B83]/5'
                }`}
              >
                {isSaved('advice', advice?.content || '') ? 'Saved ⭐' : 'Save'}
              </button>
            </div>
            <div className="p-8 bg-white border-x border-b border-[#4E8B83]/10 rounded-b-[2.5rem] shadow-sm">
              <p className={contentFontClass}>{advice?.content}</p>
            </div>
          </div>

          {/* Script Section */}
          <div className="space-y-4">
            <div className="flex justify-between items-center bg-[#FFEDE3] p-6 rounded-t-[2.5rem] border-x border-t border-[#F7A072]/10">
              <h5 className="font-black text-[#F7A072] text-2xl md:text-3xl uppercase tracking-tight flex items-center gap-3">
                <span className="text-3xl">💬</span> The Script
              </h5>
              <button 
                onClick={() => saveToFavorites('script', advice?.script || '')}
                className={`text-[9px] font-bold border-2 px-3 py-1.5 rounded-full transition-all uppercase tracking-wider ${
                  isSaved('script', advice?.script || '') 
                  ? 'bg-[#F7A072] text-white border-[#F7A072]' 
                  : 'text-[#F7A072] border-[#F7A072]/20 hover:bg-[#F7A072]/5'
                }`}
              >
                {isSaved('script', advice?.script || '') ? 'Saved ⭐' : 'Save'}
              </button>
            </div>
            <div className="p-10 bg-white border-x border-b border-[#F7A072]/10 rounded-b-[2.5rem] shadow-sm italic">
              <p className="text-[#434343] text-2xl md:text-4xl font-display leading-tight">"{advice?.script}"</p>
            </div>
          </div>

          {/* Activity Section */}
          <div className="space-y-4">
            <div className="flex justify-between items-center bg-[#FDFBF7] p-6 rounded-t-[2.5rem] border-x border-t border-gray-100">
              <h5 className="font-black text-[#434343]/60 text-2xl md:text-3xl uppercase tracking-tight flex items-center gap-3">
                <span className="text-3xl">🎨</span> Bloom Activity
              </h5>
              <button 
                onClick={() => saveToFavorites('activity', advice?.activity || '')}
                className={`text-[9px] font-bold border-2 px-3 py-1.5 rounded-full transition-all uppercase tracking-wider ${
                  isSaved('activity', advice?.activity || '') 
                  ? 'bg-[#4E8B83] text-white border-[#4E8B83]' 
                  : 'text-[#4E8B83] border-[#4E8B83]/20 hover:bg-[#4E8B83]/5'
                }`}
              >
                {isSaved('activity', advice?.activity || '') ? 'Saved ⭐' : 'Save'}
              </button>
            </div>
            <div className="p-8 bg-white border-x border-b border-gray-100 rounded-b-[2.5rem] shadow-sm">
              <p className={contentFontClass}>{advice?.activity}</p>
            </div>
          </div>

          <div className="pt-8 border-t border-gray-100 text-center space-y-6">
            <p className="text-[10px] font-bold text-[#434343]/30 uppercase tracking-[0.4em]">Did this help?</p>
            {feedbackGiven ? (
              <p className="text-[#4E8B83] font-bold text-xl animate-in zoom-in duration-300 uppercase tracking-widest">Thank you! 🌻</p>
            ) : (
              <div className="flex justify-center gap-4">
                {['Yes', 'Kind of', 'No'].map(val => (
                  <button
                    key={val}
                    onClick={() => handleFeedback(val)}
                    className="px-8 py-3 rounded-full bg-[#FDFBF7] border-2 border-gray-100 text-[11px] font-bold text-[#4E8B83] hover:bg-[#4E8B83] hover:text-white transition-all active:scale-95 shadow-sm"
                  >
                    {val}
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>
      </Modal>
    </div>
  );
};

