import React, { useState, useEffect, useRef, useMemo } from 'react';
import { UserProfile, ChatMessage, FavoriteItem } from '../types';
import { getAiChatResponse } from '../services/gemini';
import { trackEvent } from '../services/analytics';

interface Props {
  profile: UserProfile;
  onUpdateProfile: (profile: UserProfile) => void;
  onBack: () => void;
}

const CoachAIView: React.FC<Props> = ({ profile, onUpdateProfile, onBack }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom whenever history changes
  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [profile.chatHistory, loading]);

  // Extract past user questions for quick navigation
  const pastUserQuestions = useMemo(() => {
    return profile.chatHistory
      .filter(m => m.role === 'user')
      .slice(-6)
      .reverse();
  }, [profile.chatHistory]);

  const handleSend = async (customText?: string) => {
    const textToSend = customText || input;
    if (!textToSend.trim() || loading) return;

    setError(null);
    const userMsg: ChatMessage = { 
      role: 'user', 
      content: textToSend, 
      timestamp: new Date().toISOString() 
    };

    const updatedHistory = [...profile.chatHistory, userMsg];
    onUpdateProfile({ ...profile, chatHistory: updatedHistory });
    setInput('');
    setLoading(true);
    trackEvent('coach_query', { length: textToSend.length });

    try {
      const resText = await getAiChatResponse(updatedHistory.map(m => ({ role: m.role, content: m.content })), textToSend, profile.children);
      const aiMsg: ChatMessage = { 
        role: 'assistant', 
        content: resText, 
        timestamp: new Date().toISOString() 
      };
      onUpdateProfile({ ...profile, chatHistory: [...updatedHistory, aiMsg] });
    } catch (e: any) {
      console.error(e);
      const msg = e.message?.includes('429') ? "MindBloom is very busy right now. Please wait a moment and try again." : "Something went wrong. Please check your connection.";
      setError(msg);
    } finally {
      setLoading(false);
    }
  };

  const saveToFavorites = (content: string) => {
    const newItem: FavoriteItem = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'advice',
      title: "Coach Insight",
      content,
      dateSaved: new Date().toISOString()
    };
    onUpdateProfile({ ...profile, favorites: [...profile.favorites, newItem] });
    trackEvent('favorite_saved', { type: 'coach_advice' });
  };

  const clearHistory = () => {
    if (confirm("Reset conversation history?")) {
      onUpdateProfile({ ...profile, chatHistory: [] });
    }
  };

  return (
    <div className="max-w-4xl mx-auto py-2 flex flex-col h-[85vh]">
      <div className="flex justify-between items-center mb-4 px-6">
        <button onClick={onBack} className="text-[#F7A072] font-bold flex items-center gap-2 font-display text-base uppercase tracking-wider group">
          <span className="text-xl transition-transform group-hover:-translate-x-1">←</span> Home
        </button>
        <div className="flex items-center gap-4">
          {profile.chatHistory.length > 0 && (
            <button 
              onClick={clearHistory}
              className="text-[9px] font-bold text-[#434343]/30 hover:text-red-400 uppercase tracking-widest transition-colors"
            >
              Clear
            </button>
          )}
          <div className="text-right">
            <h2 className="text-2xl font-bold text-[#434343] font-display">Coach AI</h2>
          </div>
        </div>
      </div>

      <div className="flex-1 bg-white rounded-[2.5rem] card-shadow border border-gray-100 overflow-hidden flex flex-col">
        {/* Quick History Bar - More Compact */}
        {pastUserQuestions.length > 0 && (
          <div className="bg-[#FDFBF7] px-6 py-2 border-b border-gray-100 flex items-center gap-3 overflow-x-auto no-scrollbar">
            <span className="text-[7px] font-black text-[#434343]/30 uppercase tracking-[0.2em] whitespace-nowrap">Topic History:</span>
            {pastUserQuestions.map((q, i) => (
              <button 
                key={i} 
                onClick={() => handleSend(q.content)}
                className="text-[9px] font-bold bg-white border border-gray-100 px-3 py-1 rounded-full text-[#4E8B83] hover:border-[#4E8B83] transition-all whitespace-nowrap shadow-sm"
              >
                {q.content.length > 25 ? q.content.substring(0, 25) + '...' : q.content}
              </button>
            ))}
          </div>
        )}

        <div className="flex-1 overflow-y-auto p-6 md:p-8 space-y-6 scrollbar-hide">
          {profile.chatHistory.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center p-6 space-y-6">
               <div className="w-20 h-20 bg-[#FFEDE3] rounded-[1.5rem] flex items-center justify-center text-5xl animate-float shadow-xl shadow-[#F7A072]/5">🤖</div>
               <div className="space-y-2">
                 <p className="font-display text-2xl text-[#434343] font-bold">"Ask me anything."</p>
                 <p className="text-[#434343]/40 font-bold uppercase tracking-widest text-[9px]">Scripts, tantrums, or transitions.</p>
               </div>
            </div>
          ) : (
            profile.chatHistory.map((msg, i) => (
              <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 duration-300`}>
                <div className={`max-w-[90%] md:max-w-[80%] space-y-2`}>
                  <div className={`p-4 md:p-5 rounded-[1.5rem] shadow-sm font-medium leading-relaxed text-base ${
