        </div>

        <div className="p-4 md:p-6 bg-[#FDFBF7] border-t border-gray-100">
          <div className="flex gap-3 max-w-4xl mx-auto">
            <input
              type="text"
              className="flex-1 p-4 bg-white border border-gray-100 rounded-[1.5rem] outline-none focus:ring-4 focus:ring-[#F7A072]/5 text-base font-medium shadow-inner transition-all placeholder-[#434343]/20"
              placeholder="Ask about a script or milestone..."
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            />
