              onClick={() => handleSend()}
              disabled={loading || !input.trim()}
              className="bg-[#F7A072] text-white w-12 h-12 rounded-[1rem] flex items-center justify-center font-bold hover:scale-105 active:scale-95 disabled:opacity-50 transition-all shadow-lg shadow-[#F7A072]/20"
