  </svg>
);

const CHALLENGE_MAP = {
  '0-5': ['Big Emotions', 'Tantrums', 'Separation Anxiety', 'Listening Skills', 'Sleep Routines', 'Activity Transitions', 'Picky Eating', 'Turn Taking', 'Screen Limits', 'Independence Struggles'],
  '6-10': ['Emotional Regulation', 'Friendship Issues', 'Self Confidence', 'Homework Resistance', 'Respectful Listening', 'Disappointment Tolerance', 'Screen Balance', 'Honesty', 'Sibling Conflict', 'Teacher Expectations'],
  '11-15': ['Mood Swings', 'Peer Pressure', 'Communication Breakdown', 'Boundary Testing', 'Self Esteem', 'Motivation Struggles', 'Screen Time', 'Friend Drama', 'Authority Resistance', 'Stress Management'],
  '16-18': ['Independence Tension', 'Trust Building', 'Accountability', 'Emotional Control', 'Decision Making', 'Social Comparison', 'Time Management', 'Conflict Resolution', 'Life Readiness', 'Relationship Shifts']
};

const INTERESTS_MAP = {
  '0-5': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Dolls/Cars', 'Building', 'Outdoor Play', 'Dance/Music', 'Pretend Play', 'Puzzles'],
  '6-10': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Building', 'Games', 'Technology', 'Sports', 'Nature', 'Puzzles'],
  '11-15': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Technology', 'Coding', 'Gaming', 'Debate', 'Social Media', 'Drama'],
  '16-18': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Technology', 'Coding', 'Gaming', 'Travel', 'Career', 'Fitness']
};

const Onboarding: React.FC<OnboardingProps> = ({ onComplete }) => {
  const [parentName, setParentName] = useState('');
  const [children, setChildren] = useState<Child[]>([]);
  const [step, setStep] = useState<'parent' | 'child'>('parent');
  const [tempChild, setTempChild] = useState<Partial<Child>>({ 
    name: '', 
    age: undefined, 
    challenges: [], 
    interests: [] 
  });
  const [customChallenge, setCustomChallenge] = useState('');
  const [isAddingCustom, setIsAddingCustom] = useState(false);

  const currentChallenges = useMemo(() => {
    const age = Number(tempChild.age) || 0;
    let base = [];
    if (age <= 5) base = [...CHALLENGE_MAP['0-5']];
    else if (age <= 10) base = [...CHALLENGE_MAP['6-10']];
    else if (age <= 15) base = [...CHALLENGE_MAP['11-15']];
    else base = [...CHALLENGE_MAP['16-18']];

    // Merge in any custom ones already in tempChild.challenges that aren't in base
    const customOnes = (tempChild.challenges || []).filter(c => !base.includes(c));
    return [...base, ...customOnes];
  }, [tempChild.age, tempChild.challenges]);

  const currentInterests = useMemo(() => {
    const age = Number(tempChild.age) || 0;
    if (age <= 5) return INTERESTS_MAP['0-5'];
    if (age <= 10) return INTERESTS_MAP['6-10'];
    if (age <= 15) return INTERESTS_MAP['11-15'];
    return INTERESTS_MAP['16-18'];
  }, [tempChild.age]);

  const toggleItem = (item: string, key: 'challenges' | 'interests') => {
    const current = (tempChild[key] as string[]) || [];
    setTempChild({
      ...tempChild, 
      [key]: current.includes(item) ? current.filter(i => i !== item) : [...current, item]
    });
  };

  const handleAddCustomChallenge = () => {
    if (!customChallenge.trim()) return;
    const current = (tempChild.challenges as string[]) || [];
    if (!current.includes(customChallenge.trim())) {
      setTempChild({
        ...tempChild,
        challenges: [...current, customChallenge.trim()]
      });
    }
    setCustomChallenge('');
    setIsAddingCustom(false);
  };

  const handleAddChild = () => {
    if (!tempChild.name || tempChild.age === undefined) return;
    const newChild: Child = {
      id: Math.random().toString(36).substr(2, 9),
      name: tempChild.name,
      age: Number(tempChild.age),
      challenges: tempChild.challenges || [],
      interests: tempChild.interests || []
    };
    setChildren([...children, newChild]);
    setTempChild({ name: '', age: undefined, challenges: [], interests: [] });
    setIsAddingCustom(false);
    trackEvent('child_added', { age: newChild.age });
  };

  const handleFinish = () => {
    let finalChildren = [...children];
    if (tempChild.name && tempChild.age !== undefined && !children.some(c => c.name === tempChild.name)) {
      finalChildren.push({
        id: Math.random().toString(36).substr(2, 9),
        name: tempChild.name,
        age: Number(tempChild.age),
        challenges: tempChild.challenges || [],
        interests: tempChild.interests || []
      });
    }

    onComplete({ 
      name: parentName, 
      children: finalChildren, 
      onboarded: true,
      favorites: [],
      chatHistory: [],
      logs: []
    });
  };

  return (
    <div className="min-h-screen bg-[#FDFBF7] flex items-center justify-center p-6 py-12">
      <div className="max-w-3xl w-full bg-white rounded-[3.5rem] shadow-2xl shadow-[#4E8B83]/5 p-10 md:p-14 space-y-10 border border-[#4E8B83]/10 relative overflow-hidden">
        <div className="absolute -top-12 -right-12 text-6xl opacity-5 animate-spin-slow text-[#4E8B83]">🌻</div>

        <div className="text-center space-y-4">
          <div className="flex items-center justify-center gap-6">
            <GrowingPlant className="opacity-80" />
            <h2 className="text-4xl sm:text-5xl font-bold text-[#434343] font-display tracking-tight">Mind<span className="text-[#4E8B83]">Bloom</span></h2>
            <GrowingPlant className="opacity-80 -scale-x-100" />
          </div>
          <p className="text-[#434343]/50 text-lg font-medium font-display">Gentle guidance for growing families.</p>
        </div>

        {step === 'parent' ? (
          <div className="space-y-10 animate-in fade-in zoom-in duration-500 max-w-sm mx-auto">
            <section className="space-y-4 text-center">
              <label className="text-[10px] font-bold uppercase tracking-[0.3em] text-[#4E8B83]">Welcome! What is your name?</label>
              <input
                type="text"
                value={parentName}
                onChange={(e) => setParentName(e.target.value)}
                className="w-full p-5 bg-[#FDFBF7] border-2 border-[#4E8B83]/10 rounded-3xl focus:ring-4 focus:ring-[#4E8B83]/10 outline-none text-2xl text-center font-display font-bold text-[#434343] transition-all"
                placeholder="Name"
              />
            </section>
            <button
              onClick={() => setStep('child')}
              disabled={!parentName}
              className="w-full bg-[#4E8B83] text-white p-5 rounded-3xl font-bold text-xl hover:scale-[1.02] transition-all shadow-xl shadow-[#4E8B83]/20 disabled:opacity-50 font-display"
            >
              Get Started →
            </button>
          </div>
        ) : (
          <div className="space-y-10 animate-in fade-in duration-500">
            {children.length > 0 && (
              <div className="space-y-3 text-center">
                <p className="text-[8px] font-bold text-[#4E8B83] uppercase tracking-[0.2em]">Your Bloom List</p>
                <div className="flex flex-wrap justify-center gap-2">
                  {children.map(c => (
                    <div key={c.id} className="bg-[#E8F1F0] text-[#4E8B83] px-5 py-2 rounded-full text-xs font-bold border border-[#4E8B83]/10">
                      {c.name} ({c.age})
                    </div>
                  ))}
                </div>
              </div>
            )}

            <section className="space-y-8">
              <h3 className="text-3xl font-bold text-[#434343] font-display text-center">
