// Helper for exponential backoff to handle 429 errors (Quota Exceeded)
const retryWithBackoff = async <T>(fn: () => Promise<T>, retries = 3, delay = 1000): Promise<T> => {
  try {
    return await fn();
  } catch (error: any) {
    const isRetryable = error?.message?.includes('429') || error?.status === 429 || error?.message?.includes('RESOURCE_EXHAUSTED');
    if (isRetryable && retries > 0) {
      await new Promise(resolve => setTimeout(resolve, delay));
      return retryWithBackoff(fn, retries - 1, delay * 2);
    }
    throw error;
  }
};

/**
 * Specialist at MindBloom. Quick help for parenting challenges.
 */
export const getChallengeAdvice = async (child: Child, challenge: string): Promise<DailyTip> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const interestsContext = child.interests.length > 0 ? `Interests: ${child.interests.join(', ')}.` : "";

  return retryWithBackoff(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `MindBloom Specialist. Context: ${child.age}yo child, ${interestsContext} Challenge: "${challenge}". 
      Provide JSON: {title, content, activity, script, details}. Keep content/activity brief.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            content: { type: Type.STRING },
            activity: { type: Type.STRING },
            script: { type: Type.STRING },
            details: { type: Type.STRING },
          },
          required: ["title", "content", "activity", "details"],
        },
      },
    });
    return JSON.parse(response.text || "{}") as DailyTip;
  });
};

/**
 * Fetches a very short one-liner tip for the dashboard.
 */
export const getDailyOneLiner = async (child: Child, challenge: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  return retryWithBackoff(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `MindBloom Tip. Parent of ${child.age}yo, "${challenge}". 1 short supportive sentence (<10 words). No punctuation at end.`,
    });
    return response.text?.replace(/"/g, '').replace(/\.$/, '') || "Breathe deeply; you are enough";
  });
};

/**
 * AI Coaching Chat with history context.
 * Optimized for readability: extreme brevity and structure.
 */
export const getAiChatResponse = async (history: {role: string, content: string}[], message: string, children: Child[]) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const childContext = children.map(c => `${c.name} (${c.age})`).join(", ");

  return retryWithBackoff(async () => {
    const chat = ai.chats.create({
      model: "gemini-3-flash-preview",
      config: {
        systemInstruction: `MindBloom Coach. 
        GOAL: Provide compassionate, ultra-concise support.
        RULES:
        - MAXIMUM 75 WORDS.
        - Start with 1 empathetic sentence.
        - Use a bulleted list (max 3 items) for actionable steps.
        - Include exactly ONE short script ("Say: ...").
        - No long paragraphs to minimize user scrolling.
        Context: children ${childContext}.`,
      }
    });
    const result = await chat.sendMessage({ message });
    return result.text || "";
  });
};

