// Helper for exponential backoff to handle 429 errors (Quota Exceeded)
const retryWithBackoff = async <T>(fn: () => Promise<T>, retries = 3, delay = 1000): Promise<T> => {
  try {
    return await fn();
  } catch (error: any) {
    const isRetryable = error?.message?.includes('429') || error?.status === 429 || error?.message?.includes('RESOURCE_EXHAUSTED');
    if (isRetryable && retries > 0) {
      await new Promise(resolve => setTimeout(resolve, delay));
      return retryWithBackoff(fn, retries - 1, delay * 2);
    }
    throw error;
  }
};

/**
 * Specialist at MindBloom. Quick help for parenting challenges.
 * Personalized using parentName and childName.
 */
export const getChallengeAdvice = async (parentName: string, child: Child, challenge: string): Promise<DailyTip> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const interestsContext = child.interests.length > 0 ? `Interests: ${child.interests.join(', ')}.` : "";

  return retryWithBackoff(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `MindBloom Specialist. 
      Parent: ${parentName}. Child: ${child.name} (${child.age}yo). 
      ${interestsContext} 
      Challenge: "${challenge}". 
      PERSONALIZATION: Directly address ${parentName} and use ${child.name}'s name in the content. 
      Provide JSON: {title, content, activity, script, details}. Keep content/activity brief.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            content: { type: Type.STRING },
            activity: { type: Type.STRING },
            script: { type: Type.STRING },
            details: { type: Type.STRING },
          },
          required: ["title", "content", "activity", "details"],
        },
      },
    });
    return JSON.parse(response.text || "{}") as DailyTip;
  });
};

