import React, { useState } from 'react';
import { UserProfile, Child, RightNowAdvice, FavoriteItem } from '../types';
import { getRightNowAdvice } from '../services/gemini';
import { trackEvent } from '../services/analytics';

interface Props {
  profile: UserProfile;
  onUpdateProfile: (profile: UserProfile) => void;
  onBack: () => void;
}

const RightNowView: React.FC<Props> = ({ profile, onUpdateProfile, onBack }) => {
  const [selectedChild, setSelectedChild] = useState<Child>(profile.children[0]);
  const [selectedChallenge, setSelectedChallenge] = useState<string>('');
  const [advice, setAdvice] = useState<RightNowAdvice | null>(null);
  const [loading, setLoading] = useState(false);
  const [expandedStep, setExpandedStep] = useState<number | null>(null);

  const handleActionRequest = async (challenge: string) => {
    setSelectedChallenge(challenge);
    setLoading(true);
    setAdvice(null);
    setExpandedStep(null);
    trackEvent('right_now_request', { challenge, childAge: selectedChild.age });
    try {
      const res = await getRightNowAdvice(profile.name, selectedChild, challenge);
      setAdvice(res);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const saveToFavorites = () => {
    if (!advice) return;
    const content = `1. ${advice.step1}\n2. ${advice.step2}\n3. ${advice.step3}`;
    const newItem: FavoriteItem = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'right_now',
      title: `Emergency: ${selectedChallenge}`,
      content,
      childContext: `${selectedChild.name} (Age ${selectedChild.age})`,
      dateSaved: new Date().toISOString()
    };
    onUpdateProfile({ ...profile, favorites: [...profile.favorites, newItem] });
    trackEvent('favorite_saved', { type: 'right_now' });
    alert("Saved to your Bloom List!");
  };

  return (
    <div className="max-w-4xl mx-auto py-6 space-y-10 animate-in fade-in duration-500">
      <div className="flex justify-between items-center">
        <button onClick={onBack} className="text-[#4E8B83] font-bold flex items-center gap-3 hover:translate-x-[-4px] transition-transform font-display text-lg uppercase tracking-wider">
          <span className="text-2xl">←</span> Back
        </button>
        <div className="flex bg-white p-1.5 rounded-full card-shadow border border-[#4E8B83]/10">
          {profile.children.map(c => (
            <button
              key={c.id}
              onClick={() => { setSelectedChild(c); setAdvice(null); }}
              className={`px-6 py-2 rounded-full text-[11px] font-bold transition-all ${
                selectedChild.id === c.id 
                ? 'bg-[#4E8B83] text-white shadow-md' 
                : 'text-[#434343]/50 hover:text-[#4E8B83]'
              }`}
            >
              {c.name}
            </button>
          ))}
        </div>
      </div>

      <div className="text-center space-y-4">
        <h2 className="text-4xl md:text-6xl font-black text-[#434343] font-display tracking-tight">Rapid Action Plan</h2>
        <p className="text-[#434343]/50 font-bold uppercase tracking-widest text-[11px]">3 steps. Zero fluff. For {selectedChild.name}.</p>
      </div>

      {!advice && !loading && (
        <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
          {selectedChild.challenges.map(c => (
            <button
              key={c}
              onClick={() => handleActionRequest(c)}
              className="bg-white p-6 rounded-[2rem] card-shadow border border-[#4E8B83]/10 text-[#434343] font-bold hover:bg-[#4E8B83] hover:text-white transition-all text-center flex items-center justify-center min-h-[100px]"
            >
              {c}
            </button>
          ))}
        </div>
      )}

      {loading && (
        <div className="h-64 flex flex-col items-center justify-center gap-4">
          <div className="w-16 h-16 border-8 border-[#4E8B83]/10 border-t-[#4E8B83] rounded-full animate-spin"></div>
          <p className="text-[#4E8B83] font-black uppercase tracking-widest animate-pulse">Building Action Plan...</p>
        </div>
      )}

      {advice && (
        <div className="space-y-6 animate-in slide-in-from-bottom-10 duration-700">
          {[
            { step: advice.step1, detail: advice.detail1, num: 1 },
            { step: advice.step2, detail: advice.detail2, num: 2 },
            { step: advice.step3, detail: advice.detail3, num: 3 },
          ].map((item) => (
            <div key={item.num} className="bg-white rounded-[2.5rem] card-shadow border border-[#4E8B83]/5 overflow-hidden">
              <div 
                className={`p-8 md:p-10 flex items-center justify-between cursor-pointer group transition-colors ${expandedStep === item.num ? 'bg-[#E8F1F0]/30' : 'hover:bg-[#FDFBF7]'}`}
                onClick={() => setExpandedStep(expandedStep === item.num ? null : item.num)}
              >
                <div className="flex items-center gap-6">
                  <div className="w-12 h-12 bg-[#4E8B83] text-white rounded-full flex items-center justify-center text-xl font-black shadow-lg shadow-[#4E8B83]/20">
                    {item.num}
                  </div>
                  <h4 className="text-2xl md:text-3xl font-bold font-display text-[#434343]">{item.step}</h4>
                </div>
                <div className={`text-[#4E8B83] font-bold text-xs uppercase tracking-widest transition-all ${expandedStep === item.num ? 'rotate-180' : ''}`}>
                  {expandedStep === item.num ? 'Hide Info' : 'More Details'}
                </div>
              </div>
              {expandedStep === item.num && (
                <div className="px-10 pb-10 animate-in fade-in slide-in-from-top-4 duration-400">
                  <div className="p-6 bg-[#FDFBF7] rounded-[1.5rem] border border-[#4E8B83]/10 font-display text-xl text-[#434343]/70 leading-relaxed">
                    {item.detail}
                  </div>
                </div>
              )}
            </div>
          ))}

          <div className="flex flex-col sm:flex-row gap-4 pt-4">
            <button 
              onClick={saveToFavorites}
              className="flex-1 bg-white border-2 border-[#4E8B83] text-[#4E8B83] py-5 rounded-[2rem] font-bold font-display text-xl hover:bg-[#E8F1F0] transition-all"
            >
              ⭐ Save This Plan
            </button>
            <button 
              onClick={() => { setAdvice(null); setSelectedChallenge(''); }}
              className="flex-1 bg-[#4E8B83] text-white py-5 rounded-[2rem] font-bold font-display text-xl shadow-xl shadow-[#4E8B83]/20 hover:opacity-90 transition-all"
            >
              Done / New Plan
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

