        <div className="h-64 flex flex-col items-center justify-center gap-4">
          <div className="w-16 h-16 border-8 border-[#4E8B83]/10 border-t-[#4E8B83] rounded-full animate-spin"></div>
          <p className="text-[#4E8B83] font-black uppercase tracking-widest animate-pulse">Building Action Plan...</p>
        </div>
      )}

      {advice && (
        <div className="space-y-6 animate-in slide-in-from-bottom-10 duration-700">
          {[
            { step: advice.step1, detail: advice.detail1, num: 1 },
            { step: advice.step2, detail: advice.detail2, num: 2 },
