import { GoogleGenAI, Type } from "@google/genai";
import { Child, DailyTip, RightNowAdvice } from "../types";

// Helper for exponential backoff to handle 429 errors (Quota Exceeded)
const retryWithBackoff = async <T>(fn: () => Promise<T>, retries = 3, delay = 1000): Promise<T> => {
  try {
    return await fn();
  } catch (error: any) {
    const isRetryable = error?.message?.includes('429') || error?.status === 429 || error?.message?.includes('RESOURCE_EXHAUSTED');
    if (isRetryable && retries > 0) {
      await new Promise(resolve => setTimeout(resolve, delay));
      return retryWithBackoff(fn, retries - 1, delay * 2);
    }
    throw error;
  }
};

/**
 * Specialist at MindBloom. Quick help for parenting challenges.
 * Personalized using parentName and childName.
 */
export const getChallengeAdvice = async (parentName: string, child: Child, challenge: string): Promise<DailyTip> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const interestsContext = child.interests.length > 0 ? `Interests: ${child.interests.join(', ')}.` : "";

  return retryWithBackoff(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `MindBloom Specialist. 
      Parent: ${parentName}. Child: ${child.name} (${child.age}yo). 
      ${interestsContext} 
      Challenge: "${challenge}". 

      INSTRUCTIONS:
      1. PERSONALIZATION: Directly address ${parentName} and use ${child.name}'s name throughout the content.
      2. CONTENT: Provide a gentle, expert-led psychological strategy.
      3. SCRIPT: Provide a short, actionable verbal script for the parent to say.
      4. ACTIVITY: Provide a specific, named bonding activity.
      5. DETAILS: Provide a COMPREHENSIVE, step-by-step breakdown of exactly how to perform the activity, including any materials needed. Do not be generic.

      Provide JSON: {title, content, activity, script, details}.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            content: { type: Type.STRING },
            activity: { type: Type.STRING },
            script: { type: Type.STRING },
            details: { type: Type.STRING },
          },
          required: ["title", "content", "activity", "script", "details"],
        },
      },
    });
    return JSON.parse(response.text || "{}") as DailyTip;
  });
};

