                    onClick={() => handleFeedback(val)}
                    className="px-8 py-3 rounded-full bg-[#FDFBF7] border-2 border-gray-100 text-[11px] font-bold text-[#4E8B83] hover:bg-[#4E8B83] hover:text-white transition-all active:scale-95 shadow-sm font-display"
                  >
                    {val}
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>
      </Modal>
    </div>
  );
};

