                {isSaved('advice', advice?.content || '') ? 'Saved ⭐' : 'Save'}
              </button>
            </div>
            <div className="p-8 bg-white border-x border-b border-[#4E8B83]/10 rounded-b-[2.5rem] shadow-sm">
