      setShowMainModal(true);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleAddCustomChallenge = () => {
    if (!newChallengeInput.trim()) {
      setIsAddingChallenge(false);
      return;
    }

    const trimmedChallenge = newChallengeInput.trim();
    if (selectedChild.challenges.includes(trimmedChallenge)) {
      setNewChallengeInput('');
      setIsAddingChallenge(false);
      return;
    }

    const updatedChildren = profile.children.map(c => {
      if (c.id === selectedChild.id) {
        return { ...c, challenges: [...c.challenges, trimmedChallenge] };
      }
      return c;
    });

    const updatedChild = updatedChildren.find(c => c.id === selectedChild.id)!;
    onUpdateProfile({ ...profile, children: updatedChildren });
    setSelectedChild(updatedChild);
    setNewChallengeInput('');
    setIsAddingChallenge(false);
  };

  const saveToFavorites = (type: 'advice' | 'script' | 'activity', content: string) => {
    const key = `${type}-${content.substring(0, 10)}`;
    if (savedItems.has(key)) return;

    const newItem: FavoriteItem = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      title: `${selectedChallenge} (${type})`,
      content,
      childContext: `${selectedChild.name} (Age ${selectedChild.age})`,
      dateSaved: new Date().toISOString()
    };

    onUpdateProfile({ ...profile, favorites: [...profile.favorites, newItem] });
    setSavedItems(prev => new Set(prev).add(key));
  };

  const isSaved = (type: string, content: string) => {
    const key = `${type}-${content.substring(0, 10)}`;
    return savedItems.has(key);
  };

  // Renders text with clickable glossary terms
  // Use React.ReactNode instead of JSX.Element to avoid namespace issues and handle recursive replacement correctly
  const TextWithGlossary = ({ text }: { text?: string }) => {
    if (!text || !advice?.glossary) return <p className={displayFontClass}>{text}</p>;

    let parts: React.ReactNode[] = [text];
    advice.glossary.forEach(item => {
      const newParts: React.ReactNode[] = [];
      parts.forEach(part => {
        if (typeof part !== 'string') {
          newParts.push(part);
          return;
        }
        const regex = new RegExp(`(${item.term})`, 'gi');
        const split = part.split(regex);
        split.forEach(s => {
          if (s.toLowerCase() === item.term.toLowerCase()) {
            newParts.push(
              <span 
                key={`${item.term}-${Math.random()}`}
                onClick={() => setActiveDefinition(item)}
                className="cursor-help border-b-2 border-dashed border-[#F7A072] text-[#F7A072] font-bold hover:bg-[#F7A072]/10 transition-colors px-0.5 rounded"
              >
                {s}
              </span>
            );
          } else if (s) {
            newParts.push(s);
          }
        });
      });
      parts = newParts;
    });

    return <p className={displayFontClass}>{parts}</p>;
  };

  const displayFontClass = "font-display font-medium text-lg md:text-xl leading-relaxed text-[#434343]";

  return (
    <div className="space-y-8 max-w-5xl mx-auto py-4">
      <div className="px-4">
        <button onClick={onBack} className="text-[#4E8B83] font-bold flex items-center gap-3 hover:translate-x-[-4px] transition-transform font-display text-lg uppercase tracking-wider">
          <span className="text-2xl">←</span> Back
        </button>
      </div>

      <div className="bg-white p-8 md:p-12 rounded-[3.5rem] card-shadow border border-[#4E8B83]/10 min-h-[60vh] flex flex-col items-center justify-start space-y-12 animate-in fade-in duration-500">

        {/* IMPROVED CHILD SELECTION UI */}
        <div className="w-full flex flex-col items-center gap-8">
           <div className="flex flex-col items-center gap-4 w-full">
             <div className="h-1 w-24 bg-[#F7A072] rounded-full"></div>
             <span className="text-sm font-black text-[#F7A072] uppercase tracking-[0.4em]">Who are we blooming with?</span>
             <div className="flex flex-wrap justify-center bg-[#FDFBF7] p-4 rounded-[3rem] card-shadow border-2 border-[#F7A072]/20 gap-3 max-w-2xl">
                {profile.children.map(c => (
                  <button
                    key={c.id}
                    onClick={() => setSelectedChild(c)}
                    className={`px-12 py-5 rounded-[1.5rem] text-sm font-black transition-all transform hover:scale-[1.02] active:scale-95 ${
                      selectedChild.id === c.id 
                      ? 'bg-[#F7A072] text-white shadow-xl shadow-[#F7A072]/30 scale-110' 
                      : 'bg-white text-[#434343]/30 hover:text-[#F7A072] border border-[#F7A072]/5'
                    }`}
                  >
                    {c.name}
                  </button>
                ))}
             </div>
           </div>

          <header className="text-center space-y-4 pt-4">
            <h2 className="text-4xl md:text-6xl font-bold text-[#434343] font-display">Pick a Challenge</h2>
            <p className="text-[#434343]/50 font-medium text-lg max-w-lg mx-auto">Choose an area where {selectedChild.name} could use support.</p>
          </header>
        </div>

        <div className="w-full max-w-4xl grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-4">
          {selectedChild.challenges.map(c => (
            <button
              key={c}
              disabled={loading}
              onClick={() => handleChallengeClick(c)}
              className="px-4 py-8 rounded-[2rem] text-sm font-bold bg-[#FDFBF7] border border-[#4E8B83]/10 text-[#4E8B83] hover:bg-[#4E8B83] hover:text-white transition-all transform hover:-translate-y-1 shadow-sm flex items-center justify-center text-center leading-snug"
            >
              {c}
            </button>
          ))}

          {isAddingChallenge ? (
            <div className="col-span-2 flex items-center gap-2 animate-in slide-in-from-right-2 duration-300">
              <input
                autoFocus
                type="text"
                value={newChallengeInput}
                onChange={(e) => setNewChallengeInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleAddCustomChallenge()}
                placeholder="What's the challenge?"
                className="flex-1 px-6 py-5 rounded-[2rem] text-sm font-bold border-2 border-[#F7A072] outline-none text-[#434343] shadow-inner"
              />
              <button 
                onClick={handleAddCustomChallenge}
                className="w-14 h-14 bg-[#F7A072] text-white rounded-2xl flex items-center justify-center font-bold"
              >✓</button>
            </div>
          ) : (
            <button
              onClick={() => setIsAddingChallenge(true)}
              className="px-4 py-8 rounded-[2rem] text-sm font-bold border-2 border-dashed border-[#F7A072]/40 text-[#F7A072] hover:bg-[#F7A072]/5 transition-all flex items-center justify-center text-center"
