const retryWithBackoff = async <T>(fn: () => Promise<T>, retries = 3, delay = 1000): Promise<T> => {
  try {
    return await fn();
  } catch (error: any) {
    const isRetryable = error?.message?.includes('429') || error?.status === 429 || error?.message?.includes('RESOURCE_EXHAUSTED');
    if (isRetryable && retries > 0) {
      await new Promise(resolve => setTimeout(resolve, delay));
      return retryWithBackoff(fn, retries - 1, delay * 2);
    }
    throw error;
  }
};

export const getChallengeAdvice = async (parentName: string, child: Child, challenge: string): Promise<DailyTip> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const interestsContext = child.interests.length > 0 ? `Interests: ${child.interests.join(', ')}.` : "";

  return retryWithBackoff(async () => {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `MindBloom Specialist. 
      Parent: ${parentName}. Child: ${child.name} (${child.age}yo). 
      ${interestsContext} 
      Challenge: "${challenge}". 

      INSTRUCTIONS:
      1. LANGUAGE: Use extremely simple, clear language (5th-grade level). Avoid jargon.
      2. PERSONALIZATION: Address ${parentName} directly. Use ${child.name}'s name often.
      3. CONTENT: A gentle psychology strategy.
      4. SCRIPT: Exactly what ${parentName} should say to ${child.name}.
      5. ACTIVITY: A named bonding game.
      6. DETAILS: STEP-BY-STEP breakdown of the activity. Be thorough.
      7. GLOSSARY: If you use any semi-complex words (like 'amygdala', 'boundaries', 'regulation'), include them in the glossary array with a tiny, friendly definition.

      Provide JSON: {title, content, activity, script, details, glossary: [{term, definition}]}.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            content: { type: Type.STRING },
            activity: { type: Type.STRING },
            script: { type: Type.STRING },
            details: { type: Type.STRING },
            glossary: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  term: { type: Type.STRING },
                  definition: { type: Type.STRING }
                },
                required: ["term", "definition"]
              }
            }
          },
          required: ["title", "content", "activity", "script", "details"],
        },
      },
    });
    return JSON.parse(response.text || "{}") as DailyTip;
  });
};

