import React, { useState } from 'react';
import { UserProfile, Child, RightNowAdvice, FavoriteItem } from '../types';
import { getRightNowAdvice } from '../services/gemini';
import { trackEvent } from '../services/analytics';

interface Props {
  profile: UserProfile;
  onUpdateProfile: (profile: UserProfile) => void;
  onBack: () => void;
}

const RightNowView: React.FC<Props> = ({ profile, onUpdateProfile, onBack }) => {
  const [selectedChild, setSelectedChild] = useState<Child>(profile.children[0]);
  const [selectedChallenge, setSelectedChallenge] = useState<string>('');
  const [advice, setAdvice] = useState<RightNowAdvice | null>(null);
  const [loading, setLoading] = useState(false);
  const [expandedStep, setExpandedStep] = useState<number | null>(null);
  const [activeDefinition, setActiveDefinition] = useState<{term: string, definition: string} | null>(null);

  const handleActionRequest = async (challenge: string) => {
    setSelectedChallenge(challenge);
    setLoading(true);
    setAdvice(null);
    setExpandedStep(null);
    setActiveDefinition(null);
    trackEvent('right_now_request', { challenge, childAge: selectedChild.age });
    try {
      const res = await getRightNowAdvice(profile.name, selectedChild, challenge);
      setAdvice(res);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const saveToFavorites = () => {
    if (!advice) return;
    const content = `1. ${advice.step1}: ${advice.summary1}\n2. ${advice.step2}: ${advice.summary2}\n3. ${advice.step3}: ${advice.summary3}`;
    const newItem: FavoriteItem = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'right_now',
      title: `Action Plan: ${selectedChallenge}`,
      content,
      childContext: `${selectedChild.name} (Age ${selectedChild.age})`,
      dateSaved: new Date().toISOString()
    };
    onUpdateProfile({ ...profile, favorites: [...profile.favorites, newItem] });
    trackEvent('favorite_saved', { type: 'right_now' });
    alert("Saved to your Bloom List!");
  };

  const TextWithGlossary = ({ text, className }: { text?: string, className?: string }) => {
    if (!text || !advice?.glossary) return <p className={className}>{text}</p>;

    let parts: React.ReactNode[] = [text];
    advice.glossary.forEach(item => {
      const newParts: React.ReactNode[] = [];
      parts.forEach(part => {
        if (typeof part !== 'string') {
          newParts.push(part);
          return;
        }
        const regex = new RegExp(`(${item.term})`, 'gi');
        const split = part.split(regex);
        split.forEach(s => {
          if (s.toLowerCase() === item.term.toLowerCase()) {
            newParts.push(
              <span 
                key={`${item.term}-${Math.random()}`}
                onClick={(e) => { e.stopPropagation(); setActiveDefinition(item); }}
                className="cursor-help border-b-2 border-dashed border-[#F4B6A6] text-[#F4B6A6] font-bold hover:bg-[#F4B6A6]/10 transition-colors px-0.5 rounded"
              >
                {s}
              </span>
            );
          } else if (s) {
            newParts.push(s);
          }
        });
      });
      parts = newParts;
    });

    return <p className={className}>{parts}</p>;
  };

  return (
    <div className="max-w-4xl mx-auto py-6 space-y-10 animate-in fade-in duration-500 relative">

      {/* GLOSSARY TOOLTIP */}
      {activeDefinition && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-6 bg-black/20 backdrop-blur-sm" onClick={() => setActiveDefinition(null)}>
          <div className="bg-[#5B5450] text-white p-8 rounded-[3rem] shadow-2xl relative border-2 border-[#F4B6A6]/30 max-w-sm" onClick={e => e.stopPropagation()}>
            <button onClick={() => setActiveDefinition(null)} className="absolute top-4 right-4 text-white/50 hover:text-white">✕</button>
            <h5 className="font-display font-bold text-[#F4B6A6] uppercase text-xs tracking-[0.3em] mb-2">{activeDefinition.term}</h5>
            <p className="text-base font-medium leading-relaxed">{activeDefinition.definition}</p>
          </div>
        </div>
      )}

      <div className="flex justify-between items-center px-4">
        <button onClick={onBack} className="text-[#C6B7E2] font-bold flex items-center gap-3 hover:translate-x-[-4px] transition-transform font-display text-lg uppercase tracking-wider">
          <span className="text-2xl">←</span> Back
        </button>
      </div>

      <div className="flex flex-col items-center gap-8 bg-white p-10 rounded-[4rem] card-shadow border border-[#F4B6A6]/10">

        {/* PROMINENT CHILD SELECTION AT TOP */}
        <div className="flex flex-col items-center gap-4 w-full">
          <span className="text-xs font-black text-[#F4B6A6] uppercase tracking-[0.4em]">Who needs an action plan?</span>
          <div className="flex flex-wrap justify-center bg-[#FFF6EB] p-4 rounded-[3rem] border-2 border-[#C6B7E2]/10 gap-3 shadow-inner">
            {profile.children.map(c => (
              <button
                key={c.id}
                onClick={() => { setSelectedChild(c); setAdvice(null); }}
                className={`px-10 py-4 rounded-2xl text-sm font-black transition-all transform hover:scale-[1.02] active:scale-95 shadow-sm ${
                  selectedChild.id === c.id 
                  ? 'bg-[#F4B6A6] text-white shadow-xl shadow-[#F4B6A6]/30 scale-105' 
                  : 'bg-white text-[#5B5450]/30 hover:text-[#F4B6A6] border border-[#F4B6A6]/5'
                }`}
              >
                {c.name}
              </button>
            ))}
          </div>
        </div>

        <div className="text-center space-y-4">
          <h2 className="text-4xl md:text-6xl font-black text-[#5B5450] font-display tracking-tight leading-tight">Rapid Action Plan</h2>
          <p className="text-[#5B5450]/50 font-bold uppercase tracking-[0.3em] text-[11px]">3 steps. Zero fluff. Just gentle focus for {selectedChild.name}.</p>
        </div>

        {!advice && !loading && (
          <div className="grid grid-cols-2 md:grid-cols-3 gap-4 w-full pt-4">
            {selectedChild.challenges.map(c => (
              <button
                key={c}
                onClick={() => handleActionRequest(c)}
                className="bg-white p-6 rounded-[2.5rem] border-2 border-[#C6B7E2]/10 text-[#5B5450] font-bold hover:bg-[#C6B7E2] hover:text-white transition-all text-center flex items-center justify-center min-h-[140px] shadow-sm hover:shadow-lg font-display text-lg"
              >
                {c}
              </button>
            ))}
          </div>
        )}

        {loading && (
          <div className="h-64 flex flex-col items-center justify-center gap-6">
            <div className="w-16 h-16 border-8 border-[#F4B6A6]/10 border-t-[#F4B6A6] rounded-full animate-spin"></div>
            <p className="text-[#F4B6A6] font-black uppercase tracking-widest animate-pulse">Building Your Gentle Plan...</p>
          </div>
        )}

        {advice && (
          <div className="space-y-6 w-full animate-in slide-in-from-bottom-10 duration-700">
            {[
              { step: advice.step1, summary: advice.summary1, detail: advice.detail1, num: 1 },
              { step: advice.step2, summary: advice.summary2, detail: advice.detail2, num: 2 },
              { step: advice.step3, summary: advice.summary3, detail: advice.detail3, num: 3 },
            ].map((item) => (
              <div key={item.num} className="bg-white rounded-[3.5rem] border-2 border-[#F4B6A6]/5 overflow-hidden shadow-sm hover:shadow-md transition-shadow">
                <div 
                  className={`p-8 md:p-12 flex flex-col md:flex-row items-start md:items-center justify-between cursor-pointer group transition-colors ${expandedStep === item.num ? 'bg-[#F4B6A6]/5' : 'hover:bg-[#FFF6EB]/40'}`}
                  onClick={() => setExpandedStep(expandedStep === item.num ? null : item.num)}
                >
                  <div className="flex items-start gap-8">
                    <div className="w-16 h-16 bg-[#F4B6A6] text-white rounded-[1.5rem] flex items-center justify-center text-3xl font-black shadow-lg shadow-[#F4B6A6]/20 flex-shrink-0">
                      {item.num}
                    </div>
                    <div className="space-y-2">
                      <h4 className="text-2xl md:text-3xl font-black font-display text-[#5B5450]">{item.step}</h4>
                      <TextWithGlossary text={item.summary} className="text-lg md:text-xl font-medium text-[#5B5450]/60 leading-relaxed font-display" />
                    </div>
                  </div>
                  <div className={`mt-6 md:mt-0 text-[#F4B6A6] font-black text-xs uppercase tracking-[0.3em] transition-all bg-white/50 px-6 py-3 rounded-full border border-[#F4B6A6]/10 group-hover:bg-[#F4B6A6] group-hover:text-white ${expandedStep === item.num ? 'bg-[#F4B6A6] text-white' : ''}`}>
                    {expandedStep === item.num ? 'Hide Details' : 'See Full Details'}
                  </div>
                </div>
                {expandedStep === item.num && (
                  <div className="px-10 pb-10 animate-in fade-in slide-in-from-top-4 duration-400">
                    <div className="p-10 bg-[#FFF6EB] rounded-[2.5rem] border border-[#F4B6A6]/10 shadow-inner">
                       <h6 className="text-xs font-black text-[#F4B6A6] uppercase tracking-[0.4em] mb-6">Detailed Strategy:</h6>
                       <div className="font-display text-lg md:text-2xl text-[#5B5450] leading-relaxed whitespace-pre-wrap">
                          <TextWithGlossary text={item.detail} />
                       </div>
                    </div>
                  </div>
                )}
              </div>
            ))}

            <div className="bg-[#FFF6EB] p-12 rounded-[3.5rem] border border-[#F4B6A6]/10 text-center space-y-6">
              <p className="text-[#F4B6A6] font-bold font-display text-2xl leading-relaxed">
                “This was quick help for right now. For long-term ideas, try Help my child.”
              </p>
              <div className="h-1.5 w-16 bg-[#F4B6A6]/20 mx-auto rounded-full"></div>
            </div>

            <div className="flex flex-col sm:flex-row gap-4 pt-6">
              <button 
                onClick={saveToFavorites}
                className="flex-1 bg-white border-2 border-[#C6B7E2] text-[#C6B7E2] py-6 rounded-[2.5rem] font-black font-display text-xl hover:bg-[#C6B7E2]/10 transition-all shadow-sm"
              >
                ⭐ Save This Plan
              </button>
              <button 
                onClick={() => { setAdvice(null); setSelectedChallenge(''); }}
                className="flex-1 bg-[#C6B7E2] text-white py-6 rounded-[2.5rem] font-black font-display text-xl shadow-xl shadow-[#C6B7E2]/30 hover:scale-[1.02] transition-transform"
              >
                Done / New Plan
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default RightNowView;

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { UserProfile, ChatMessage, FavoriteItem } from '../types';
import { getAiChatResponse } from '../services/gemini';
import { trackEvent } from '../services/analytics';

interface Props {
  profile: UserProfile;
  onUpdateProfile: (profile: UserProfile) => void;
  onBack: () => void;
}

const CoachAIView: React.FC<Props> = ({ profile, onUpdateProfile, onBack }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [profile.chatHistory, loading]);

  const pastUserQuestions = useMemo(() => {
    return profile.chatHistory
      .filter(m => m.role === 'user')
      .slice(-6)
      .reverse();
  }, [profile.chatHistory]);

  const handleSend = async (customText?: string) => {
    const textToSend = customText || input;
    if (!textToSend.trim() || loading) return;

    setError(null);
    const userMsg: ChatMessage = { 
      role: 'user', 
      content: textToSend, 
      timestamp: new Date().toISOString() 
    };

    const updatedHistory = [...profile.chatHistory, userMsg];
    onUpdateProfile({ ...profile, chatHistory: updatedHistory });
    setInput('');
    setLoading(true);
    trackEvent('coach_query', { length: textToSend.length });

    try {
      const resText = await getAiChatResponse(updatedHistory.map(m => ({ role: m.role, content: m.content })), textToSend, profile.children);
      const aiMsg: ChatMessage = { 
        role: 'assistant', 
        content: resText, 
        timestamp: new Date().toISOString() 
      };
      onUpdateProfile({ ...profile, chatHistory: [...updatedHistory, aiMsg] });
    } catch (e: any) {
      console.error(e);
      const msg = e.message?.includes('429') ? "MindBloom is very busy right now. Please wait a moment and try again." : "Something went wrong. Please check your connection.";
      setError(msg);
    } finally {
      setLoading(false);
    }
  };

  const saveToFavorites = (content: string) => {
    const newItem: FavoriteItem = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'advice',
      title: "Coach Insight",
      content,
      dateSaved: new Date().toISOString()
    };
    onUpdateProfile({ ...profile, favorites: [...profile.favorites, newItem] });
    trackEvent('favorite_saved', { type: 'coach_advice' });
  };

  const clearHistory = () => {
    if (confirm("Reset conversation history?")) {
      onUpdateProfile({ ...profile, chatHistory: [] });
    }
  };

  return (
    <div className="max-w-4xl mx-auto py-2 flex flex-col h-[85vh]">
      <div className="flex justify-between items-center mb-6 px-6">
        <button onClick={onBack} className="text-[#F4B6A6] font-bold flex items-center gap-2 font-display text-lg uppercase tracking-wider group">
          <span className="text-xl transition-transform group-hover:-translate-x-1">←</span> Home
        </button>
        <div className="flex items-center gap-6">
          {profile.chatHistory.length > 0 && (
            <button 
              onClick={clearHistory}
              className="text-[10px] font-bold text-[#5B5450]/30 hover:text-red-400 uppercase tracking-widest transition-colors"
            >
              Clear
            </button>
          )}
          <h2 className="text-3xl font-bold text-[#5B5450] font-display">Coach AI</h2>
        </div>
      </div>

      <div className="flex-1 bg-white rounded-[3rem] card-shadow border border-[#F4B6A6]/10 overflow-hidden flex flex-col">
        {pastUserQuestions.length > 0 && (
          <div className="bg-[#FFF6EB]/40 px-6 py-3 border-b border-[#F4B6A6]/10 flex items-center gap-4 overflow-x-auto no-scrollbar">
            <span className="text-[8px] font-black text-[#5B5450]/30 uppercase tracking-[0.3em] whitespace-nowrap">Past Topics:</span>
            {pastUserQuestions.map((q, i) => (
              <button 
                key={i} 
                onClick={() => handleSend(q.content)}
                className="text-[10px] font-bold bg-white border border-[#F4B6A6]/20 px-4 py-1.5 rounded-full text-[#F4B6A6] hover:bg-[#F4B6A6] hover:text-white transition-all whitespace-nowrap shadow-sm"
              >
                {q.content.length > 20 ? q.content.substring(0, 20) + '...' : q.content}
              </button>
            ))}
          </div>
        )}

        <div className="flex-1 overflow-y-auto p-8 space-y-6 scrollbar-hide">
          {profile.chatHistory.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center p-10 space-y-8">
               <div className="w-24 h-24 bg-[#FFF6EB] border-2 border-[#F4B6A6]/20 rounded-[2rem] flex items-center justify-center text-6xl animate-float shadow-xl shadow-[#F4B6A6]/5">🤖</div>
               <div className="space-y-3">
                 <p className="font-display text-3xl text-[#5B5450] font-bold">"How can I help you bloom today?"</p>
                 <p className="text-[#5B5450]/40 font-bold uppercase tracking-[0.3em] text-[10px]">Ask about scripts, tantrums, or transitions.</p>
               </div>
            </div>
          ) : (
            profile.chatHistory.map((msg, i) => (
              <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 duration-300`}>
                <div className={`max-w-[90%] md:max-w-[80%] space-y-3`}>
                  <div className={`p-6 rounded-[2rem] shadow-sm font-medium leading-relaxed text-lg ${
                    msg.role === 'user' 
                    ? 'bg-[#F4B6A6] text-white rounded-tr-none shadow-lg shadow-[#F4B6A6]/20' 
                    : 'bg-[#FFF6EB] text-[#5B5450] rounded-tl-none border border-[#C6B7E2]/20'
                  }`}>
                    <p className="whitespace-pre-wrap">{msg.content}</p>
                  </div>
                  {msg.role === 'assistant' && (
                    <button 
                      onClick={() => saveToFavorites(msg.content)} 
                      className="text-[9px] font-bold text-[#C6B7E2] uppercase tracking-widest hover:text-[#5B5450] ml-6 transition-colors flex items-center gap-2"
                    >
                      <span>⭐</span> Save to Bloom List
                    </button>
                  )}
                </div>
              </div>
            ))
          )}
          {loading && (
            <div className="flex justify-start">
              <div className="bg-[#FFF6EB] px-8 py-4 rounded-full border border-[#C6B7E2]/20 flex gap-2 items-center shadow-sm">
                <div className="w-1.5 h-1.5 bg-[#C6B7E2] rounded-full animate-bounce"></div>
                <div className="w-1.5 h-1.5 bg-[#C6B7E2] rounded-full animate-bounce [animation-delay:0.2s]"></div>
                <div className="w-1.5 h-1.5 bg-[#C6B7E2] rounded-full animate-bounce [animation-delay:0.4s]"></div>
              </div>
            </div>
          )}
          <div ref={scrollRef} />
        </div>

        <div className="p-6 md:p-10 bg-[#FFF6EB]/40 border-t border-[#F4B6A6]/10">
          <div className="flex gap-4 max-w-4xl mx-auto">
            <input
              type="text"
              className="flex-1 p-5 bg-white border border-[#C6B7E2]/20 rounded-[2rem] outline-none focus:ring-4 focus:ring-[#F4B6A6]/10 text-lg font-medium shadow-inner transition-all placeholder-[#5B5450]/30"
              placeholder="Ask me anything..."
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            />
            <button
              onClick={() => handleSend()}
              disabled={loading || !input.trim()}
              className="bg-[#F4B6A6] text-white w-14 h-14 rounded-[1.5rem] flex items-center justify-center font-bold hover:scale-105 active:scale-95 disabled:opacity-50 transition-all shadow-xl shadow-[#F4B6A6]/30"
            >
              <span className="text-3xl">→</span>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CoachAIView;

import React, { useState } from 'react';
import { getSelfCareContent } from '../services/gemini';
import { UserProfile, FavoriteItem } from '../types';
import Modal from './Modal';
import { trackEvent } from '../services/analytics';

interface Props {
  profile: UserProfile;
  onUpdateProfile: (profile: UserProfile) => void;
  onBack: () => void;
}

const SelfCareHub: React.FC<Props> = ({ profile, onUpdateProfile, onBack }) => {
  const [loadingCategory, setLoadingCategory] = useState<string | null>(null);
  const [content, setContent] = useState<{ title: string; content: string } | null>(null);
  const [feedbackGiven, setFeedbackGiven] = useState(false);

  const handleSelect = async (category: string) => {
    setLoadingCategory(category);
    setFeedbackGiven(false);
    setContent(null); 
    trackEvent('self_care_request', { category });
    try {
      const res = await getSelfCareContent(category);
      setContent(res);
    } catch (e) {
      console.error(e);
    } finally {
      setLoadingCategory(null);
    }
  };

  const saveToFavorites = () => {
    if (!content) return;
    const newItem: FavoriteItem = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'self_care',
      title: `Zen: ${content.title}`,
      content: content.content,
      dateSaved: new Date().toISOString()
    };
    onUpdateProfile({ ...profile, favorites: [...profile.favorites, newItem] });
    trackEvent('favorite_saved', { type: 'self_care' });
  };

  const handleFeedback = (val: string) => {
    setFeedbackGiven(true);
    trackEvent('self_care_feedback', { feedback: val });
  };

  const categories = [
    { label: 'Calm Down Tools', icon: '❄️', color: 'bg-white border-[#C6B7E2]/30 text-[#C6B7E2]' },
    { label: 'Grounding', icon: '🧘', color: 'bg-white border-[#F4B6A6]/30 text-[#F4B6A6]' },
    { label: 'Affirmations', icon: '✨', color: 'bg-white border-[#5B5450]/20 text-[#5B5450]' },
  ];

  return (
    <div className="max-w-3xl mx-auto py-10 space-y-10">
      <button onClick={onBack} className="text-[#C6B7E2] font-bold flex items-center gap-3 mb-4 hover:translate-x-[-4px] transition-transform font-display text-lg uppercase tracking-wider">
        <span className="text-2xl">←</span> Back
      </button>

      <div className="text-center space-y-8 bg-white p-12 rounded-[4rem] card-shadow border border-[#F4B6A6]/10">
        <div className="space-y-4">
          <h2 className="text-4xl md:text-6xl font-black text-[#5B5450] font-display tracking-tight leading-tight">Parent Safe Space</h2>
          <div className="text-[#5B5450]/60 text-lg leading-relaxed max-w-lg mx-auto font-medium">
            <p>You cannot pour from an empty cup. Take a micro-moment for your own peace.</p>
          </div>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-3 gap-6 pt-8">
          {categories.map((cat) => (
            <button
              key={cat.label}
              onClick={() => handleSelect(cat.label)}
              disabled={!!loadingCategory}
              className={`p-10 rounded-[3rem] border-2 flex flex-col items-center justify-center space-y-6 shadow-sm hover:scale-105 transition-all relative overflow-hidden group ${cat.color}`}
            >
              {loadingCategory === cat.label ? (
                <div className="flex flex-col items-center gap-4 animate-pulse">
                  <div className="w-10 h-10 border-4 border-current border-t-transparent rounded-full animate-spin"></div>
                  <span className="text-[10px] font-black uppercase tracking-[0.4em]">Finding Zen...</span>
                </div>
              ) : (
                <>
                  <span className="text-5xl group-hover:animate-float">{cat.icon}</span>
                  <span className="font-black text-xs uppercase tracking-widest leading-tight">{cat.label}</span>
                </>
              )}
            </button>
          ))}
        </div>
      </div>

      <Modal isOpen={!!content} onClose={() => setContent(null)} title={content?.title || ''}>
        <div className="text-center space-y-10 py-6">
          <div className="p-12 bg-[#FFF6EB] rounded-[3.5rem] text-2xl md:text-3xl font-display text-[#5B5450] border-2 border-[#F4B6A6]/20 shadow-inner leading-relaxed font-medium">
            {content?.content}
          </div>
          <div className="space-y-6">
            <button onClick={saveToFavorites} className="text-[#F4B6A6] font-black text-xs uppercase tracking-[0.4em] hover:underline decoration-2">⭐ Save to Bloom List</button>
            <button onClick={() => setContent(null)} className="w-full bg-[#C6B7E2] text-white py-6 rounded-[2.5rem] font-black font-display text-xl shadow-xl shadow-[#C6B7E2]/20 hover:scale-[1.02] transition-transform">I Feel Centered</button>
          </div>

          <div className="pt-8 border-t border-gray-100 space-y-6">
            <p className="text-[10px] font-black text-[#5B5450]/30 uppercase tracking-[0.5em]">Did this micro-moment help?</p>
            {feedbackGiven ? (
              <p className="text-[#F4B6A6] font-black text-xl animate-in zoom-in duration-300 uppercase tracking-widest">Thank you! 🌸</p>
            ) : (
              <div className="flex justify-center gap-4">
                {['Yes', 'Kind of', 'No'].map(val => (
                  <button 
                    key={val} 
                    onClick={() => handleFeedback(val)} 
                    className="px-10 py-3 rounded-full bg-white border-2 border-gray-100 text-xs font-black text-[#5B5450]/60 hover:bg-[#FFF6EB] hover:border-[#F4B6A6]/20 transition-all font-display"
                  >
                    {val}
                  </button>
                ))}
              </div>
            )}
          </div>
        </div>
      </Modal>
    </div>
  );
};

export default SelfCareHub;

import React, { useState, useMemo } from 'react';
import { UserProfile, Child } from '../types';
import { trackEvent } from '../services/analytics';

interface OnboardingProps {
  onComplete: (profile: UserProfile) => void;
}

const GrowingPlant = ({ className = "" }: { className?: string }) => (
  <svg width="40" height="40" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" className={`${className} animate-pulse`}>
    <path d="M12 22V10" stroke="#F4B6A6" strokeWidth="2" strokeLinecap="round"/>
    <path d="M12 18C12 18 6 18 6 13C6 10 12 10 12 18Z" fill="#F4B6A6" fillOpacity="0.4" stroke="#F4B6A6" strokeWidth="1.5"/>
    <path d="M12 14C12 14 18 14 18 9C18 6 12 6 12 14Z" fill="#C6B7E2" fillOpacity="0.7" stroke="#C6B7E2" strokeWidth="1.5"/>
  </svg>
);

const CHALLENGE_MAP = {
  '0-5': ['Big Emotions', 'Tantrums', 'Separation Anxiety', 'Listening Skills', 'Sleep Routines', 'Activity Transitions', 'Picky Eating', 'Turn Taking', 'Screen Limits', 'Independence Struggles'],
  '6-10': ['Emotional Regulation', 'Friendship Issues', 'Self Confidence', 'Homework Resistance', 'Respectful Listening', 'Disappointment Tolerance', 'Screen Balance', 'Honesty', 'Sibling Conflict', 'Teacher Expectations'],
  '11-15': ['Mood Swings', 'Peer Pressure', 'Communication Breakdown', 'Boundary Testing', 'Self Esteem', 'Motivation Struggles', 'Screen Time', 'Friend Drama', 'Authority Resistance', 'Stress Management'],
  '16-18': ['Independence Tension', 'Trust Building', 'Accountability', 'Emotional Control', 'Decision Making', 'Social Comparison', 'Time Management', 'Conflict Resolution', 'Life Readiness', 'Relationship Shifts']
};

const INTERESTS_MAP = {
  '0-5': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Dolls/Cars', 'Building', 'Outdoor Play', 'Dance/Music', 'Pretend Play', 'Puzzles'],
  '6-10': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Building', 'Games', 'Technology', 'Sports', 'Outdoor Play', 'Puzzles'],
  '11-15': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Technology', 'Coding', 'Gaming', 'Debate', 'Social Media', 'Drama'],
  '16-18': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Technology', 'Coding', 'Gaming', 'Travel', 'Career', 'Fitness']
};

const Onboarding: React.FC<OnboardingProps> = ({ onComplete }) => {
  const [parentName, setParentName] = useState('');
  const [children, setChildren] = useState<Child[]>([]);
  const [step, setStep] = useState<'parent' | 'child'>('parent');
  const [tempChild, setTempChild] = useState<Partial<Child>>({ 
    name: '', 
    age: undefined, 
    challenges: [], 
    interests: [] 
  });
  const [customChallenge, setCustomChallenge] = useState('');
  const [isAddingCustom, setIsAddingCustom] = useState(false);

  const currentChallenges = useMemo(() => {
    const age = Number(tempChild.age) || 0;
    let base = [];
    if (age <= 5) base = [...CHALLENGE_MAP['0-5']];
    else if (age <= 10) base = [...CHALLENGE_MAP['6-10']];
    else if (age <= 15) base = [...CHALLENGE_MAP['11-15']];
    else base = [...CHALLENGE_MAP['16-18']];

    const customOnes = (tempChild.challenges || []).filter(c => !base.includes(c));
    return [...base, ...customOnes];
  }, [tempChild.age, tempChild.challenges]);

  const currentInterests = useMemo(() => {
    const age = Number(tempChild.age) || 0;
    if (age <= 5) return INTERESTS_MAP['0-5'];
    if (age <= 10) return INTERESTS_MAP['6-10'];
    if (age <= 15) return INTERESTS_MAP['11-15'];
    return INTERESTS_MAP['16-18'];
  }, [tempChild.age]);

  const toggleItem = (item: string, key: 'challenges' | 'interests') => {
    const current = (tempChild[key] as string[]) || [];
    setTempChild({
      ...tempChild, 
      [key]: current.includes(item) ? current.filter(i => i !== item) : [...current, item]
    });
  };

  const handleAddCustomChallenge = () => {
    if (!customChallenge.trim()) {
      setIsAddingCustom(false);
      return;
    }
    const current = (tempChild.challenges as string[]) || [];
    if (!current.includes(customChallenge.trim())) {
      setTempChild({
        ...tempChild,
        challenges: [...current, customChallenge.trim()]
      });
    }
    setCustomChallenge('');
    setIsAddingCustom(false);
  };

  const handleAddChild = () => {
    if (!tempChild.name || tempChild.age === undefined) return;
    const newChild: Child = {
      id: Math.random().toString(36).substr(2, 9),
      name: tempChild.name,
      age: Number(tempChild.age),
      challenges: tempChild.challenges || [],
      interests: tempChild.interests || []
    };
    setChildren([...children, newChild]);
    setTempChild({ name: '', age: undefined, challenges: [], interests: [] });
    setIsAddingCustom(false);
    trackEvent('child_added', { age: newChild.age });
  };

  const handleFinish = () => {
    let finalChildren = [...children];
    if (tempChild.name && tempChild.age !== undefined && !children.some(c => c.name === tempChild.name)) {
      finalChildren.push({
        id: Math.random().toString(36).substr(2, 9),
        name: tempChild.name,
        age: Number(tempChild.age),
        challenges: tempChild.challenges || [],
        interests: tempChild.interests || []
      });
    }

    onComplete({ 
      name: parentName, 
      children: finalChildren, 
      onboarded: true,
      favorites: [],
      chatHistory: [],
      logs: []
    });
  };

  return (
    <div className="min-h-screen bg-[#FFF6EB] flex items-center justify-center p-6 py-12">
      <div className="max-w-3xl w-full bg-white rounded-[4rem] shadow-3xl shadow-[#5B5450]/5 p-10 md:p-16 space-y-12 border border-[#F4B6A6]/20 relative overflow-hidden">
        <div className="absolute -top-12 -right-12 text-6xl opacity-10 animate-spin-slow text-[#F4B6A6]">🌸</div>

        <div className="text-center space-y-4">
          <div className="flex items-center justify-center gap-8">
            <GrowingPlant />
            <h2 className="text-5xl md:text-6xl font-black text-[#5B5450] font-display tracking-tight leading-tight">Mind<span className="text-[#F4B6A6]">Bloom</span></h2>
            <GrowingPlant className="-scale-x-100" />
          </div>
          <p className="text-[#5B5450]/40 text-xl font-medium font-display uppercase tracking-[0.2em]">Gentle parenting, balanced families.</p>
        </div>

        {step === 'parent' ? (
          <div className="space-y-12 animate-in fade-in zoom-in duration-600 max-w-sm mx-auto">
            <section className="space-y-6 text-center">
              <label className="text-xs font-black uppercase tracking-[0.5em] text-[#F4B6A6]">What's your name?</label>
              <input
                type="text"
                value={parentName}
                onChange={(e) => setParentName(e.target.value)}
                className="w-full p-6 bg-[#FFF6EB] border-2 border-[#F4B6A6]/10 rounded-[2rem] focus:ring-8 focus:ring-[#F4B6A6]/5 outline-none text-3xl text-center font-display font-black text-[#5B5450] transition-all"
                placeholder="Name"
              />
            </section>
            <button
              onClick={() => setStep('child')}
              disabled={!parentName}
              className="w-full bg-[#C6B7E2] text-white p-6 rounded-[2rem] font-black text-2xl hover:scale-[1.02] transition-all shadow-xl shadow-[#C6B7E2]/20 disabled:opacity-50 font-display"
            >
              Get Started →
            </button>
          </div>
        ) : (
          <div className="space-y-12 animate-in fade-in duration-600">
            {children.length > 0 && (
              <div className="space-y-4 text-center">
                <p className="text-[10px] font-black text-[#C6B7E2] uppercase tracking-[0.4em]">Your Growing Bloom List</p>
                <div className="flex flex-wrap justify-center gap-3">
                  {children.map(c => (
                    <div key={c.id} className="bg-[#FFF6EB] text-[#5B5450] px-8 py-3 rounded-full text-sm font-black border-2 border-[#C6B7E2]/20 shadow-sm">
                      {c.name} ({c.age})
                    </div>
                  ))}
                </div>
              </div>
            )}

            <section className="space-y-10">
              <h3 className="text-4xl font-black text-[#5B5450] font-display text-center">
                {children.length === 0 ? "Tell us about your child" : "Add another child"}
              </h3>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-3">
                  <label className="text-xs font-black uppercase tracking-[0.3em] text-[#F4B6A6] px-4">Name</label>
                  <input
                    type="text"
                    placeholder="Child's Name"
                    className="w-full p-6 bg-[#FFF6EB]/40 border-2 border-[#C6B7E2]/10 rounded-[2rem] outline-none font-bold text-[#5B5450] focus:border-[#C6B7E2]"
                    value={tempChild.name}
                    onChange={(e) => setTempChild({...tempChild, name: e.target.value})}
                  />
                </div>
                <div className="space-y-3">
                  <label className="text-xs font-black uppercase tracking-[0.3em] text-[#F4B6A6] px-4">Age</label>
                  <input
                    type="number"
                    placeholder="Age"
                    className="w-full p-6 bg-[#FFF6EB]/40 border-2 border-[#C6B7E2]/10 rounded-[2rem] outline-none font-bold text-[#5B5450] focus:border-[#C6B7E2]"
                    value={tempChild.age === undefined ? '' : tempChild.age}
                    onChange={(e) => setTempChild({...tempChild, age: e.target.value === '' ? undefined : Number(e.target.value)})}
                  />
                </div>
              </div>

              {tempChild.name && tempChild.age !== undefined && (
                <div className="space-y-12 pt-6 animate-in fade-in duration-600">
                  <div className="space-y-6 text-center">
                    <p className="text-xs font-black text-[#F4B6A6] uppercase tracking-[0.4em]">What are you working on?</p>
                    <div className="flex flex-wrap justify-center gap-3">
                      {currentChallenges.map(c => (
                        <button
                          key={c}
                          onClick={() => toggleItem(c, 'challenges')}
                          className={`px-6 py-3 rounded-full text-xs font-black border-2 transition-all ${
                            tempChild.challenges?.includes(c) 
                            ? 'bg-[#F4B6A6] border-[#F4B6A6] text-white shadow-lg' 
                            : 'bg-white border-gray-100 text-gray-400 hover:border-[#F4B6A6]/30'
                          }`}
                        >
                          {c}
                        </button>
                      ))}

                      {isAddingCustom ? (
                        <div className="flex items-center gap-3 animate-in slide-in-from-left-4">
                          <input 
                            type="text"
                            value={customChallenge}
                            onChange={(e) => setCustomChallenge(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && handleAddCustomChallenge()}
                            placeholder="Challenge..."
                            className="px-6 py-2 border-2 border-[#F4B6A6] rounded-full text-xs outline-none font-black"
                            autoFocus
                          />
                          <button onClick={handleAddCustomChallenge} className="text-[#F4B6A6] font-black text-sm">Add</button>
                        </div>
                      ) : (
                        <button 
                          onClick={() => setIsAddingCustom(true)}
                          className="px-6 py-3 rounded-full text-xs font-black border-2 border-dashed border-[#F4B6A6]/30 text-[#F4B6A6]/60 hover:border-[#F4B6A6]/50"
                        >
                          + Add Custom
                        </button>
                      )}
                    </div>
                  </div>

                  <div className="space-y-6 text-center">
                    <p className="text-xs font-black text-[#C6B7E2] uppercase tracking-[0.4em]">Interests</p>
                    <div className="flex flex-wrap justify-center gap-3">
                      {currentInterests.map(i => (
                        <button
                          key={i}
                          onClick={() => toggleItem(i, 'interests')}
                          className={`px-6 py-3 rounded-full text-xs font-black border-2 transition-all ${
                            tempChild.interests?.includes(i) 
                            ? 'bg-[#C6B7E2] border-[#C6B7E2] text-white shadow-lg' 
                            : 'bg-white border-gray-100 text-gray-400 hover:border-[#C6B7E2]/30'
                          }`}
                        >
                          {i}
                        </button>
                      ))}
                    </div>
                  </div>
                </div>
              )}
            </section>

            <div className="flex flex-col sm:flex-row gap-6 pt-6">
              <button
                onClick={handleAddChild}
                disabled={!tempChild.name || tempChild.age === undefined}
                className="flex-1 bg-white text-[#C6B7E2] border-4 border-[#C6B7E2]/10 p-6 rounded-[2rem] font-black text-xl hover:bg-[#C6B7E2]/5 transition-all disabled:opacity-30 font-display"
              >
                + Add Another
              </button>
              <button
                onClick={handleFinish}
                disabled={children.length === 0 && (!tempChild.name || tempChild.age === undefined)}
                className="flex-1 bg-[#F4B6A6] text-white p-6 rounded-[2rem] font-black text-xl hover:opacity-90 transition-all shadow-xl shadow-[#F4B6A6]/20 disabled:opacity-50 font-display"
              >
                Let's Bloom
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Onboarding;

import React from 'react';
import { View, SyncStatus } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  currentView: View;
  setView: (view: View) => void;
  syncStatus?: SyncStatus;
}

const Layout: React.FC<LayoutProps> = ({ children, currentView, setView, syncStatus = 'synced' }) => {
  const navItems = [
    { id: View.DASHBOARD, label: 'Home', icon: '🏠' },
    { id: View.FAVORITES, label: 'Saved', icon: '⭐' },
