import React, { useState } from 'react';
import { UserProfile, Child, DailyTip, FavoriteItem } from '../types';
import { getChallengeAdvice } from '../services/gemini';
import Modal from './Modal';
import { trackEvent } from '../services/analytics';

interface Props {
  profile: UserProfile;
  onUpdateProfile: (profile: UserProfile) => void;
  onBack: () => void;
}

const AdviceActivities: React.FC<Props> = ({ profile, onUpdateProfile, onBack }) => {
  const [selectedChild, setSelectedChild] = useState<Child>(profile.children[0]);
  const [selectedChallenge, setSelectedChallenge] = useState<string>('');
  const [advice, setAdvice] = useState<DailyTip | null>(null);
  const [loading, setLoading] = useState(false);
  const [showMainModal, setShowMainModal] = useState(false);
  const [feedbackGiven, setFeedbackGiven] = useState<string | null>(null);
  const [savedItems, setSavedItems] = useState<Set<string>>(new Set());
  const [newChallengeInput, setNewChallengeInput] = useState('');
  const [isAddingChallenge, setIsAddingChallenge] = useState(false);
  const [activeDefinition, setActiveDefinition] = useState<{term: string, definition: string} | null>(null);

  const handleChallengeClick = async (challenge: string) => {
    setSelectedChallenge(challenge);
    setLoading(true);
    setFeedbackGiven(null);
    setSavedItems(new Set());
    setActiveDefinition(null);
    trackEvent('advice_request', { challenge, childAge: selectedChild.age });
    try {
      const res = await getChallengeAdvice(profile.name, selectedChild, challenge);
      setAdvice(res);
      setShowMainModal(true);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleAddCustomChallenge = () => {
    if (!newChallengeInput.trim()) {
      setIsAddingChallenge(false);
      return;
    }

    const trimmedChallenge = newChallengeInput.trim();
    if (selectedChild.challenges.includes(trimmedChallenge)) {
      setNewChallengeInput('');
      setIsAddingChallenge(false);
      return;
    }

    const updatedChildren = profile.children.map(c => {
      if (c.id === selectedChild.id) {
        return { ...c, challenges: [...c.challenges, trimmedChallenge] };
      }
      return c;
    });

    const updatedChild = updatedChildren.find(c => c.id === selectedChild.id)!;
    onUpdateProfile({ ...profile, children: updatedChildren });
    setSelectedChild(updatedChild);
    setNewChallengeInput('');
    setIsAddingChallenge(false);
  };

  const saveToFavorites = (type: 'advice' | 'script' | 'activity', content: string) => {
    const key = `${type}-${content.substring(0, 10)}`;
    if (savedItems.has(key)) return;

    const newItem: FavoriteItem = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      title: `${selectedChallenge} (${type})`,
      content,
      childContext: `${selectedChild.name} (Age ${selectedChild.age})`,
      dateSaved: new Date().toISOString()
    };

    onUpdateProfile({ ...profile, favorites: [...profile.favorites, newItem] });
    setSavedItems(prev => new Set(prev).add(key));
  };

  const isSaved = (type: string, content: string) => {
    const key = `${type}-${content.substring(0, 10)}`;
    return savedItems.has(key);
  };

  const renderContentWithGlossary = (text?: string) => {
    if (!text) return null;

    const lines = text.split('\n');

    return lines.map((line, idx) => {
      const isBullet = line.trim().startsWith('-') || line.trim().startsWith('*');
      const cleanLine = isBullet ? line.trim().substring(1).trim() : line;

      let parts: React.ReactNode[] = [cleanLine];
      if (advice?.glossary) {
        advice.glossary.forEach(item => {
          const newParts: React.ReactNode[] = [];
          parts.forEach(part => {
            if (typeof part !== 'string') {
              newParts.push(part);
              return;
            }
            const regex = new RegExp(`(${item.term})`, 'gi');
            const split = part.split(regex);
            split.forEach(s => {
              if (s.toLowerCase() === item.term.toLowerCase()) {
                newParts.push(
                  <span 
                    key={`${item.term}-${Math.random()}`}
                    onClick={() => setActiveDefinition(item)}
                    className="cursor-help border-b-2 border-dashed border-[#4E8B83] text-[#4E8B83] font-bold hover:bg-[#EEF5F4] transition-colors px-0.5 rounded"
                  >
                    {s}
                  </span>
                );
              } else if (s) {
                newParts.push(s);
              }
            });
          });
          parts = newParts;
        });
      }

      if (isBullet) {
        return (
          <div key={idx} className="flex gap-4 mb-3 items-start">
            <div className="w-1.5 h-1.5 rounded-full bg-[#4E8B83] mt-2.5 flex-shrink-0"></div>
            <p className={displayFontClass}>{parts}</p>
          </div>
        );
      }

      return <p key={idx} className={`${displayFontClass} mb-4`}>{parts}</p>;
    });
  };

  const displayFontClass = "font-display font-medium text-lg md:text-xl leading-relaxed text-[#3B3B3B]";

  return (
    <div className="space-y-8 max-w-5xl mx-auto py-4">
      <div className="px-4">
        <button onClick={onBack} className="text-[#4E8B83] font-bold flex items-center gap-3 hover:translate-x-[-4px] transition-transform font-display text-lg uppercase tracking-wider">
          <span className="text-2xl">←</span> Back
        </button>
      </div>

      <div className="bg-white p-8 md:p-12 rounded-[3.5rem] card-shadow border border-[#EEF5F4] min-h-[60vh] flex flex-col items-center justify-start space-y-12 animate-in fade-in duration-500">

        <div className="w-full flex flex-col items-center gap-8">
           <div className="flex flex-col items-center gap-4 w-full">
             <div className="h-1.5 w-24 bg-[#4E8B83] rounded-full opacity-20"></div>
             <span className="text-xs font-black text-[#4E8B83] uppercase tracking-[0.4em]">Who are we blooming with?</span>
             <div className="flex flex-wrap justify-center bg-[#FAF9F6] p-4 rounded-[3rem] border-2 border-[#EEF5F4] gap-3 max-w-2xl">
                {profile.children.map(c => (
                  <button
                    key={c.id}
                    onClick={() => setSelectedChild(c)}
                    className={`px-12 py-5 rounded-[1.5rem] text-sm font-black transition-all transform hover:scale-[1.02] active:scale-95 shadow-sm ${
                      selectedChild.id === c.id 
                      ? 'bg-[#4E8B83] text-white shadow-xl shadow-[#4E8B83]/30 scale-110' 
                      : 'bg-white text-[#3B3B3B]/30 hover:text-[#4E8B83] border border-[#EEF5F4]'
                    }`}
                  >
                    {c.name}
                  </button>
                ))}
             </div>
           </div>

          <header className="text-center space-y-4 pt-4 w-full">
            <h2 className="text-4xl md:text-6xl font-bold text-[#2E2E2E] font-display">Pick a Challenge</h2>
            <p className="text-[#3B3B3B]/50 font-medium text-lg md:text-xl leading-relaxed whitespace-nowrap">Choose an area where {selectedChild.name} could use some gentle support.</p>
          </header>
        </div>

        <div className="w-full max-w-4xl grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-4">
          {selectedChild.challenges.map(c => (
            <button
              key={c}
              disabled={loading}
              onClick={() => handleChallengeClick(c)}
              className="px-4 py-8 rounded-[2rem] text-sm font-bold bg-[#FAF9F6] border border-[#EEF5F4] text-[#3B3B3B] hover:bg-[#4E8B83] hover:text-white transition-all transform hover:-translate-y-1 shadow-sm flex items-center justify-center text-center leading-snug"
            >
              {c}
            </button>
          ))}

          {isAddingChallenge ? (
            <div className="col-span-2 flex items-center gap-2 animate-in slide-in-from-right-2 duration-300">
              <input
                autoFocus
                type="text"
                value={newChallengeInput}
                onChange={(e) => setNewChallengeInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleAddCustomChallenge()}
                placeholder="What's the challenge?"
                className="flex-1 px-6 py-5 rounded-[2rem] text-sm font-bold border-2 border-[#4E8B83] outline-none text-[#3B3B3B] shadow-inner bg-white"
              />
              <button 
                onClick={handleAddCustomChallenge}
                className="w-14 h-14 bg-[#4E8B83] text-white rounded-2xl flex items-center justify-center font-bold text-xl shadow-lg"
              >✓</button>
            </div>
          ) : (
            <button
              onClick={() => setIsAddingChallenge(true)}
              className="px-4 py-8 rounded-[2rem] text-sm font-bold border-2 border-dashed border-[#4E8B83]/40 text-[#4E8B83] hover:bg-[#EEF5F4] transition-all flex items-center justify-center text-center"
            >+ Add Custom</button>
          )}
        </div>

        {loading && (
          <div className="py-8 flex flex-col items-center gap-4">
            <div className="w-12 h-12 border-4 border-[#EEF5F4] border-t-[#4E8B83] rounded-full animate-spin"></div>
            <p className="text-[#4E8B83] font-bold text-xs tracking-widest uppercase animate-pulse">Consulting Specialist AI...</p>
          </div>
        )}
      </div>

      <Modal isOpen={showMainModal} onClose={() => setShowMainModal(false)} title={selectedChallenge}>
        <div className="space-y-8 relative">

          <div className="text-center -mt-4 mb-2">
            <span className="bg-[#FAF9F6] text-[#4E8B83] px-5 py-2 rounded-full text-[11px] font-black uppercase tracking-[0.15em] border border-[#EEF5F4] shadow-sm">
              Developmentally appropriate for age {selectedChild.age}
            </span>
          </div>

          {activeDefinition && (
            <div className="absolute top-0 left-0 w-full z-50 animate-in slide-in-from-top-4">
              <div className="bg-[#2E2E2E] text-white p-6 rounded-[2rem] shadow-2xl relative border-2 border-[#4E8B83]/30">
                <button onClick={() => setActiveDefinition(null)} className="absolute top-4 right-4 text-white/50 hover:text-white">✕</button>
                <h5 className="font-display font-bold text-[#4E8B83] uppercase text-xs tracking-widest mb-1">{activeDefinition.term}</h5>
                <p className="text-sm font-medium leading-relaxed">{activeDefinition.definition}</p>
              </div>
            </div>
          )}

          <div className="flex flex-col gap-2 p-5 bg-[#FAF9F6] rounded-[2rem] border border-[#EEF5F4] text-[11px] font-bold text-[#3B3B3B]/70 uppercase tracking-widest">
            <div className="flex items-center gap-2">
              <span className="text-[#4E8B83]">💡</span> <span className="text-[10px]">Tap highlighted words for easy definitions</span>
            </div>
          </div>

          <div className="space-y-4">
            <div className="flex justify-between items-center bg-[#EEF5F4] p-6 rounded-t-[2.5rem] border-x border-t border-[#EEF5F4]">
              <h4 className="font-black text-[#4E8B83] uppercase text-2xl md:text-3xl tracking-tight flex items-center gap-3 font-display">
                <span className="text-3xl">💡</span> Gentle Strategy
              </h4>
              <button 
                onClick={() => saveToFavorites('advice', advice?.content || '')}
                className={`text-[9px] font-bold border-2 px-3 py-1.5 rounded-full transition-all uppercase tracking-wider ${
                  isSaved('advice', advice?.content || '') 
                  ? 'bg-[#4E8B83] text-white border-[#4E8B83]' 
                  : 'text-[#4E8B83] border-[#4E8B83]/20 hover:bg-white'
                }`}
              >
                {isSaved('advice', advice?.content || '') ? 'Saved ⭐' : 'Save'}
              </button>
            </div>
            <div className="p-8 bg-white border-x border-b border-[#EEF5F4] rounded-b-[2.5rem] shadow-sm">
              {renderContentWithGlossary(advice?.content)}
            </div>
          </div>

          <div className="space-y-4">
            <div className="flex justify-between items-center bg-[#F1F1F1] p-6 rounded-t-[2.5rem] border-x border-t border-[#F1F1F1]">
              <h5 className="font-black text-[#2E2E2E] text-2xl md:text-3xl uppercase tracking-tight flex items-center gap-3 font-display">
                <span className="text-3xl">💬</span> The Script
              </h5>
              <button 
                onClick={() => saveToFavorites('script', advice?.script || '')}
                className={`text-[9px] font-bold border-2 px-3 py-1.5 rounded-full transition-all uppercase tracking-wider ${
                  isSaved('script', advice?.script || '') 
                  ? 'bg-[#2E2E2E] text-white border-[#2E2E2E]' 
                  : 'text-[#2E2E2E] border-[#2E2E2E]/20 hover:bg-white'
                }`}
              >
                {isSaved('script', advice?.script || '') ? 'Saved ⭐' : 'Save'}
              </button>
            </div>
            <div className="p-8 bg-white border-x border-b border-[#F1F1F1] rounded-b-[2.5rem] shadow-sm italic">
              {renderContentWithGlossary(advice?.script ? `"${advice.script}"` : undefined)}
            </div>
          </div>

          <div className="space-y-4">
            <div className="flex justify-between items-center bg-[#FAF9F6] p-6 rounded-t-[2.5rem] border-x border-t border-gray-100">
              <h5 className="font-black text-[#3B3B3B]/60 text-2xl md:text-3xl uppercase tracking-tight flex items-center gap-3 font-display">
                <span className="text-3xl">🎨</span> Bloom Activity
              </h5>
              <button 
                onClick={() => saveToFavorites('activity', `${advice?.activity}\n\n${advice?.details}`)}
                className={`text-[9px] font-bold border-2 px-3 py-1.5 rounded-full transition-all uppercase tracking-wider ${
                  isSaved('activity', `${advice?.activity}\n\n${advice?.details}`) 
                  ? 'bg-[#4E8B83] text-white border-[#4E8B83]' 
                  : 'text-[#4E8B83] border-[#4E8B83]/20 hover:bg-white'
                }`}
              >
                {isSaved('activity', `${advice?.activity}\n\n${advice?.details}`) ? 'Saved ⭐' : 'Save'}
              </button>
            </div>
            <div className="p-8 bg-white border-x border-b border-gray-100 rounded-b-[2.5rem] shadow-sm space-y-4">
              <h6 className="text-[#4E8B83] font-black uppercase text-xs tracking-widest">{advice?.activity}</h6>
              <div className="whitespace-pre-wrap">
                {renderContentWithGlossary(advice?.details || advice?.activity)}
              </div>
            </div>
          </div>

          <div className="pt-8 border-t border-gray-100 text-center space-y-6">
            <div className="bg-[#FAF9F6] p-8 rounded-[2.5rem] border border-[#EEF5F4]">
              <p className="text-[#4E8B83] font-bold font-display text-xl leading-relaxed">If things feel urgent in the moment, try What should I do right now?”</p>
            </div>
            <button onClick={() => setShowMainModal(false)} className="w-full bg-[#4E8B83] text-white py-6 rounded-[2.5rem] font-bold font-display text-xl shadow-xl shadow-[#4E8B83]/20 hover:scale-[1.02] transition-transform">I'm Ready</button>
          </div>
        </div>
      </Modal>
    </div>
  );
};

export default AdviceActivities;

import React, { useState, useMemo } from 'react';
import { UserProfile, Child } from '../types';
import { trackEvent } from '../services/analytics';

interface OnboardingProps {
  onComplete: (profile: UserProfile) => void;
}

const GrowingPlant = ({ className = "" }: { className?: string }) => (
  <svg width="40" height="40" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" className={`${className} animate-pulse`}>
    <path d="M12 22V10" stroke="#4E8B83" strokeWidth="2" strokeLinecap="round"/>
    <path d="M12 18C12 18 6 18 6 13C6 10 12 10 12 18Z" fill="#4E8B83" fillOpacity="0.4" stroke="#4E8B83" strokeWidth="1.5"/>
    <path d="M12 14C12 14 18 14 18 9C18 6 12 6 12 14Z" fill="#4E8B83" fillOpacity="0.2" stroke="#4E8B83" strokeWidth="1.5"/>
  </svg>
);

const CHALLENGE_MAP = {
  '0-5': ['Big Emotions', 'Tantrums', 'Separation Anxiety', 'Listening Skills', 'Sleep Routines', 'Activity Transitions', 'Picky Eating', 'Turn Taking', 'Screen Limits', 'Independence Struggles'],
  '6-10': ['Emotional Regulation', 'Friendship Issues', 'Self Confidence', 'Homework Resistance', 'Respectful Listening', 'Disappointment Tolerance', 'Screen Balance', 'Honesty', 'Sibling Conflict', 'Teacher Expectations'],
  '11-15': ['Mood Swings', 'Peer Pressure', 'Communication Breakdown', 'Boundary Testing', 'Self Esteem', 'Motivation Struggles', 'Screen Time', 'Friend Drama', 'Authority Resistance', 'Stress Management'],
  '16-18': ['Independence Tension', 'Trust Building', 'Accountability', 'Emotional Control', 'Decision Making', 'Social Comparison', 'Time Management', 'Conflict Resolution', 'Life Readiness', 'Relationship Shifts']
};

const INTERESTS_MAP = {
  '0-5': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Dolls/Cars', 'Building', 'Outdoor Play', 'Dance/Music', 'Pretend Play', 'Puzzles'],
  '6-10': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Building', 'Games', 'Technology', 'Sports', 'Outdoor Play', 'Puzzles'],
  '11-15': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Technology', 'Coding', 'Gaming', 'Debate', 'Social Media', 'Drama'],
  '16-18': ['Reading', 'Science', 'Friends', 'Creative Arts', 'Technology', 'Coding', 'Gaming', 'Travel', 'Career', 'Fitness']
};

const Onboarding: React.FC<OnboardingProps> = ({ onComplete }) => {
  const [parentName, setParentName] = useState('');
  const [children, setChildren] = useState<Child[]>([]);
  const [step, setStep] = useState<'parent' | 'child'>('parent');
  const [tempChild, setTempChild] = useState<Partial<Child>>({ 
    name: '', 
    age: undefined, 
    challenges: [], 
    interests: [] 
  });
  const [customChallenge, setCustomChallenge] = useState('');
  const [isAddingCustom, setIsAddingCustom] = useState(false);

  const [customInterest, setCustomInterest] = useState('');
  const [isAddingCustomInterest, setIsAddingCustomInterest] = useState(false);

  const currentChallenges = useMemo(() => {
    const age = Number(tempChild.age) || 0;
    let base = [];
    if (age <= 5) base = [...CHALLENGE_MAP['0-5']];
    else if (age <= 10) base = [...CHALLENGE_MAP['6-10']];
    else if (age <= 15) base = [...CHALLENGE_MAP['11-15']];
    else base = [...CHALLENGE_MAP['16-18']];

    const customOnes = (tempChild.challenges || []).filter(c => !base.includes(c));
    return [...base, ...customOnes];
  }, [tempChild.age, tempChild.challenges]);

  const currentInterests = useMemo(() => {
    const age = Number(tempChild.age) || 0;
    let base = [];
    if (age <= 5) base = [...INTERESTS_MAP['0-5']];
    else if (age <= 10) base = [...INTERESTS_MAP['6-10']];
    else if (age <= 15) base = [...INTERESTS_MAP['11-15']];
    else base = [...INTERESTS_MAP['16-18']];

    const customOnes = (tempChild.interests || []).filter(i => !base.includes(i));
    return [...base, ...customOnes];
  }, [tempChild.age, tempChild.interests]);

  const toggleItem = (item: string, key: 'challenges' | 'interests') => {
    const current = (tempChild[key] as string[]) || [];
    setTempChild({
      ...tempChild, 
      [key]: current.includes(item) ? current.filter(i => i !== item) : [...current, item]
    });
  };

  const handleAddCustomChallenge = () => {
    if (!customChallenge.trim()) {
      setIsAddingCustom(false);
      return;
    }
    const current = (tempChild.challenges as string[]) || [];
    if (!current.includes(customChallenge.trim())) {
      setTempChild({
        ...tempChild,
        challenges: [...current, customChallenge.trim()]
      });
    }
    setCustomChallenge('');
    setIsAddingCustom(false);
  };

  const handleAddCustomInterest = () => {
    if (!customInterest.trim()) {
      setIsAddingCustomInterest(false);
      return;
    }
    const current = (tempChild.interests as string[]) || [];
    if (!current.includes(customInterest.trim())) {
      setTempChild({
        ...tempChild,
        interests: [...current, customInterest.trim()]
      });
    }
    setCustomInterest('');
    setIsAddingCustomInterest(false);
  };

  const handleAddChild = () => {
    if (!tempChild.name || tempChild.age === undefined) return;
    const newChild: Child = {
      id: Math.random().toString(36).substr(2, 9),
      name: tempChild.name,
      age: Number(tempChild.age),
      challenges: tempChild.challenges || [],
      interests: tempChild.interests || []
    };
    setChildren([...children, newChild]);
    setTempChild({ name: '', age: undefined, challenges: [], interests: [] });
    setIsAddingCustom(false);
    setIsAddingCustomInterest(false);
    trackEvent('child_added', { age: newChild.age });
  };

  const handleFinish = () => {
    let finalChildren = [...children];
    if (tempChild.name && tempChild.age !== undefined && !children.some(c => c.name === tempChild.name)) {
      finalChildren.push({
        id: Math.random().toString(36).substr(2, 9),
        name: tempChild.name,
        age: Number(tempChild.age),
        challenges: tempChild.challenges || [],
        interests: tempChild.interests || []
      });
    }

    onComplete({ 
      name: parentName, 
      children: finalChildren, 
      onboarded: true,
      favorites: [],
      chatHistory: [],
      logs: []
    });
  };

  return (
    <div className="min-h-screen bg-[#FAF9F6] flex items-center justify-center p-6 py-12">
      <div className="max-w-4xl w-full bg-white rounded-[4rem] shadow-3xl shadow-[#2E2E2E]/5 p-10 md:p-16 space-y-12 border border-[#EEF5F4] relative overflow-hidden">
        <div className="absolute -top-12 -right-12 text-6xl opacity-10 animate-spin-slow text-[#4E8B83]">🌸</div>

        <div className="text-center space-y-6">
          <div className="flex items-center justify-center gap-8">
            <GrowingPlant />
            <h2 className="text-5xl md:text-6xl font-black text-[#2E2E2E] font-display tracking-tight leading-tight">Mind<span className="text-[#4E8B83]">Bloom</span></h2>
            <GrowingPlant className="-scale-x-100" />
          </div>
          <div className="space-y-1">
            <p className="text-[#2E2E2E] text-2xl font-bold font-display leading-tight whitespace-nowrap overflow-hidden text-ellipsis">
              Personalized, practical support for hard parenting moments
            </p>
            <p className="text-[#3B3B3B]/60 text-sm font-medium">For everyday, non-medical emotional and behavioral challenges</p>
          </div>
        </div>

        {step === 'parent' ? (
          <div className="space-y-12 animate-in fade-in zoom-in duration-600 max-w-xl mx-auto">
            <div className="space-y-10 text-center">
              <p className="text-[#4E8B83] text-xl md:text-2xl font-black font-display uppercase tracking-widest leading-tight">
                Get personalized guidance in seconds
              </p>

              <section className="space-y-6">
                <label className="text-xs font-black uppercase tracking-[0.5em] text-[#4E8B83]">What's your name?</label>
                <input
                  type="text"
                  value={parentName}
                  onChange={(e) => setParentName(e.target.value)}
                  className="w-full p-6 bg-[#FAF9F6] border-2 border-[#EEF5F4] rounded-[2rem] focus:ring-8 focus:ring-[#EEF5F4]/5 outline-none text-3xl text-center font-display font-black text-[#2E2E2E] transition-all"
                  placeholder="Name"
                />
              </section>
            </div>

            <button
              onClick={() => setStep('child')}
              disabled={!parentName}
              className="w-full bg-[#4E8B83] text-white p-6 rounded-[2rem] font-black text-2xl hover:scale-[1.02] transition-all shadow-xl shadow-[#4E8B83]/20 disabled:opacity-50 font-display"
            >
              Get Started →
            </button>
          </div>
        ) : (
          <div className="space-y-12 animate-in fade-in duration-600">
            {children.length > 0 && (
              <div className="space-y-4 text-center">
                <p className="text-[10px] font-black text-[#4E8B83] uppercase tracking-[0.4em]">Your Growing Bloom List</p>
                <div className="flex flex-wrap justify-center gap-3">
                  {children.map(c => (
                    <div key={c.id} className="bg-[#FAF9F6] text-[#3B3B3B] px-8 py-3 rounded-full text-sm font-black border-2 border-[#EEF5F4] shadow-sm">
                      {c.name} ({c.age})
                    </div>
                  ))}
                </div>
              </div>
            )}

            <section className="space-y-10">
              <h3 className="text-4xl font-black text-[#2E2E2E] font-display text-center">
                {children.length === 0 ? "Tell us about your child" : "Add another child"}
              </h3>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-3">
                  <label className="text-xs font-black uppercase tracking-[0.3em] text-[#4E8B83] px-4">Name</label>
                  <input
                    type="text"
                    placeholder="Child's Name"
                    className="w-full p-6 bg-[#FAF9F6] border-2 border-[#EEF5F4] rounded-[2rem] outline-none font-bold text-[#2E2E2E] focus:border-[#4E8B83]"
                    value={tempChild.name}
                    onChange={(e) => setTempChild({...tempChild, name: e.target.value})}
                  />
                </div>
                <div className="space-y-3">
                  <label className="text-xs font-black uppercase tracking-[0.3em] text-[#4E8B83] px-4">Age</label>
                  <input
                    type="number"
                    placeholder="Age"
                    className="w-full p-6 bg-[#FAF9F6] border-2 border-[#EEF5F4] rounded-[2rem] outline-none font-bold text-[#2E2E2E] focus:border-[#4E8B83]"
                    value={tempChild.age === undefined ? '' : tempChild.age}
                    onChange={(e) => setTempChild({...tempChild, age: e.target.value === '' ? undefined : Number(e.target.value)})}
                  />
                </div>
              </div>

              {tempChild.name && tempChild.age !== undefined && (
                <div className="space-y-12 pt-6 animate-in fade-in duration-600">
                  <div className="space-y-6 text-center">
                    <p className="text-xs font-black text-[#4E8B83] uppercase tracking-[0.4em]">What are you working on?</p>
                    <div className="flex flex-wrap justify-center gap-3">
                      {currentChallenges.map(c => (
                        <button
                          key={c}
                          onClick={() => toggleItem(c, 'challenges')}
                          className={`px-6 py-3 rounded-full text-xs font-black border-2 transition-all ${
                            tempChild.challenges?.includes(c) 
                            ? 'bg-[#4E8B83] border-[#4E8B83] text-white shadow-lg' 
                            : 'bg-white border-[#EEF5F4] text-[#3B3B3B]/40 hover:border-[#4E8B83]'
                          }`}
                        >
                          {c}
                        </button>
                      ))}

                      {isAddingCustom ? (
                        <div className="flex items-center gap-3 animate-in slide-in-from-left-4">
                          <input 
                            type="text"
                            value={customChallenge}
                            onChange={(e) => setCustomChallenge(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && handleAddCustomChallenge()}
                            placeholder="Challenge..."
                            className="px-6 py-2 border-2 border-[#4E8B83] rounded-full text-xs outline-none font-black"
                            autoFocus
                          />
                          <button onClick={handleAddCustomChallenge} className="text-[#4E8B83] font-black text-sm">Add</button>
                        </div>
                      ) : (
                        <button 
                          onClick={() => setIsAddingCustom(true)}
                          className="px-6 py-3 rounded-full text-xs font-black border-2 border-dashed border-[#4E8B83]/30 text-[#4E8B83]/60 hover:border-[#4E8B83]/50"
                        >
                          + Add Custom
                        </button>
                      )}
                    </div>
                  </div>

                  <div className="space-y-6 text-center">
                    <p className="text-xs font-black text-[#3B3B3B]/40 uppercase tracking-[0.4em]">Interests</p>
                    <div className="flex flex-wrap justify-center gap-3">
                      {currentInterests.map(i => (
                        <button
                          key={i}
                          onClick={() => toggleItem(i, 'interests')}
                          className={`px-6 py-3 rounded-full text-xs font-black border-2 transition-all ${
                            tempChild.interests?.includes(i) 
                            ? 'bg-[#2E2E2E] border-[#2E2E2E] text-white shadow-lg' 
                            : 'bg-white border-[#EEF5F4] text-[#3B3B3B]/40 hover:border-[#2E2E2E]'
                          }`}
                        >
                          {i}
                        </button>
                      ))}

                      {isAddingCustomInterest ? (
                        <div className="flex items-center gap-3 animate-in slide-in-from-left-4">
                          <input 
                            type="text"
                            value={customInterest}
                            onChange={(e) => setCustomInterest(e.target.value)}
                            onKeyDown={(e) => e.key === 'Enter' && handleAddCustomInterest()}
                            placeholder="Interest..."
                            className="px-6 py-2 border-2 border-[#4E8B83] rounded-full text-xs outline-none font-black"
                            autoFocus
                          />
                          <button onClick={handleAddCustomInterest} className="text-[#4E8B83] font-black text-sm">Add</button>
                        </div>
                      ) : (
                        <button 
                          onClick={() => setIsAddingCustomInterest(true)}
                          className="px-6 py-3 rounded-full text-xs font-black border-2 border-dashed border-[#4E8B83]/30 text-[#4E8B83]/60 hover:border-[#4E8B83]/50"
                        >
                          + Add Custom
                        </button>
                      )}
                    </div>
                  </div>
                </div>
              )}
            </section>

            <div className="flex flex-col sm:flex-row gap-6 pt-6">
              <button
                onClick={handleAddChild}
                disabled={!tempChild.name || tempChild.age === undefined}
                className="flex-1 bg-white text-[#4E8B83] border-4 border-[#EEF5F4] p-6 rounded-[2rem] font-black text-xl hover:bg-[#EEF5F4] transition-all disabled:opacity-30 font-display"
              >
                + Add Another
              </button>
              <button
                onClick={handleFinish}
                disabled={children.length === 0 && (!tempChild.name || tempChild.age === undefined)}
                className="flex-1 bg-[#4E8B83] text-white p-6 rounded-[2rem] font-black text-xl hover:opacity-90 transition-all shadow-xl shadow-[#4E8B83]/20 disabled:opacity-50 font-display"
              >
                Let's Bloom
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Onboarding;

import React, { useState } from 'react';
import { UserProfile, Child, DailyTip, FavoriteItem } from '../types';
import { getChallengeAdvice } from '../services/gemini';
import Modal from './Modal';
import { trackEvent } from '../services/analytics';

interface Props {
  profile: UserProfile;
  onUpdateProfile: (profile: UserProfile) => void;
  onBack: () => void;
}

const AdviceActivities: React.FC<Props> = ({ profile, onUpdateProfile, onBack }) => {
  const [selectedChild, setSelectedChild] = useState<Child>(profile.children[0]);
  const [selectedChallenge, setSelectedChallenge] = useState<string>('');
  const [advice, setAdvice] = useState<DailyTip | null>(null);
  const [loading, setLoading] = useState(false);
  const [showMainModal, setShowMainModal] = useState(false);
  const [feedbackGiven, setFeedbackGiven] = useState<string | null>(null);
  const [savedItems, setSavedItems] = useState<Set<string>>(new Set());
  const [newChallengeInput, setNewChallengeInput] = useState('');
  const [isAddingChallenge, setIsAddingChallenge] = useState(false);
  const [activeDefinition, setActiveDefinition] = useState<{term: string, definition: string} | null>(null);

  const handleChallengeClick = async (challenge: string) => {
    setSelectedChallenge(challenge);
    setLoading(true);
    setFeedbackGiven(null);
    setSavedItems(new Set());
    setActiveDefinition(null);
    trackEvent('advice_request', { challenge, childAge: selectedChild.age });
    try {
      const res = await getChallengeAdvice(profile.name, selectedChild, challenge);
      setAdvice(res);
      setShowMainModal(true);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleFeedback = (val: string) => {
    setFeedbackGiven(val);
    trackEvent('advice_feedback', { challenge: selectedChallenge, rating: val });
  };

  const handleAddCustomChallenge = () => {
    if (!newChallengeInput.trim()) {
      setIsAddingChallenge(false);
      return;
    }

    const trimmedChallenge = newChallengeInput.trim();
    if (selectedChild.challenges.includes(trimmedChallenge)) {
      setNewChallengeInput('');
      setIsAddingChallenge(false);
      return;
    }

    const updatedChildren = profile.children.map(c => {
      if (c.id === selectedChild.id) {
        return { ...c, challenges: [...c.challenges, trimmedChallenge] };
      }
      return c;
    });

    const updatedChild = updatedChildren.find(c => c.id === selectedChild.id)!;
    onUpdateProfile({ ...profile, children: updatedChildren });
    setSelectedChild(updatedChild);
    setNewChallengeInput('');
    setIsAddingChallenge(false);
  };

  const saveToFavorites = (type: 'advice' | 'script' | 'activity', content: string) => {
    const key = `${type}-${content.substring(0, 10)}`;
    if (savedItems.has(key)) return;

    const newItem: FavoriteItem = {
      id: Math.random().toString(36).substr(2, 9),
      type,
      title: `${selectedChallenge} (${type})`,
      content,
      childContext: `${selectedChild.name} (Age ${selectedChild.age})`,
      dateSaved: new Date().toISOString()
    };

    onUpdateProfile({ ...profile, favorites: [...profile.favorites, newItem] });
    setSavedItems(prev => new Set(prev).add(key));
  };

  const isSaved = (type: string, content: string) => {
    const key = `${type}-${content.substring(0, 10)}`;
    return savedItems.has(key);
  };

  const renderContentWithGlossary = (text?: string) => {
    if (!text) return null;

    const lines = text.split('\n');

    return lines.map((line, idx) => {
      const isBullet = line.trim().startsWith('-') || line.trim().startsWith('*');
      const cleanLine = isBullet ? line.trim().substring(1).trim() : line;

      let parts: React.ReactNode[] = [cleanLine];
      if (advice?.glossary) {
        advice.glossary.forEach(item => {
          const newParts: React.ReactNode[] = [];
          parts.forEach(part => {
            if (typeof part !== 'string') {
              newParts.push(part);
              return;
            }
            const regex = new RegExp(`(${item.term})`, 'gi');
            const split = part.split(regex);
            split.forEach(s => {
              if (s.toLowerCase() === item.term.toLowerCase()) {
                newParts.push(
                  <span 
                    key={`${item.term}-${Math.random()}`}
                    onClick={() => setActiveDefinition(item)}
                    className="cursor-help border-b-2 border-dashed border-[#4E8B83] text-[#4E8B83] font-bold hover:bg-[#EEF5F4] transition-colors px-0.5 rounded"
                  >
                    {s}
                  </span>
                );
              } else if (s) {
                newParts.push(s);
              }
            });
          });
          parts = newParts;
        });
      }

      if (isBullet) {
        return (
          <div key={idx} className="flex gap-4 mb-3 items-start">
            <div className="w-1.5 h-1.5 rounded-full bg-[#4E8B83] mt-2.5 flex-shrink-0"></div>
            <p className={displayFontClass}>{parts}</p>
          </div>
        );
      }

      return <p key={idx} className={`${displayFontClass} mb-4`}>{parts}</p>;
    });
  };

  const displayFontClass = "font-display font-medium text-lg md:text-xl leading-relaxed text-[#3B3B3B]";

  return (
    <div className="space-y-8 max-w-5xl mx-auto py-4">
      <div className="px-4">
        <button onClick={onBack} className="text-[#4E8B83] font-bold flex items-center gap-3 hover:translate-x-[-4px] transition-transform font-display text-lg uppercase tracking-wider">
          <span className="text-2xl">←</span> Back
        </button>
      </div>

      <div className="bg-white p-8 md:p-12 rounded-[3.5rem] card-shadow border border-[#EEF5F4] min-h-[60vh] flex flex-col items-center justify-start space-y-12 animate-in fade-in duration-500">

        <div className="w-full flex flex-col items-center gap-8">
           <div className="flex flex-col items-center gap-4 w-full">
             <div className="h-1.5 w-24 bg-[#4E8B83] rounded-full opacity-20"></div>
             <span className="text-xs font-black text-[#4E8B83] uppercase tracking-[0.4em]">Who are we blooming with?</span>
             <div className="flex flex-wrap justify-center bg-[#FAF9F6] p-4 rounded-[3rem] border-2 border-[#EEF5F4] gap-3 max-w-2xl">
                {profile.children.map(c => (
                  <button
                    key={c.id}
                    onClick={() => setSelectedChild(c)}
                    className={`px-12 py-5 rounded-[1.5rem] text-sm font-black transition-all transform hover:scale-[1.02] active:scale-95 shadow-sm ${
                      selectedChild.id === c.id 
                      ? 'bg-[#4E8B83] text-white shadow-xl shadow-[#4E8B83]/30 scale-110' 
                      : 'bg-white text-[#3B3B3B]/30 hover:text-[#4E8B83] border border-[#EEF5F4]'
                    }`}
                  >
                    {c.name}
                  </button>
                ))}
             </div>
           </div>

          <header className="text-center space-y-4 pt-4 w-full">
            <h2 className="text-4xl md:text-6xl font-bold text-[#2E2E2E] font-display">Pick a Challenge</h2>
            <p className="text-[#3B3B3B]/50 font-medium text-lg md:text-xl leading-relaxed whitespace-nowrap">Choose an area where {selectedChild.name} could use some gentle support.</p>
          </header>
        </div>

        <div className="w-full max-w-4xl grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-4">
          {selectedChild.challenges.map(c => (
            <button
              key={c}
              disabled={loading}
              onClick={() => handleChallengeClick(c)}
              className="px-4 py-8 rounded-[2rem] text-sm font-bold bg-[#FAF9F6] border border-[#EEF5F4] text-[#3B3B3B] hover:bg-[#4E8B83] hover:text-white transition-all transform hover:-translate-y-1 shadow-sm flex items-center justify-center text-center leading-snug"
            >
              {c}
            </button>
          ))}

          {isAddingChallenge ? (
            <div className="col-span-2 flex items-center gap-2 animate-in slide-in-from-right-2 duration-300">
              <input
                autoFocus
                type="text"
                value={newChallengeInput}
                onChange={(e) => setNewChallengeInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleAddCustomChallenge()}
                placeholder="What's the challenge?"
                className="flex-1 px-6 py-5 rounded-[2rem] text-sm font-bold border-2 border-[#4E8B83] outline-none text-[#3B3B3B] shadow-inner bg-white"
              />
              <button 
                onClick={handleAddCustomChallenge}
                className="w-14 h-14 bg-[#4E8B83] text-white rounded-2xl flex items-center justify-center font-bold text-xl shadow-lg"
              >✓</button>
            </div>
          ) : (
            <button
              onClick={() => setIsAddingChallenge(true)}
              className="px-4 py-8 rounded-[2rem] text-sm font-bold border-2 border-dashed border-[#4E8B83]/40 text-[#4E8B83] hover:bg-[#EEF5F4] transition-all flex items-center justify-center text-center"
            >+ Add Custom</button>
          )}
        </div>

        {loading && (
          <div className="py-8 flex flex-col items-center gap-4">
            <div className="w-12 h-12 border-4 border-[#EEF5F4] border-t-[#4E8B83] rounded-full animate-spin"></div>
            <p className="text-[#4E8B83] font-bold text-xs tracking-widest uppercase animate-pulse">Consulting Specialist AI...</p>
          </div>
        )}
      </div>

      <Modal isOpen={showMainModal} onClose={() => setShowMainModal(false)} title={selectedChallenge}>
        <div className="space-y-8 relative">

          <div className="text-center -mt-4 mb-2">
            <span className="bg-[#FAF9F6] text-[#4E8B83] px-5 py-2 rounded-full text-[11px] font-black uppercase tracking-[0.15em] border border-[#EEF5F4] shadow-sm">
              Developmentally appropriate for age {selectedChild.age}
            </span>
          </div>

          {activeDefinition && (
            <div className="absolute top-0 left-0 w-full z-50 animate-in slide-in-from-top-4">
              <div className="bg-[#2E2E2E] text-white p-6 rounded-[2rem] shadow-2xl relative border-2 border-[#4E8B83]/30">
                <button onClick={() => setActiveDefinition(null)} className="absolute top-4 right-4 text-white/50 hover:text-white">✕</button>
                <h5 className="font-display font-bold text-[#4E8B83] uppercase text-xs tracking-widest mb-1">{activeDefinition.term}</h5>
                <p className="text-sm font-medium leading-relaxed">{activeDefinition.definition}</p>
              </div>
            </div>
          )}

          <div className="flex flex-col gap-2 p-5 bg-[#FAF9F6] rounded-[2rem] border border-[#EEF5F4] text-[11px] font-bold text-[#3B3B3B]/70 uppercase tracking-widest">
            <div className="flex items-center gap-2">
              <span className="text-[#4E8B83]">💡</span> <span className="text-[10px]">Tap highlighted words for easy definitions</span>
            </div>
          </div>

          <div className="space-y-4">
            <div className="flex justify-between items-center bg-[#EEF5F4] p-6 rounded-t-[2.5rem] border-x border-t border-[#EEF5F4]">
              <h4 className="font-black text-[#4E8B83] uppercase text-2xl md:text-3xl tracking-tight flex items-center gap-3 font-display">
                <span className="text-3xl">💡</span> Gentle Strategy
              </h4>
              <button 
                onClick={() => saveToFavorites('advice', advice?.content || '')}
                className={`text-[9px] font-bold border-2 px-3 py-1.5 rounded-full transition-all uppercase tracking-wider ${
                  isSaved('advice', advice?.content || '') 
                  ? 'bg-[#4E8B83] text-white border-[#4E8B83]' 
                  : 'text-[#4E8B83] border-[#4E8B83]/20 hover:bg-white'
                }`}
              >
                {isSaved('advice', advice?.content || '') ? 'Saved ⭐' : 'Save'}
              </button>
            </div>
            <div className="p-8 bg-white border-x border-b border-[#EEF5F4] rounded-b-[2.5rem] shadow-sm">
              {renderContentWithGlossary(advice?.content)}
            </div>
          </div>

          <div className="space-y-4">
            <div className="flex justify-between items-center bg-[#F1F1F1] p-6 rounded-t-[2.5rem] border-x border-t border-[#F1F1F1]">
              <h5 className="font-black text-[#2E2E2E] text-2xl md:text-3xl uppercase tracking-tight flex items-center gap-3 font-display">
                <span className="text-3xl">💬</span> The Script
              </h5>
              <button 
                onClick={() => saveToFavorites('script', advice?.script || '')}
                className={`text-[9px] font-bold border-2 px-3 py-1.5 rounded-full transition-all uppercase tracking-wider ${
                  isSaved('script', advice?.script || '') 
                  ? 'bg-[#2E2E2E] text-white border-[#2E2E2E]' 
                  : 'text-[#2E2E2E] border-[#2E2E2E]/20 hover:bg-white'
                }`}
              >
                {isSaved('script', advice?.script || '') ? 'Saved ⭐' : 'Save'}
              </button>
            </div>
            <div className="p-8 bg-white border-x border-b border-[#F1F1F1] rounded-b-[2.5rem] shadow-sm italic">
              {renderContentWithGlossary(advice?.script ? `"${advice.script}"` : undefined)}
            </div>
          </div>

          <div className="space-y-4">
            <div className="flex justify-between items-center bg-[#FAF9F6] p-6 rounded-t-[2.5rem] border-x border-t border-gray-100">
              <h5 className="font-black text-[#3B3B3B]/60 text-2xl md:text-3xl uppercase tracking-tight flex items-center gap-3 font-display">
                <span className="text-3xl">🎨</span> Bloom Activity
              </h5>
              <button 
                onClick={() => saveToFavorites('activity', `${advice?.activity}\n\n${advice?.details}`)}
                className={`text-[9px] font-bold border-2 px-3 py-1.5 rounded-full transition-all uppercase tracking-wider ${
                  isSaved('activity', `${advice?.activity}\n\n${advice?.details}`) 
                  ? 'bg-[#4E8B83] text-white border-[#4E8B83]' 
                  : 'text-[#4E8B83] border-[#4E8B83]/20 hover:bg-white'
                }`}
              >
                {isSaved('activity', `${advice?.activity}\n\n${advice?.details}`) ? 'Saved ⭐' : 'Save'}
              </button>
            </div>
            <div className="p-8 bg-white border-x border-b border-gray-100 rounded-b-[2.5rem] shadow-sm space-y-4">
              <h6 className="text-[#4E8B83] font-black uppercase text-xs tracking-widest">{advice?.activity}</h6>
              <div className="whitespace-pre-wrap">
                {renderContentWithGlossary(advice?.details || advice?.activity)}
              </div>
            </div>
          </div>

          <div className="pt-8 border-t border-gray-100 text-center space-y-8">
            <div className="space-y-4">
              <p className="text-[10px] font-black text-[#3B3B3B]/30 uppercase tracking-[0.4em]">Did this help?</p>
              {feedbackGiven ? (
                <p className="text-[#4E8B83] font-black text-xl animate-in zoom-in duration-300 uppercase tracking-widest">Thank you! 🌸</p>
              ) : (
                <div className="flex justify-center gap-3">
                  {['Yes', 'Kind of', 'No'].map(val => (
                    <button 
                      key={val} 
                      onClick={() => handleFeedback(val)} 
                      className="px-8 py-2.5 rounded-full bg-white border-2 border-[#EEF5F4] text-[11px] font-black text-[#3B3B3B]/60 hover:bg-[#FAF9F6] hover:border-[#4E8B83]/20 transition-all font-display"
                    >
                      {val}
                    </button>
                  ))}
                </div>
              )}
            </div>

            <div className="bg-[#FAF9F6] p-8 rounded-[2.5rem] border border-[#EEF5F4]">
              <p className="text-[#4E8B83] font-bold font-display text-xl leading-relaxed">If things feel urgent in the moment, try "What should I do right now?"</p>
            </div>
            <button onClick={() => setShowMainModal(false)} className="w-full bg-[#4E8B83] text-white py-6 rounded-[2.5rem] font-bold font-display text-xl shadow-xl shadow-[#4E8B83]/20 hover:scale-[1.02] transition-transform">I'm Ready</button>
          </div>
        </div>
      </Modal>
    </div>
  );
};

export default AdviceActivities;

import React, { useState } from 'react';
import { UserProfile, Child, RightNowAdvice, FavoriteItem } from '../types';
import { getRightNowAdvice } from '../services/gemini';
import { trackEvent } from '../services/analytics';

interface Props {
  profile: UserProfile;
  onUpdateProfile: (profile: UserProfile) => void;
  onBack: () => void;
}

const RightNowView: React.FC<Props> = ({ profile, onUpdateProfile, onBack }) => {
  const [selectedChild, setSelectedChild] = useState<Child>(profile.children[0]);
  const [selectedChallenge, setSelectedChallenge] = useState<string>('');
  const [advice, setAdvice] = useState<RightNowAdvice | null>(null);
  const [loading, setLoading] = useState(false);
  const [expandedStep, setExpandedStep] = useState<number | null>(null);
  const [activeDefinition, setActiveDefinition] = useState<{term: string, definition: string} | null>(null);
  const [feedbackGiven, setFeedbackGiven] = useState<string | null>(null);

  const handleActionRequest = async (challenge: string) => {
    setSelectedChallenge(challenge);
    setLoading(true);
    setAdvice(null);
    setExpandedStep(null);
    setActiveDefinition(null);
    setFeedbackGiven(null);
    trackEvent('right_now_request', { challenge, childAge: selectedChild.age });
    try {
      const res = await getRightNowAdvice(profile.name, selectedChild, challenge);
      setAdvice(res);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleFeedback = (val: string) => {
    setFeedbackGiven(val);
    trackEvent('right_now_feedback', { challenge: selectedChallenge, rating: val });
  };

  const saveToFavorites = () => {
    if (!advice) return;
    const content = `1. ${advice.step1}: ${advice.summary1}\n2. ${advice.step2}: ${advice.summary2}\n3. ${advice.step3}: ${advice.summary3}`;
    const newItem: FavoriteItem = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'right_now',
      title: `Action Plan: ${selectedChallenge}`,
      content,
      childContext: `${selectedChild.name} (Age ${selectedChild.age})`,
      dateSaved: new Date().toISOString()
    };
    onUpdateProfile({ ...profile, favorites: [...profile.favorites, newItem] });
    trackEvent('favorite_saved', { type: 'right_now' });
    alert("Saved to your Bloom List!");
  };

  const TextWithGlossary = ({ text, className }: { text?: string, className?: string }) => {
    if (!text || !advice?.glossary) return <p className={className}>{text}</p>;

    let parts: React.ReactNode[] = [text];
    advice.glossary.forEach(item => {
      const newParts: React.ReactNode[] = [];
      parts.forEach(part => {
        if (typeof part !== 'string') {
          newParts.push(part);
          return;
        }
        const regex = new RegExp(`(${item.term})`, 'gi');
        const split = part.split(regex);
        split.forEach(s => {
          if (s.toLowerCase() === item.term.toLowerCase()) {
            newParts.push(
              <span 
                key={`${item.term}-${Math.random()}`}
                onClick={(e) => { e.stopPropagation(); setActiveDefinition(item); }}
                className="cursor-help border-b-2 border-dashed border-[#4E8B83] text-[#4E8B83] font-bold hover:bg-[#EEF5F4] transition-colors px-0.5 rounded"
              >
                {s}
              </span>
            );
          } else if (s) {
            newParts.push(s);
          }
        });
      });
      parts = newParts;
    });

    return <p className={className}>{parts}</p>;
  };

  return (
    <div className="max-w-4xl mx-auto py-6 space-y-10 animate-in fade-in duration-500 relative">

      {/* GLOSSARY TOOLTIP */}
      {activeDefinition && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-6 bg-black/20 backdrop-blur-sm" onClick={() => setActiveDefinition(null)}>
          <div className="bg-[#2E2E2E] text-white p-8 rounded-[3rem] shadow-2xl relative border-2 border-[#4E8B83]/30 max-w-sm" onClick={e => e.stopPropagation()}>
            <button onClick={() => setActiveDefinition(null)} className="absolute top-4 right-4 text-white/50 hover:text-white">✕</button>
            <h5 className="font-display font-bold text-[#4E8B83] uppercase text-xs tracking-[0.3em] mb-2">{activeDefinition.term}</h5>
            <p className="text-base font-medium leading-relaxed">{activeDefinition.definition}</p>
          </div>
        </div>
      )}

      <div className="flex justify-between items-center px-4">
        <button onClick={onBack} className="text-[#4E8B83] font-bold flex items-center gap-3 hover:translate-x-[-4px] transition-transform font-display text-lg uppercase tracking-wider">
          <span className="text-2xl">←</span> Back
        </button>
      </div>

      <div className="flex flex-col items-center gap-8 bg-white p-10 rounded-[4rem] card-shadow border border-[#EEF5F4]">

        {/* PROMINENT CHILD SELECTION AT TOP */}
        <div className="flex flex-col items-center gap-4 w-full">
          <span className="text-xs font-black text-[#4E8B83] uppercase tracking-[0.4em]">Who needs an action plan?</span>
          <div className="flex flex-wrap justify-center bg-[#FAF9F6] p-4 rounded-[3rem] border-2 border-[#EEF5F4] gap-3 shadow-inner">
            {profile.children.map(c => (
              <button
                key={c.id}
                onClick={() => { setSelectedChild(c); setAdvice(null); }}
                className={`px-10 py-4 rounded-2xl text-sm font-black transition-all transform hover:scale-[1.02] active:scale-95 shadow-sm ${
                  selectedChild.id === c.id 
                  ? 'bg-[#4E8B83] text-white shadow-xl shadow-[#4E8B83]/30 scale-105' 
                  : 'bg-white text-[#3B3B3B]/30 hover:text-[#4E8B83] border border-[#EEF5F4]'
