import React, { useState, useEffect, useRef, useMemo } from 'react';
import { UserProfile, ChatMessage, FavoriteItem } from '../types';
import { getAiChatResponse } from '../services/gemini';
import { trackEvent } from '../services/analytics';

interface Props {
  profile: UserProfile;
  onUpdateProfile: (profile: UserProfile) => void;
  onBack: () => void;
}

const CoachAIView: React.FC<Props> = ({ profile, onUpdateProfile, onBack }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [feedbackState, setFeedbackState] = useState<Record<number, string>>({});
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [profile.chatHistory, loading]);

  const pastUserQuestions = useMemo(() => {
    return profile.chatHistory
      .filter(m => m.role === 'user')
      .slice(-6)
      .reverse();
  }, [profile.chatHistory]);

  const handleSend = async (customText?: string) => {
    const textToSend = customText || input;
    if (!textToSend.trim() || loading) return;

    setError(null);
    const userMsg: ChatMessage = { 
      role: 'user', 
      content: textToSend, 
      timestamp: new Date().toISOString() 
    };

    const updatedHistory = [...profile.chatHistory, userMsg];
    onUpdateProfile({ ...profile, chatHistory: updatedHistory });
    setInput('');
    setLoading(true);
    trackEvent('coach_query', { length: textToSend.length });

    try {
      const resText = await getAiChatResponse(updatedHistory.map(m => ({ role: m.role, content: m.content })), textToSend, profile.children);
      const aiMsg: ChatMessage = { 
        role: 'assistant', 
        content: resText, 
        timestamp: new Date().toISOString() 
      };
      onUpdateProfile({ ...profile, chatHistory: [...updatedHistory, aiMsg] });
    } catch (e: any) {
      console.error(e);
      const msg = e.message?.includes('429') ? "MindBloom is very busy right now. Please wait a moment and try again." : "Something went wrong. Please check your connection.";
      setError(msg);
    } finally {
      setLoading(false);
    }
  };

  const saveToFavorites = (content: string) => {
    const newItem: FavoriteItem = {
      id: Math.random().toString(36).substr(2, 9),
      type: 'advice',
      title: "Coach Insight",
      content,
      dateSaved: new Date().toISOString()
    };
    onUpdateProfile({ ...profile, favorites: [...profile.favorites, newItem] });
    trackEvent('favorite_saved', { type: 'coach_advice' });
  };

  const handleFeedback = (idx: number, val: string) => {
    setFeedbackState(prev => ({ ...prev, [idx]: val }));
    trackEvent('coach_feedback', { messageIndex: idx, rating: val });
  };

  const clearHistory = () => {
    if (confirm("Reset conversation history?")) {
      onUpdateProfile({ ...profile, chatHistory: [] });
      setFeedbackState({});
    }
  };

  return (
    <div className="max-w-4xl mx-auto py-2 flex flex-col h-[85vh]">
      <div className="flex justify-between items-center mb-6 px-6">
        <button onClick={onBack} className="text-[#4E8B83] font-bold flex items-center gap-2 font-display text-lg uppercase tracking-wider group">
          <span className="text-xl transition-transform group-hover:-translate-x-1">←</span> Home
        </button>
        <div className="flex items-center gap-6">
          {profile.chatHistory.length > 0 && (
            <button 
              onClick={clearHistory}
              className="text-[10px] font-bold text-[#3B3B3B]/30 hover:text-red-400 uppercase tracking-widest transition-colors"
            >
              Clear
            </button>
          )}
          <h2 className="text-3xl font-bold text-[#2E2E2E] font-display">Coach AI</h2>
        </div>
      </div>

      <div className="flex-1 bg-white rounded-[3rem] card-shadow border border-[#EEF5F4] overflow-hidden flex flex-col">
        {pastUserQuestions.length > 0 && (
          <div className="bg-[#FAF9F6] px-6 py-3 border-b border-[#EEF5F4] flex items-center gap-4 overflow-x-auto no-scrollbar">
            <span className="text-[8px] font-black text-[#3B3B3B]/30 uppercase tracking-[0.3em] whitespace-nowrap">Past Topics:</span>
            {pastUserQuestions.map((q, i) => (
              <button 
                key={i} 
                onClick={() => handleSend(q.content)}
                className="text-[10px] font-bold bg-white border border-[#EEF5F4] px-4 py-1.5 rounded-full text-[#4E8B83] hover:bg-[#4E8B83] hover:text-white transition-all whitespace-nowrap shadow-sm"
              >
                {q.content.length > 20 ? q.content.substring(0, 20) + '...' : q.content}
              </button>
            ))}
          </div>
        )}

        <div className="flex-1 overflow-y-auto p-8 space-y-6 scrollbar-hide">
          {profile.chatHistory.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-center p-10 space-y-8">
               <div className="w-24 h-24 bg-[#FAF9F6] border-2 border-[#EEF5F4] rounded-[2rem] flex items-center justify-center text-6xl animate-float shadow-xl shadow-[#4E8B83]/5">🤖</div>
               <div className="space-y-3">
                 <p className="font-display text-3xl text-[#2E2E2E] font-bold">"How can I help you bloom today?"</p>
                 <p className="text-[#3B3B3B]/40 font-bold uppercase tracking-[0.3em] text-[10px]">Ask about scripts, tantrums, or transitions.</p>
               </div>
            </div>
          ) : (
            profile.chatHistory.map((msg, i) => (
              <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 duration-300`}>
                <div className={`max-w-[90%] md:max-w-[80%] space-y-3`}>
                  <div className={`p-6 rounded-[2rem] shadow-sm font-medium leading-relaxed text-lg ${
                    msg.role === 'user' 
                    ? 'bg-[#4E8B83] text-white rounded-tr-none shadow-lg shadow-[#4E8B83]/20' 
                    : 'bg-[#FAF9F6] text-[#3B3B3B] rounded-tl-none border border-[#EEF5F4]'
                  }`}>
                    <p className="whitespace-pre-wrap">{msg.content}</p>
                  </div>
                  {msg.role === 'assistant' && (
                    <div className="flex items-center gap-6 ml-6">
                      <button 
                        onClick={() => saveToFavorites(msg.content)} 
                        className="text-[9px] font-bold text-[#4E8B83] uppercase tracking-widest hover:text-[#2E2E2E] transition-colors flex items-center gap-2"
                      >
                        <span>⭐</span> Save
                      </button>

                      {feedbackState[i] ? (
                        <span className="text-[9px] font-black text-[#4E8B83] uppercase tracking-widest">Helpful: {feedbackState[i]}</span>
                      ) : (
                        <div className="flex items-center gap-3">
                           <span className="text-[8px] font-black text-[#3B3B3B]/20 uppercase tracking-widest">Was this helpful?</span>
                           <div className="flex gap-1.5">
                             {['Yes', 'No'].map(v => (
                               <button 
                                 key={v}
                                 onClick={() => handleFeedback(i, v)}
                                 className="text-[9px] font-bold text-[#3B3B3B]/30 hover:text-[#4E8B83] transition-colors border-b border-transparent hover:border-[#4E8B83]/20"
                               >
                                 {v}
                               </button>
                             ))}
                           </div>
                        </div>
                      )}
                    </div>
                  )}
                </div>
              </div>
            ))
          )}
          {loading && (
            <div className="flex justify-start">
              <div className="bg-[#FAF9F6] px-8 py-4 rounded-full border border-[#EEF5F4] flex gap-2 items-center shadow-sm">
                <div className="w-1.5 h-1.5 bg-[#4E8B83] rounded-full animate-bounce"></div>
                <div className="w-1.5 h-1.5 bg-[#4E8B83] rounded-full animate-bounce [animation-delay:0.2s]"></div>
                <div className="w-1.5 h-1.5 bg-[#4E8B83] rounded-full animate-bounce [animation-delay:0.4s]"></div>
              </div>
            </div>
          )}
          <div ref={scrollRef} />
        </div>

        <div className="p-6 md:p-10 bg-[#FAF9F6] border-t border-[#EEF5F4]">
          <div className="flex gap-4 max-w-4xl mx-auto">
            <input
              type="text"
              className="flex-1 p-5 bg-white border border-[#EEF5F4] rounded-[2rem] outline-none focus:ring-4 focus:ring-[#4E8B83]/10 text-lg font-medium shadow-inner transition-all placeholder-[#3B3B3B]/30"
              placeholder="Ask me anything..."
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            />
            <button
              onClick={() => handleSend()}
              disabled={loading || !input.trim()}
              className="bg-[#4E8B83] text-white w-14 h-14 rounded-[1.5rem] flex items-center justify-center font-bold hover:scale-105 active:scale-95 disabled:opacity-50 transition-all shadow-xl shadow-[#4E8B83]/30"
            >
              <span className="text-3xl">→</span>
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CoachAIView;

import React, { useState } from 'react';
import { UserProfile, Child } from '../types';
import { getExpertResponse } from '../services/gemini';
import { trackEvent } from '../services/analytics';

interface ExpertSectionProps {
  profile: UserProfile;
}

const ExpertSection: React.FC<ExpertSectionProps> = ({ profile }) => {
  const [selectedChildId, setSelectedChildId] = useState(profile.children[0]?.id || '');
  const [question, setQuestion] = useState('');
  const [response, setResponse] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [submitted, setSubmitted] = useState(false);
  const [feedbackGiven, setFeedbackGiven] = useState<string | null>(null);

  const handleSubmit = async () => {
    if (!question || !selectedChildId) return;
    setLoading(true);
    setResponse(null);
    setSubmitted(false);
    setFeedbackGiven(null);

    const child = profile.children.find(c => c.id === selectedChildId);
    if (!child) return;

    try {
      const result = await getExpertResponse(question, child);
      setResponse(result);
      setSubmitted(true);
      trackEvent('expert_query', { childAge: child.age });
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const handleFeedback = (val: string) => {
    setFeedbackGiven(val);
    trackEvent('expert_feedback', { rating: val });
  };

  return (
    <div className="space-y-8">
      <div className="bg-white rounded-[3rem] shadow-xl border border-[#EEF5F4] p-8 md:p-12">
        <header className="mb-10 space-y-4">
          <div className="inline-block bg-[#EEF5F4] text-[#4E8B83] px-4 py-1 rounded-full text-xs font-bold uppercase tracking-widest">
            Clinical Insights
          </div>
          <h2 className="text-3xl md:text-4xl font-bold text-[#2E2E2E] font-display">Ask a MindBloom Specialist</h2>
          <p className="text-[#3B3B3B]/50 max-w-xl font-medium">Deep clinical context for your child's specific developmental milestones.</p>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
          <div className="space-y-6">
            <div className="space-y-3">
              <label className="text-xs font-bold uppercase tracking-widest text-[#3B3B3B]/30">Child context</label>
              <div className="flex flex-wrap gap-2">
                {profile.children.map(c => (
                  <button
                    key={c.id}
                    onClick={() => { setSelectedChildId(c.id); setSubmitted(false); }}
                    className={`px-6 py-2 rounded-full text-sm font-bold transition-all border ${
                      selectedChildId === c.id ? 'bg-[#4E8B83] text-white' : 'bg-white border-[#EEF5F4] text-[#3B3B3B]/40'
                    }`}
                  >
                    {c.name}
                  </button>
                ))}
              </div>
            </div>

            <div className="space-y-3">
              <label className="text-xs font-bold uppercase tracking-widest text-[#3B3B3B]/30">Your query</label>
              <textarea
                className="w-full h-48 p-6 bg-[#FAF9F6] border border-[#EEF5F4] rounded-[2rem] outline-none focus:ring-4 focus:ring-[#4E8B83]/10 transition-all font-medium"
                placeholder="Describe your concern in detail..."
                value={question}
                onChange={(e) => setQuestion(e.target.value)}
              />
            </div>

            <button
              onClick={handleSubmit}
              disabled={loading || !question}
              className="w-full py-5 bg-[#4E8B83] text-white rounded-[2rem] font-bold text-lg hover:bg-[#4E8B83]/90 transition-all disabled:opacity-50 shadow-lg shadow-[#4E8B83]/20"
            >
              {loading ? 'Reviewing Query...' : 'Submit to Specialist'}
            </button>
          </div>

          <div className="bg-[#FAF9F6] rounded-[2.5rem] p-10 flex flex-col items-center justify-center text-center space-y-6 min-h-[400px] border border-[#EEF5F4]">
            {!submitted && !loading ? (
              <>
                <div className="text-5xl animate-float">📄</div>
                <h4 className="text-xl font-bold text-[#2E2E2E] font-display">Your Report Awaits</h4>
                <p className="text-sm text-[#3B3B3B]/50 font-medium">The specialist will provide a research-backed breakdown of your situation.</p>
              </>
            ) : loading ? (
              <div className="animate-pulse space-y-6 w-full">
                <div className="h-4 bg-white/50 rounded w-3/4 mx-auto"></div>
                <div className="h-4 bg-white/50 rounded w-full"></div>
                <div className="h-4 bg-white/50 rounded w-5/6 mx-auto"></div>
              </div>
            ) : (
              <div className="text-left w-full space-y-8 animate-in fade-in duration-500 overflow-y-auto max-h-[400px] pr-2">
                <div className="flex justify-between items-center border-b border-[#EEF5F4] pb-4">
                  <h4 className="text-xl font-bold text-[#4E8B83] font-display">Specialist Analysis</h4>
                  <div className="bg-[#4E8B83] text-white text-[8px] font-black uppercase px-2 py-1 rounded">Confidential</div>
                </div>
                <div className="text-[#3B3B3B] leading-relaxed whitespace-pre-wrap text-base font-medium">
                  {response}
                </div>

                <div className="pt-8 border-t border-[#EEF5F4] space-y-4">
                  <p className="text-[10px] font-black text-[#3B3B3B]/30 uppercase tracking-[0.4em] text-center">Did this analysis help?</p>
                  {feedbackGiven ? (
                    <p className="text-[#4E8B83] font-black text-xl text-center animate-in zoom-in duration-300 uppercase tracking-widest">Thank you! 🌸</p>
                  ) : (
                    <div className="flex justify-center gap-3">
                      {['Yes', 'Kind of', 'No'].map(val => (
                        <button 
                          key={val} 
                          onClick={() => handleFeedback(val)} 
                          className="px-8 py-2 rounded-full bg-white border-2 border-[#EEF5F4] text-[10px] font-black text-[#3B3B3B]/60 hover:bg-[#EEF5F4] transition-all"
